 // ── Hybrid RLS Setup (Blueprint / Wizard / Manual) ──
 type BlueprintListItem = { slug: string; name: string; industry?: string; icon?: string; description?: string; claims_count?: number; policies_count?: number; required_tables?: string[]; popularity?: number; is_system?: boolean; created_by?: string };
 type BlueprintDetail = BlueprintListItem & { claims?: any[]; policies?: any[] };

