 let blueprintsLoading = $state(false);
 let blueprintsError = $state<string | null>(null);
 let blueprintSearch = $state('');
 let blueprintSort = $state<'popular'|'name'|'industry'>('popular');
 let blueprintDetail = $state<BlueprintDetail | null>(null);
 let blueprintDetailLoading = $state(false);
 let blueprintCompat = $state<{matched: string[]; missing: string[]} | null>(null);
 let blueprintApplyMode = $state<'replace'|'merge'>('merge');
 let blueprintApplying = $state(false);
 // Inline-edit state for preview modal — lets user tweak the blueprint's
 // claims/policies before APPLY without modifying the blueprint itself.
 let bpEditedClaims = $state<any[] | null>(null);
 let bpEditedPolicies = $state<any[] | null>(null);
 let bpPolicyIncluded = $state<Record<number, boolean>>({});
 let bpClaimPopover = $state<number | null>(null);
 let bpPolicyEditing = $state<Record<number, boolean>>({});
 const bpEdited = $derived.by(() => {
 if (!blueprintDetail) return false;
 if (bpEditedClaims !== null || bpEditedPolicies !== null) return true;
 // Any policy un-included counts as edit
 const total = (blueprintDetail.policies || []).length;
 for (let i = 0; i < total; i++) {
 if (bpPolicyIncluded[i] === false) return true;
 }
 return false;
 });
 function bpResetEdits() {
 bpEditedClaims = null;
 bpEditedPolicies = null;
 bpPolicyIncluded = {};
 bpClaimPopover = null;
 bpPolicyEditing = {};
 }
 function bpClaimsForApply(): any[] {
 return bpEditedClaims !== null
 ? bpEditedClaims
 : ((blueprintDetail?.claims as any[]) || []);
 }
 function bpPoliciesForApply(): any[] {
 const base = bpEditedPolicies !== null
 ? bpEditedPolicies
 : ((blueprintDetail?.policies as any[]) || []);
 return base.filter((_p, i) => bpPolicyIncluded[i] !== false);
 }
 function bpEditClaim(i: number, patch: any) {
 const base = (bpEditedClaims !== null ? bpEditedClaims : ((blueprintDetail?.claims as any[]) || [])).map(x => ({ ...x }));
 base[i] = { ...base[i], ...patch };
 bpEditedClaims = base;
 }
 function bpEditPolicy(i: number, patch: any) {
 const base = (bpEditedPolicies !== null ? bpEditedPolicies : ((blueprintDetail?.policies as any[]) || [])).map(x => ({ ...x }));
 base[i] = { ...base[i], ...patch };
 bpEditedPolicies = base;
 }
