 // ── Blueprints helpers ──
 async function openBlueprintModal() {
 blueprintModalOpen = true;
 blueprintDetail = null;
 blueprintCompat = null;
 if (blueprintsList.length === 0) await loadBlueprints();
 }
 async function loadBlueprints() {
 blueprintsLoading = true;
 blueprintsError = null;
 try {
 const r = await fetch(`/api/embed-rls-blueprints`, { headers: _h() });
 if (r.ok) {
 const d = await r.json();
 blueprintsList = Array.isArray(d) ? d : (Array.isArray(d.blueprints) ? d.blueprints : []);
 } else {
 blueprintsError = `http_${r.status}`;
 }
 } catch (e) {
 console.error('loadBlueprints', e);
 blueprintsError = 'fetch_failed';
 } finally {
 blueprintsLoading = false;
 }
 }
 const filteredBlueprints = $derived.by(() => {
 const q = blueprintSearch.trim().toLowerCase();
 let list = blueprintsList.filter(b => !q || (b.name?.toLowerCase().includes(q) || b.slug?.toLowerCase().includes(q) || b.industry?.toLowerCase().includes(q) || b.description?.toLowerCase().includes(q)));
 if (blueprintSort === 'name') list = [...list].sort((a, b) => (a.name || '').localeCompare(b.name || ''));
 else if (blueprintSort === 'industry') list = [...list].sort((a, b) => (a.industry || '').localeCompare(b.industry || ''));
 else list = [...list].sort((a, b) => (b.popularity || 0) - (a.popularity || 0));
 return list;
 });
 async function previewBlueprint(embedId: string, bp: BlueprintListItem) {
 blueprintDetailLoading = true;
 blueprintDetail = null;
 blueprintCompat = null;
 blueprintCompatDisplay = null;
 bpExpandedPolicy = {};
 bpResetEdits();
 try {
 const r = await fetch(`/api/embed-rls-blueprints/${encodeURIComponent(bp.slug)}`, { headers: _h() });
 if (r.ok) {
 const j = await r.json();
 blueprintDetail = (j && j.blueprint) ? j.blueprint : j;
 }
 const cr = await fetch(`/api/projects/${slug}/embeds/${embedId}/blueprint-compatibility?slug=${encodeURIComponent(bp.slug)}`, { headers: _h() });
 if (cr.ok) {
 const cj = await cr.json();
 const matched = Array.isArray(cj.matched) ? cj.matched : (Array.isArray(cj.present) ? cj.present : []);
 blueprintCompat = { matched, missing: Array.isArray(cj.missing) ? cj.missing : [] };
