 function _policyKey(table: string, column: string) { return `${table}::${column || '*'}`; }

 function applyImportedClaims(embedId: string) {
 if (!embedSchemaCatalog) return;
 const existingKeys = new Set(embedRlsClaims.map(c => c.key.trim()).filter(Boolean));
 const toAdd = embedSchemaCatalog.suggested_claims.filter(s => claimsImportSelected[s.key] && !existingKeys.has(s.key));
 if (toAdd.length === 0) { claimsImportOpen = false; return; }
 embedRlsClaims = [
 ...embedRlsClaims,
 ...toAdd.map(s => ({
 key: s.key,
 label: s.label || s.key,
 type: (s.type === 'number' || s.type === 'enum' ? s.type : 'string') as 'string'|'number'|'enum',
 required: false,
 values: '',
 })),
 ];
 claimsImportSelected = {};
 claimsImportOpen = false;
 saveEmbedRls(embedId, { rls_claims: true });
 }

 function applyImportedPolicies(embedId: string) {
 if (!embedSchemaCatalog) return;
 const existing = new Set(embedRlsPolicies.map(p => _policyKey(p.table, p.column)));
 const toAdd = embedSchemaCatalog.suggested_policies.filter(s => {
 const k = _policyKey(s.table, s.column || '*');
 return policiesImportSelected[k] && !existing.has(k);
 });
 if (toAdd.length === 0) { policiesImportOpen = false; return; }
 embedRlsPolicies = [
 ...embedRlsPolicies,
 ...toAdd.map(s => ({
 table: s.table,
 column: s.column || '*',
 mode: ((['private','own_value','shared','redacted','hidden'].includes(s.mode) ? s.mode : 'private')) as 'private'|'own_value'|'shared'|'redacted'|'hidden',
 filter: s.filter || '',
 bypass_roles: '',
 })),
 ];
 policiesImportSelected = {};
 policiesImportOpen = false;
 saveEmbedRls(embedId, { rls_policies: true });
 }

 function selectAllPolicies(mode?: string) {
 if (!embedSchemaCatalog) return;
 const sel: Record<string, boolean> = {};
 for (const s of embedSchemaCatalog.suggested_policies) {
 if (!mode || s.mode === mode) sel[_policyKey(s.table, s.column || '*')] = true;
 }
 policiesImportSelected = sel;
 }
 function selectNonePolicies() { policiesImportSelected = {}; }

 async function loadEmbedRls(embedId: string) {
 if (embedRlsLoaded === embedId) return;
 try {
 const r = await fetch(`/api/projects/${slug}/embeds/${embedId}/rls`, { headers: _h() });
 if (r.ok) {
 const raw = await r.json();
 // Backend wraps as {status, rls: ...}. rls may be (a) object {rls_enabled,...} or (b) tuple [enabled,claims,policies,source].
 const rls = raw?.rls ?? raw;
 let enabled: any, claims: any[] = [], policies: any[] = [], src: string = 'token';
 if (Array.isArray(rls)) {
   enabled = rls[0]; claims = rls[1] || []; policies = rls[2] || []; src = rls[3] || 'token';
 } else if (rls && typeof rls === 'object') {
   enabled = rls.rls_enabled; claims = rls.rls_claims || []; policies = rls.rls_policies || []; src = rls.rls_claim_source || 'token';
 } else {
   // legacy flat shape fallback
   enabled = raw.rls_enabled; claims = raw.rls_claims || []; policies = raw.rls_policies || []; src = raw.rls_claim_source || 'token';
 }
 embedRlsEnabled = !!enabled;
 embedRlsClaimSource = src as any;
 embedRlsClaims = Array.isArray(claims) ? claims.map((c: any) => ({
 key: c.key || '', label: c.label || '', type: c.type || 'string',
 required: !!c.required,
 values: Array.isArray(c.values) ? c.values.join(',') : (c.values || ''),
 })) : [];
 embedRlsPolicies = Array.isArray(policies) ? policies.map((p: any) => ({
 table: p.table || '', column: p.column || '*',
 mode: p.mode || 'private', filter: p.filter || '',
 bypass_roles: Array.isArray(p.bypass_roles) ? p.bypass_roles.join(',') : (p.bypass_roles || ''),
 })) : [];
 embedRlsLoaded = embedId;
 }
 } catch (e) { console.error('loadEmbedRls', e); }
 // audit fetch (guarded)
 try {
 embedRlsAuditError = null;
 const ar = await fetch(`/api/projects/${slug}/embeds/${embedId}/audit?days=7`, { headers: _h() });
 if (ar.ok) {
 const aj = await ar.json();
 embedRlsAudit = Array.isArray(aj.top_denials) ? aj.top_denials : (Array.isArray(aj) ? aj : []);
 } else {
 embedRlsAudit = null;
 embedRlsAuditError = ar.status === 404 ? 'no_endpoint' : `http_${ar.status}`;
 }
 } catch { embedRlsAudit = null; embedRlsAuditError = 'fetch_failed'; }
 }

 function _serializeRlsClaims() {
 return embedRlsClaims
 .filter(c => c.key.trim())
 .map(c => ({
 key: c.key.trim(),
 label: c.label.trim() || c.key.trim(),
 type: c.type,
 required: !!c.required,
 values: c.type === 'enum'
 ? c.values.split(',').map(s => s.trim()).filter(Boolean)
 : [],
 }));
 }
 function _serializeRlsPolicies() {
 return embedRlsPolicies
 .filter(p => p.table.trim())
 .map(p => ({
 table: p.table.trim(),
 column: (p.column || '*').trim() || '*',
 mode: p.mode,
 filter: p.mode === 'private' ? p.filter.trim() : '',
 bypass_roles: p.bypass_roles.split(',').map(s => s.trim()).filter(Boolean),
 }));
 }
 function saveEmbedRls(embedId: string, patch: Record<string, any>) {
 clearTimeout(_embedRlsTimers[embedId]);
 _embedRlsTimers[embedId] = setTimeout(async () => {
 try {
 const body: Record<string, any> = {};
 if ('rls_enabled' in patch) body.rls_enabled = patch.rls_enabled;
 if ('rls_claim_source' in patch) body.rls_claim_source = patch.rls_claim_source;
 if ('rls_claims' in patch) body.rls_claims = _serializeRlsClaims();
 if ('rls_policies' in patch) body.rls_policies = _serializeRlsPolicies();
 const r = await fetch(`/api/projects/${slug}/embeds/${embedId}`, {
 method: 'PATCH', headers: { ..._h(), 'Content-Type': 'application/json' },
 body: JSON.stringify(body),
 });
 if (r.ok) {
 embedRlsSavedFlash = true;
 setTimeout(() => { embedRlsSavedFlash = false; }, 1500);
 }
 } catch (e) { console.error('saveEmbedRls', e); }
 }, 600);
 }
 function addRlsClaim() {
