 function launchRlsTestChat(embedId: string) {
 const params = new URLSearchParams();
 for (const c of _serializeRlsClaims()) {
 const v = embedRlsSandboxValues[c.key];
 if (v !== undefined && v !== '') params.set(`claim_${c.key}`, v);
 }
 const url = `/api/embed/try/${embedId}${params.toString() ? '?' + params.toString() : ''}`;
 window.open(url, '_blank');
