 async function copyRlsSignedUrl(embedId: string) {
 try {
 const claims: Record<string, any> = {};
 for (const c of _serializeRlsClaims()) {
 const v = embedRlsSandboxValues[c.key];
 if (v !== undefined && v !== '') claims[c.key] = v;
 }
 const r = await fetch(`/api/projects/${slug}/embeds/${embedId}/test-token`, {
