 }

 // Bump preview key (debounced) — call after any field change
 function bumpPreview() {
 clearTimeout(_previewBumpTimer);
 _previewBumpTimer = setTimeout(() => { previewKey++; }, 800);
 }
 function _fmtCountdown(ms: number): string {
 if (ms <= 0) return 'expired';
 const totalSec = Math.floor(ms / 1000);
 const m = Math.floor(totalSec / 60);
 const s = totalSec % 60;
 return `${m}:${s.toString().padStart(2, '0')}`;
 }
 function _startCountdown() {
 clearInterval(_tokenCountdownTimer);
 if (!testToken) { tokenCountdown = ''; return; }
 const tick = () => {
 if (!testToken) { tokenCountdown = ''; clearInterval(_tokenCountdownTimer); return; }
 const expMs = new Date(testToken.expires_at).getTime() - Date.now();
 tokenCountdown = _fmtCountdown(expMs);
 if (expMs <= 0) { testToken = null; clearInterval(_tokenCountdownTimer); }
 };
 tick();
 _tokenCountdownTimer = setInterval(tick, 1000);
 }
 async function regenTestToken(embedId: string) {
 try {
 const r = await fetch(`/api/projects/${slug}/embeds/${embedId}/test-token`, {
