 });
 if (!r.ok) { alert('Failed to mint test token'); return; }
 const d = await r.json();
 testToken = { token: d.token, expires_at: d.expires_at, url: d.url };
 _startCountdown();
 } catch (e) { console.error('regenTestToken', e); }
 }
