 async function rlsQuickAdd() {
 if (!rlsQuickAddAttrKey || !rlsQuickAddColumn) return;
 rlsQuickAddBusy = true;
 rlsQuickAddResult = null;
 try {
 const r = await fetch(`/api/projects/${slug}/rls-config/quick-add`, {
 method: 'POST',
 headers: { ..._h(), 'Content-Type': 'application/json' },
 body: JSON.stringify({
 attr_key: rlsQuickAddAttrKey,
 column: rlsQuickAddColumn,
 mode: rlsConfig?.mode || 'rewrite',
 }),
 });
 const j = await r.json();
 if (j.status === 'ok') {
 rlsConfig = j.config;
 rlsQuickAddResult = { ok: true, matched: j.matched_tables };
 setTimeout(() => { rlsQuickAddOpen = false; rlsQuickAddResult = null; rlsQuickAddAttrKey = ''; rlsQuickAddColumn = ''; }, 2000);
 } else {
 rlsQuickAddResult = { ok: false, error: j.detail };
 }
 } catch (e: any) {
 rlsQuickAddResult = { ok: false, error: e.message };
 } finally {
 rlsQuickAddBusy = false;
 }
 }

 function parseExprColumn(expr: string): string {
 const m = (expr || '').match(/^\s*([a-zA-Z_][a-zA-Z0-9_]*)\s*[=]/);
 if (m) return m[1];
 const m2 = (expr || '').match(/^\s*([a-zA-Z_][a-zA-Z0-9_]*)\s+IN\s*\(/i);
 return m2 ? m2[1] : '';
 }
 function parseExprOp(expr: string): string {
 if (!expr) return '=';
 if (/=\s*ANY\s*\(/i.test(expr)) return 'ANY';
 if (/\sIN\s*\(/i.test(expr)) return 'IN';
 return '=';
 }
 function parseExprAttr(expr: string): string {
 const m = (expr || '').match(/:([a-zA-Z_][a-zA-Z0-9_]*)/);
 return m ? m[1] : '';
 }
 function updateExprPicker(tname: string, field: 'col'|'op'|'attr', val: string) {
 const cur = (rlsConfig?.table_filters || {})[tname] || '';
 let col = parseExprColumn(cur);
 let op = parseExprOp(cur);
 let attr = parseExprAttr(cur);
 if (field === 'col') col = val;
 if (field === 'op') op = val;
 if (field === 'attr') attr = val;
 let expr = '';
 if (col && attr) {
 if (op === '=') expr = `${col} = :${attr}`;
 else if (op === 'IN') expr = `${col} IN (:${attr})`;
 else if (op === 'ANY') expr = `${col} = ANY(:${attr})`;
 }
 const f = { ...(rlsConfig?.table_filters || {}) }; f[tname] = expr;
 rlsConfig = { ...rlsConfig, table_filters: f };
 }

