 // -------------------- Data Quality --------------------
 type DqIssue = {
 type: string; severity: 'high'|'medium'|'low'|'info';
 table: string; column?: string|null;
 message: string; suggestion: string; count?: number;
 };
 type DqPayload = {
 issues: DqIssue[];
 by_severity: { high: number; medium: number; low: number; info: number };
 by_table: Record<string, number>;
 by_type?: Record<string, number>;
 score: number;
 table_count?: number;
 issue_count?: number;
 last_scanned?: string|null;
 error?: string;
 };
 let dqData = $state<DqPayload | null>(null);
 let dqLoading = $state(false);
 let dqRescanning = $state(false);
 let dqLoaded = $state(false);
 let dqSeverityFilter = $state<'all'|'high'|'medium'|'low'|'info'>('all');
 let dqTableFilter = $state<string>('');
 let dqExpanded = $state<Record<number, boolean>>({});
 // Toggle for showing tables ending in _casted (default hidden)
 let showCastedTables = $state(false);

 function _isCasted(name: string): boolean {
 return typeof name === 'string' && name.endsWith('_casted');
 }
 function _agentsListFiltered() {
 if (!agentsData?.agents) return [];
 return agentsData.agents;
 }

 async function loadDataQuality(force: boolean = false) {
 if (dqLoading) return;
 dqLoading = true;
 try {
 const url = `/api/projects/${slug}/data-quality`;
 const r = await fetch(url, { headers: _h() });
 if (r.ok) dqData = await r.json();
 } catch {}
 dqLoading = false;
 dqLoaded = true;
 }

 async function rescanDataQuality() {
 if (dqRescanning) return;
 dqRescanning = true;
 try {
 const r = await fetch(`/api/projects/${slug}/data-quality/rescan`, {
 method: 'POST', headers: _h(),
 });
 if (r.ok) dqData = await r.json();
 } catch {}
 dqRescanning = false;
 dqLoaded = true;
 }

 function dqFilteredIssues(): DqIssue[] {
 if (!dqData?.issues) return [];
 return dqData.issues.filter(it => {
 if (dqSeverityFilter !== 'all' && it.severity !== dqSeverityFilter) return false;
 if (dqTableFilter && it.table !== dqTableFilter) return false;
 return true;
 });
 }

 function dqScoreColor(score: number): string {
 if (score >= 80) return 'var(--pw-success, #2d8a4a)';
 if (score >= 50) return '#cc7a00';
 return 'var(--pw-error, #c14a3a)';
 }

 function dqSeverityColor(sev: string): string {
 if (sev === 'high') return 'var(--pw-error, #c14a3a)';
 if (sev === 'medium') return '#cc7a00';
 if (sev === 'low') return '#888';
 return 'var(--pw-muted, #999)';
 }

 function dqSeverityIcon(sev: string): string {
 if (sev === 'high') return '●';
 if (sev === 'medium') return '◐';
 if (sev === 'low') return '○';
 return 'ⓘ';
 }

 function dqTypeLabel(t: string): string {
 const map: Record<string, string> = {
 text_dates: 'TEXT DATES',
 opaque_columns: 'OPAQUE COL',
 high_null_pct: 'HIGH NULL%',
 duplicate_tables: 'DUPLICATE',
 missing_fk: 'MISSING FK',
 unicode_non_latin: 'UNICODE',
 tiny_table: 'TINY TABLE',
 cast_artifact: 'CAST ARTIFACT',
 enum_no_value_map: 'NO ENUM MAP',
 low_codex_confidence: 'LOW METADATA',
 };
 return map[t] || t.toUpperCase();
 }

