 function draftStatusColor(s: string): { bg: string; fg: string } {
 if (s === 'pending') return { bg: '#fff4d4', fg: '#cc7a00' };
 if (s === 'approved') return { bg: 'var(--pw-success-soft)', fg: 'var(--pw-success)' };
 if (s === 'rejected') return { bg: 'var(--pw-error-soft)', fg: 'var(--pw-error)' };
 if (s === 'published') return { bg: '#e3f2fd', fg: '#1565c0' };
 return { bg: 'var(--pw-border-soft)', fg: 'var(--pw-muted)' };
 }

