 }

 async function loadVisPolicy() {
 visLoading = true; visError = '';
 try {
 const r = await fetch(`/api/projects/${slug}/visibility-policy`, { headers: _h() });
 if (r.status === 404) {
 visPolicy = { version: 1, private: { fields: {} }, network: { fields: {} }, public: { fields: {} } };
 visVersion = 0;
 } else if (r.ok) {
 const d = await r.json();
 visPolicy = d.policy || { version: 1, private: { fields: {} }, network: { fields: {} }, public: { fields: {} } };
 if (!visPolicy.private) visPolicy.private = { fields: {} };
 if (!visPolicy.network) visPolicy.network = { fields: {} };
 if (!visPolicy.public) visPolicy.public = { fields: {} };
 visVersion = d.version || 0;
 } else { visError = `load failed: ${r.status}`; }
 visLoadedSnapshot = JSON.stringify(visPolicy);
 } catch (e: any) { visError = String(e); }
 finally { visLoading = false; }
 }
 async function saveVisPolicy() {
 if (!visPolicy) return;
 visSaving = true; visError = '';
 try {
 const r = await fetch(`/api/projects/${slug}/visibility-policy`, {
 method: 'PUT', headers: { ..._h(), 'content-type': 'application/json' },
 body: JSON.stringify({ policy: visPolicy, force: visForceSave })
 });
 if (r.status === 422) {
 try { visSaveValidation = await r.json(); } catch { visSaveValidation = { failures: [], warnings: [] }; }
 visShowSaveModal = true;
 } else if (r.ok) {
 const d = await r.json();
 visVersion = d.version;
 visLoadedSnapshot = JSON.stringify(visPolicy);
 visForceSave = false;
 visShowSaveModal = false;
 visSaveValidation = null;
 } else { visError = `save failed: ${r.status} ${await r.text()}`; }
 } catch (e: any) { visError = String(e); }
 finally { visSaving = false; }
 }
