 function highlightRewrittenSql(sql: string): string {
 if (!sql) return '';
 const esc = sql.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
 return esc.replace(/\b(CASE|WHEN|THEN|ELSE|END|AS)\b/g, '<span style="color:var(--pw-success); font-weight:700;">$1</span>');
 }
 function onPreviewKeydown(e: KeyboardEvent) {
