 else if (template === 'manager') visRoles.push({ role_name: 'manager', allowed_intents: ['private', 'network'], description: 'Manager — private + network partners' });
 else if (template === 'admin') visRoles.push({ role_name: 'admin', allowed_intents: ['private', 'network', 'public'], description: 'Admin — full access' });
 else visRoles.push({ role_name: '', allowed_intents: ['private'], description: '' });
 visRoles = visRoles;
 }
