 // colored gradient bar by band index (low=green → high=red)
 function bandBarColor(idx: number, total: number): string {
 if (total <= 1) return 'var(--pw-success)';
 const t = idx / (total - 1);
 if (t < 0.5) return `rgb(${Math.round(102 + t * 2 * (255 - 102))}, ${Math.round(187 - t * 2 * 20)}, 80)`;
 const tt = (t - 0.5) * 2;
 return `rgb(255, ${Math.round(167 - tt * 100)}, ${Math.round(80 - tt * 30)})`;
 }
 function bandSliderMax(bands: any[]): number {
 let m = 0;
 for (const b of (bands || [])) m = Math.max(m, Number(b?.max) || 0);
 return Math.max(100, m * 2);
 }

 // diff renderer for history rows — shape: {added:{aud:[col]}, removed:{aud:[col]}, modified:{aud:[col]}}
 function renderDiffParts(cf: any): { sign: string; color: string; label: string }[] {
 const out: any[] = [];
 if (!cf || typeof cf !== 'object') return out;
 for (const aud of Object.keys(cf.added || {})) for (const c of (cf.added[aud] || [])) out.push({ sign: '+', color: 'var(--pw-success)', label: `${aud}.${c}` });
 for (const aud of Object.keys(cf.removed || {})) for (const c of (cf.removed[aud] || [])) out.push({ sign: '−', color: 'var(--pw-error)', label: `${aud}.${c}` });
 for (const aud of Object.keys(cf.modified || {})) for (const c of (cf.modified[aud] || [])) out.push({ sign: '~', color: '#cc7a00', label: `${aud}.${c}` });
 return out;
 }
