 const k = rlsNewAttrKey.trim();
 const keys = [...(rlsConfig.user_attr_keys || [])];
 if (!keys.includes(k)) keys.push(k);
 rlsConfig = { ...rlsConfig, user_attr_keys: keys };
 rlsNewAttrKey = '';
