 const keys = (rlsConfig.user_attr_keys || []).filter((_: any, idx: number) => idx !== i);
 rlsConfig = { ...rlsConfig, user_attr_keys: keys };
 }
 function rlsAddFilter() {
 if (!rlsConfig) return;
 const tf = { ...(rlsConfig.table_filters || {}) };
 // Generate a placeholder key
 let i = 1;
 while (tf[`table_${i}`] !== undefined) i++;
 tf[`table_${i}`] = '';
 rlsConfig = { ...rlsConfig, table_filters: tf };
 }
 function rlsRemoveFilter(key: string) {
 if (!rlsConfig) return;
 const tf = { ...(rlsConfig.table_filters || {}) };
 delete tf[key];
 rlsConfig = { ...rlsConfig, table_filters: tf };
 }
 function rlsRenameFilter(oldKey: string, newKey: string) {
 if (!rlsConfig || oldKey === newKey) return;
 const tf: Record<string, string> = {};
 for (const [k, v] of Object.entries(rlsConfig.table_filters || {})) {
 if (k === oldKey) tf[newKey] = v as string;
 else tf[k] = v as string;
 }
 rlsConfig = { ...rlsConfig, table_filters: tf };
 }
 function rlsSetFilter(key: string, expr: string) {
 if (!rlsConfig) return;
 const tf = { ...(rlsConfig.table_filters || {}) };
 tf[key] = expr;
