const jwt = require('jsonwebtoken');
const fs = require('fs');

const PRIVATE_KEY = fs.readFileSync('./private.pem');

function signUserJWT(user) {
 return jwt.sign(
 { sub: String(user.id), store_id: user.storeId },
 PRIVATE_KEY,
