 if (lang === 'php') {
 return `<?php
// PHP — sign JWT (firebase/php-jwt)
use Firebase\\JWT\\JWT;

$privateKey = file_get_contents('private.pem');

function signUserJWT($user) {
 global $privateKey;
 $claims = [
 'sub' => (string) $user->id,
 'store_id' => $user->store_id,
 'iat' => time(),
 'exp' => time() + 900,
 ];
 return JWT::encode($claims, $privateKey, 'RS256');
}
?>`;
 }
 }
 return '';
 }

 async function loadEmbeds() {
 loadingEmbeds = true;
 try {
 const r = await fetch(`/api/projects/${slug}/embeds`, { headers: _h() });
 if (r.ok) {
 const d = await r.json();
 const raw = d.embeds || d || [];
 // Hide legacy per-agent auto-provisioned rows; keep project-level
 // default (auto_provisioned + !agent_id) and manual customs.
 embeds = (raw || []).filter((e: any) => !e?.agent_id);
 }
 // Auto-provision project-level default if missing (filter never strips
 // project-defaults — agent_id is NULL — so this check stays correct).
 const hasProjectEmbed = (embeds || []).some((e: any) => e.auto_provisioned && !e.agent_id);
 if (!embeds || embeds.length === 0 || !hasProjectEmbed) {
 try {
 await fetch(`/api/projects/${slug}/embeds/backfill`, { method: 'POST', headers: _h() });
 const r2 = await fetch(`/api/projects/${slug}/embeds`, { headers: _h() });
 if (r2.ok) {
 const d2 = await r2.json();
 const raw2 = d2.embeds || d2 || [];
 embeds = (raw2 || []).filter((e: any) => !e?.agent_id);
 }
 } catch {}
 }
 } catch {}
 loadingEmbeds = false;
 }
