 // Feature config (agent creator toggles)
 let featureConfig = $state<any>(null);
 let availablePresets = $state<any[]>([]);
 let selectedPreset = $state<string>('');
 let presetSearch = $state<string>('');
 let activeCategory = $state<string>('all');

 let filteredPresets = $derived.by(() => {
 const q = presetSearch.trim().toLowerCase();
 return availablePresets.filter((p: any) => {
 if (activeCategory !== 'all' && (p.category || 'general') !== activeCategory) return false;
 if (!q) return true;
 return p.label.toLowerCase().includes(q)
 || p.description.toLowerCase().includes(q)
 || p.key.toLowerCase().includes(q);
 });
 });

 let categoryList = $derived.by(() => {
 const seen = new Set<string>();
 const out: string[] = ['all'];
 for (const p of availablePresets) {
 const c = p.category || 'general';
 if (!seen.has(c)) { seen.add(c); out.push(c); }
 }
 return out;
 });

 let selectedPresetMeta = $derived(availablePresets.find(p => p.key === selectedPreset));

 // Auto-detect which preset matches current config (for "ACTIVE" badge).
 $effect(() => {
 if (!featureConfig || !availablePresets.length) return;
 const sameMap = (a: any, b: any) => {
 if (!a || !b) return false;
 const ks = new Set([...Object.keys(a), ...Object.keys(b)]);
 for (const k of ks) if (Boolean(a[k]) !== Boolean(b[k])) return false;
 return true;
 };
 for (const p of availablePresets) {
 if (sameMap(p.tabs, featureConfig.tabs) && sameMap(p.tools, featureConfig.tools) && sameMap(p.agents, featureConfig.agents)) {
 if (selectedPreset !== p.key) selectedPreset = p.key;
 return;
 }
 }
 if (selectedPreset !== '') selectedPreset = ''; // custom
 });
