 function relTime(iso: string | null | undefined): string {
 if (!iso) return '—';
 const t = new Date(iso).getTime();
 if (isNaN(t)) return '—';
 const s = Math.floor((Date.now() - t) / 1000);
 if (s < 60) return `${s}s ago`;
 if (s < 3600) return `${Math.floor(s/60)}m ago`;
 if (s < 86400) return `${Math.floor(s/3600)}h ago`;
 if (s < 604800) return `${Math.floor(s/86400)}d ago`;
 return `${Math.floor(s/604800)}w ago`;
 }
 function isTableTrained(name: string): boolean {
 return knowledgeFiles.some((f: any) => f.type === 'tables' && f.name === name + '.json');
 }
 function tableStatus(t: any): { label: string; cls: string } {
 if (trainingTable === t.name) return { label: 'Training', cls: 'dt-pill-warn' };
 if (isTableTrained(t.name)) return { label: 'Trained', cls: 'dt-pill-good' };
 return { label: 'Untrained', cls: 'dt-pill-muted' };
 }
 function distroBars(rows: any[], col: string, topN: number = 3): { label: string; pct: number }[] {
 if (!rows || rows.length === 0) return [];
 const counts: Record<string, number> = {};
 for (const r of rows) {
 const v = String((r ?? {})[col] ?? '');
 if (!v) continue;
 counts[v] = (counts[v] || 0) + 1;
 }
 const total = Object.values(counts).reduce((a, b) => a + b, 0) || 1;
 return Object.entries(counts)
 .map(([k, v]) => ({ label: k, pct: Math.round((v / total) * 100) }))
 .sort((a, b) => b.pct - a.pct)
 .slice(0, topN);
 }
 function fiveNum(rows: any[], col: string): { min: number; p25: number; p50: number; p75: number; max: number } | null {
 if (!rows || rows.length === 0) return null;
 const vals = rows.map(r => Number((r ?? {})[col])).filter(v => Number.isFinite(v)).sort((a, b) => a - b);
 if (vals.length === 0) return null;
 const q = (p: number) => vals[Math.min(vals.length - 1, Math.floor(p * (vals.length - 1)))];
 return { min: vals[0], p25: q(0.25), p50: q(0.5), p75: q(0.75), max: vals[vals.length - 1] };
 }
 function downloadTable(name: string, format: 'csv' | 'excel') {
 const ext = format === 'csv' ? 'csv' : 'xlsx';
 fetch(`/api/tables/${name}/download?format=${format}&project=${slug}`, { headers: _h() })
 .then(r => r.ok ? r.blob() : null)
 .then(blob => {
 if (!blob) return;
 const url = URL.createObjectURL(blob);
 const a = document.createElement('a');
 a.href = url; a.download = `${name}.${ext}`; a.click();
 URL.revokeObjectURL(url);
 });
 }
