 // Phase 5: per-source training stream + patch
 let trainingSourceId = $state<number | null>(null);
 let trainLog = $state<{step: string; detail?: string; duration?: string; cost?: string; status?: string}[]>([]);
 let driftBusy = $state<number | null>(null);
 // Classification (per-source)
 let classifyingSourceId = $state<number | null>(null);
 let classifyLog = $state<{step: string; status: string; message?: string; duration_ms?: number}[]>([]);
 let classifyStats = $state<{cols_total?: number; pii_count?: number; high_conf?: number}>({});
 let classificationCache = $state<Record<number, any>>({});

 async function loadClassification(id: number) {
 try {
 const r = await fetch(`/api/connectors/sources/${id}/classification`, { headers: _h() });
 if (r.ok) {
 const data = await r.json();
 classificationCache[id] = data;
 }
 } catch {}
 }

 async function classifySource(id: number) {
 classifyingSourceId = id;
 classifyLog = [];
 classifyStats = {};
 try {
 const res = await fetch(`/api/connectors/sources/${id}/classify`, {
 method: 'POST',
 headers: { ..._h(), 'Accept': 'text/event-stream' }
 });
 if (!res.ok || !res.body) throw new Error(`HTTP ${res.status}`);
 const reader = res.body.getReader();
 const dec = new TextDecoder();
 let buf = '';
 while (true) {
 const { done, value } = await reader.read();
 if (done) break;
 buf += dec.decode(value, { stream: true });
 let idx;
 while ((idx = buf.indexOf('\n\n')) !== -1) {
 const chunk = buf.slice(0, idx);
 buf = buf.slice(idx + 2);
 if (chunk.startsWith('data: ')) {
 try {
 const ev = JSON.parse(chunk.slice(6));
 classifyLog = [...classifyLog, ev];
 if (ev.message) {
 const m = ev.message.match(/(\d+) cols/);
 if (m) classifyStats.cols_total = parseInt(m[1]);
 const p = ev.message.match(/(\d+) pii/i);
 if (p) classifyStats.pii_count = parseInt(p[1]);
 }
 } catch {}
 } else if (chunk.startsWith('event: done')) {
 const r = await fetch(`/api/connectors/sources/${id}/classification`, { headers: _h() });
 if (r.ok) {
 const data = await r.json();
 classificationCache[id] = data;
 let cols = 0, pii = 0, high = 0;
 for (const tbl of Object.values(data) as any[]) {
 for (const c of Object.values(tbl) as any[]) {
 cols++;
 if (c.pii) pii++;
 if ((c.confidence_overall || 0) >= 0.85) high++;
 }
 }
 classifyStats = { cols_total: cols, pii_count: pii, high_conf: high };
 }
 }
 }
 }
 // Final fetch in case 'event: done' wasn't emitted
 if (!classificationCache[id]) await loadClassification(id);
 } catch (e) {
 classifyLog = [...classifyLog, { step: 'error', status: 'error', message: String(e) }];
 } finally {
 setTimeout(() => { classifyingSourceId = null; }, 1500);
 }
 }
 // Pending (unsaved) changes per source — { id -> { mode?, agent_scope?, name? } }
 let pendingSrcChanges: Record<number, Record<string, any>> = $state({});
 let savedSrcFlash: Record<number, boolean> = $state({});

 function stageSrcChange(sourceId: number, patch: Record<string, any>) {
 pendingSrcChanges = { ...pendingSrcChanges, [sourceId]: { ...(pendingSrcChanges[sourceId] || {}), ...patch } };
 }
 function discardSrcChanges(sourceId: number) {
 const next = { ...pendingSrcChanges };
 delete next[sourceId];
 pendingSrcChanges = next;
 }
 function hasPending(sourceId: number): boolean {
 const p = pendingSrcChanges[sourceId];
 return !!p && Object.keys(p).length > 0;
 }
 async function saveSrcChanges(sourceId: number) {
 const patch = pendingSrcChanges[sourceId];
 if (!patch) return;
 // Optimistic merge
 dbSources = dbSources.map((s: any) => s.id === sourceId ? { ...s, ...patch } : s);
 try {
 await fetch(`/api/connectors/sources/${sourceId}`, {
 method: 'PATCH', headers: { ..._h(), 'Content-Type': 'application/json' },
 body: JSON.stringify(patch)
 });
 discardSrcChanges(sourceId);
 savedSrcFlash = { ...savedSrcFlash, [sourceId]: true };
 setTimeout(() => {
 savedSrcFlash = { ...savedSrcFlash, [sourceId]: false };
 }, 1800);
 } catch (e) {
 console.error('save source failed', e);
 }
 }
 // Legacy single-shot patch (kept for callers that want immediate apply, e.g. delete/disconnect)
 async function patchSource(sourceId: number, patch: Record<string, any>) {
 dbSources = dbSources.map((s: any) => s.id === sourceId ? { ...s, ...patch } : s);
 try {
 await fetch(`/api/connectors/sources/${sourceId}`, {
 method: 'PATCH', headers: { ..._h(), 'Content-Type': 'application/json' },
 body: JSON.stringify(patch)
 });
 } catch {}
 }
