 // Also accept postMessage from callback page
 window.addEventListener('message', async (ev) => {
 if (ev.data && ev.data.onedrive === 'connected') {
 try { odPopup?.close(); } catch {}
 clearInterval(timer);
 await odVerifyAndLoadDrive();
 }
 }, { once: true });
 } catch (e: any) {
 odError = e?.message || 'Failed to start OneDrive OAuth';
 odStep = 'idle';
 } finally { odLoading = false; }
 }
 async function odVerifyAndLoadDrive() {
 odLoading = true; odError = '';
 try {
 const r = await fetch(`/api/onedrive/my-drive?project=${slug}`, { headers: _h() });
 if (!r.ok) throw new Error('Drive verification failed');
 const d = await r.json();
 odDriveInfo = d;
 odStep = 'connected';
 await odBrowse('root', 'My Drive');
 } catch (e: any) {
 odError = e?.message || 'Could not load OneDrive';
 odStep = 'idle';
 } finally { odLoading = false; }
 }
 async function odBrowse(folderId: string = 'root', folderName: string = 'My Drive') {
 odLoading = true; odStep = 'browsing'; odError = '';
 try {
 const r = await fetch(`/api/onedrive/browse?project=${slug}&folder_id=${folderId}`, { headers: _h() });
 if (!r.ok) throw new Error('Browse failed');
 const d = await r.json();
 odFolders = d.folders || []; odFiles = d.files || []; odTypeCounts = d.type_counts || {};
 odSelectedFolder = { id: folderId, name: folderName };
 if (folderId === 'root') odFolderPath = [{ id: 'root', name: odDriveInfo?.name || 'My Drive' }];
 } catch (e: any) {
 odError = e?.message || 'Failed to browse folder';
 } finally { odLoading = false; }
 }
 function odNavigateFolder(folderId: string, folderName: string) {
 odFolderPath = [...odFolderPath, { id: folderId, name: folderName }];
 odBrowse(folderId, folderName);
 }
 function odNavigateBreadcrumb(index: number) {
 const target = odFolderPath[index];
 odFolderPath = odFolderPath.slice(0, index + 1);
 odBrowse(target.id, target.name);
 }
 function odPickFolder() {
 odStep = 'folder_picked';
 }
 async function odFinalize() {
 odLoading = true; odError = '';
 try {
 const r = await fetch('/api/onedrive/connect', {
 method: 'POST', headers: { ..._h(), 'Content-Type': 'application/json' },
 body: JSON.stringify({
 project_slug: slug,
 folder_id: odSelectedFolder.id,
 folder_path: odFolderPath.map((f: any) => f.name).join('/'),
 file_types: odFileTypes,
 })
 });
 if (!r.ok) throw new Error('Connect failed');
 const d = await r.json();
 odStep = 'done';
 // Auto-trigger first sync
 if (d.source_id) await odSync(d.source_id, odSelectedFolder.id);
 await loadOdSources();
 odStep = 'idle'; sourceType = 'none';
 } catch (e: any) {
 odError = e?.message || 'Failed to connect OneDrive folder';
 } finally { odLoading = false; }
 }
 async function odSync(sourceId: number, folderId: string = 'root') {
 odSyncing = true; odSyncLog = []; odError = '';
 try {
 const r = await fetch('/api/onedrive/sync', {
 method: 'POST',
 headers: { ..._h(), 'Content-Type': 'application/json', 'Accept': 'text/event-stream' },
 body: JSON.stringify({ source_id: sourceId, folder_id: folderId })
 });
 if (r.ok && r.body) {
 const reader = r.body.getReader();
 const decoder = new TextDecoder();
 let buf = '';
 while (true) {
 const { done, value } = await reader.read();
 if (done) break;
 buf += decoder.decode(value, { stream: true });
 const lines = buf.split('\n');
 buf = lines.pop() || '';
 for (const line of lines) {
 if (line.startsWith('data: ')) {
 try { odSyncLog = [...odSyncLog, JSON.parse(line.slice(6))]; } catch {}
 }
 }
 }
 }
 await loadOdSources();
 } catch (e: any) {
 odError = e?.message || 'Sync failed';
 } finally { odSyncing = false; }
 }
 async function odDelete(sourceId: number) {
 if (!(await confirmDelete({ itemName: `onedrive-${sourceId}`, itemType: 'OneDrive source', message: 'Disconnect this OneDrive source? Synced files stay but new sync stops.' }))) return;
 try {
 await fetch(`/api/onedrive/sources/${sourceId}`, { method: 'DELETE', headers: _h() });
 await loadOdSources();
 } catch (e: any) { odError = e?.message || 'Delete failed'; }
 }

