 // ─── Phase 3 SELF-LEARN: polling-based cycle run (separate from SSE runLearningCycle) ───
 const SL_STEPS = ['curiosity', 'researcher', 'hypothesis', 'verifier', 'consolidator', 'forgetter', 'promotion', 'digest'];
 let slRunning = $state(false);
 let slCurrentRunId: string | null = $state(null);
 let slLogs: {ts: string; step: string; msg: string}[] = $state([]);
 let slStep: {name: string; idx: number} = $state({ name: '—', idx: 0 });
 let slStartTs: number = $state(0);
 let slElapsed: string = $state('0s');
 let slLastCost: number = $state(0);
 let slPollTimer: any = null;
 let slLogScrollEl: HTMLElement | null = $state(null);
 $effect(() => {
 void slLogs.length;
 if (slLogScrollEl) {
 queueMicrotask(() => { if (slLogScrollEl) slLogScrollEl.scrollTop = slLogScrollEl.scrollHeight; });
 }
 });
 let slRuns: any[] = $state([]);
 let slLastSummary: any = $state(null);
 let slFocus = $state('');
 let slExpanded: Record<string, boolean> = $state({});
 let slElapsedTimer: any = null;

 function _slFmtElapsed(ms: number): string {
 const s = Math.floor(ms / 1000);
 if (s < 60) return `${s}s`;
 const m = Math.floor(s / 60); const r = s % 60;
 return `${m}m${r.toString().padStart(2, '0')}s`;
 }

 async function loadSlRuns() {
 try {
 const r = await fetch(`/api/projects/${slug}/learning/runs?limit=10`, { headers: _h() });
 if (r.ok) {
 const j = await r.json();
 slRuns = j.runs || [];
 const top = slRuns[0];
 if (top && (top.status === 'done' || top.status === 'failed' || top.status === 'success')) {
 slLastSummary = top;
 } else if (slRuns.length > 0) {
 slLastSummary = slRuns.find((x: any) => x.status === 'done' || x.status === 'success' || x.status === 'failed') || null;
 }
 }
 } catch {}
 }

 function _slStopPolling() {
 if (slPollTimer) { clearInterval(slPollTimer); slPollTimer = null; }
 if (slElapsedTimer) { clearInterval(slElapsedTimer); slElapsedTimer = null; }
 }

 async function slPoll() {
 try {
 const r = await fetch(`/api/projects/${slug}/learning/runs?limit=10`, { headers: _h() });
 if (!r.ok) return;
 const j = await r.json();
 const runs = j.runs || [];
 slRuns = runs;
 const cur = runs.find((x: any) => String(x.id) === String(slCurrentRunId)) || runs[0];
 if (!cur) return;
 // Append new logs (dedup by ts+msg)
 const newLogs = cur.logs || [];
 if (newLogs.length) {
 const seen = new Set(slLogs.map(l => `${l.ts}|${l.msg}`));
 const adds = newLogs.filter((l: any) => !seen.has(`${l.ts}|${l.msg}`));
 if (adds.length) slLogs = [...slLogs, ...adds];
 }
 // Update step
 if (cur.current_step) {
 const idx = cur.step_index ?? SL_STEPS.indexOf(cur.current_step);
 slStep = { name: cur.current_step, idx: (idx >= 0 ? idx : 0) + 1 };
 }
 if (typeof cur.cost_usd === 'number') slLastCost = cur.cost_usd;
 // Stop on terminal status
 if (cur.status === 'done' || cur.status === 'failed' || cur.status === 'success' || cur.status === 'error') {
 _slStopPolling();
 slRunning = false;
 slLastSummary = cur;
 await loadSlRuns();
 }
 } catch {}
 }

 async function slStartCycle() {
 if (slRunning) return;
 slRunning = true;
 slLogs = [];
 slStep = { name: 'curiosity', idx: 1 };
 slStartTs = Date.now();
 slElapsed = '0s';
 slLastCost = 0;
 slCurrentRunId = null;
 try {
 const body: any = {};
 if (slFocus.trim()) body.focus = slFocus.trim();
 const r = await fetch(`/api/projects/${slug}/learning/run`, {
 method: 'POST',
 headers: { ..._h(), 'Content-Type': 'application/json' },
 body: JSON.stringify(body),
 });
 if (!r.ok) { slRunning = false; return; }
 const j = await r.json();
 slCurrentRunId = j.run_id || j.id || null;
 // Start polling at 2s cadence
 slPollTimer = setInterval(slPoll, 2000);
 slElapsedTimer = setInterval(() => { slElapsed = _slFmtElapsed(Date.now() - slStartTs); }, 1000);
 // Immediate first poll
 slPoll();
 } catch {
 slRunning = false;
 }
 }

 async function slStopCycle() {
 if (!slCurrentRunId) return;
 try {
 await fetch(`/api/projects/${slug}/learning/runs/${slCurrentRunId}/stop`, {
 method: 'POST',
 headers: { ..._h(), 'Content-Type': 'application/json' },
 });
 slLogs = [...slLogs, { ts: new Date().toISOString(), step: 'cycle', msg: '[stop] requested — finalizing on next checkpoint' }];
 } catch {}
 }

 // Stop polling when leaving self-learn tab
 $effect(() => {
 if (activeTab !== 'self-learn' && slPollTimer) {
 _slStopPolling();
 }
 });

 async function runLearningCycle() {
 runningCycle = true;
 cycleLog = [];
 try {
 const url = `/api/learning/cycle/${slug}${dryRun ? '?dry_run=true' : ''}`;
 const res = await fetch(url, {
 method: 'POST',
 headers: { ..._h(), 'Accept': 'text/event-stream' },
 });
 const reader = res.body!.getReader();
 const dec = new TextDecoder();
 let buf = '';
 while (true) {
 const { done, value } = await reader.read();
 if (done) break;
 buf += dec.decode(value, { stream: true });
 let idx;
 while ((idx = buf.indexOf('\n\n')) !== -1) {
 const chunk = buf.slice(0, idx);
 buf = buf.slice(idx + 2);
 if (chunk.startsWith('data: ')) {
 try {
 const ev = JSON.parse(chunk.slice(6));
 cycleLog = [...cycleLog, ev];
 } catch {}
 }
 }
 }
 await loadSelfLearn();
 } finally {
 setTimeout(() => { runningCycle = false; }, 1500);
 }
 }

