 function _h(): Record<string, string> {
 const t = typeof localStorage !== 'undefined' ? localStorage.getItem('dash_token') : null;
 return t ? { Authorization: `Bearer ${t}` } : {};
 }

 function tv(id: string): string {
 if (!detail) return '...';
 switch (id) {
 case 'cockpit': return registryOverall ? `${registryOverall}%` : '—';
 case 'datasets': return String(detail.tables?.length || 0);
 case 'data-quality': return dqData?.issue_count ? String(dqData.issue_count) : '○';
 case 'knowledge': return String(detail.knowledge_vectors || 0);
 case 'training': return String((training?.learnings || 0) + (training?.training_qa?.length || 0) + brainFeedback.length + brainPatterns.length + brainMemories.length);
 case 'evals': return String(brainEvals.length);
 case 'docs': return String(docs.length);
 case 'queries': return String(brainPatterns.length || knowledgeFiles.filter((f: any) => f.type === 'queries').length);
 case 'metrics': return metricsCount != null ? String(metricsCount) : '○';
 case 'lineage': return String([...(lineage?.relationships || []), ...relationships].length);
 case 'rules': return String(rules.length);
 case 'agents': return String(agentsData?.agents?.length || 4);
 case 'workflows': return String(workflows.length);
 case 'schedules': return String(schedules.length);
 case 'users': return String(sharedUsers.length);
 case 'embed': return String(embeds?.length || 0);
 case 'rls': return rlsConfig?.enabled ? String(Object.keys(rlsConfig?.table_filters || {}).length || 0) : '○';
 case 'config': return '';
 case 'sources': return String((spSources?.length || 0) + (gdSources?.length || 0) + (odSources?.length || 0) + (dbSources?.length || 0));
 case 'self-learn': return String(learnRuns.length || 0);
 case 'fed-health': return fedHealth && Object.keys(fedHealth).length ? String(Object.keys(fedHealth).length) : '◆';
 default: return '○';
 }
 }

 function tabStatus(id: string): 'complete' | 'partial' | 'empty' {
 if (!detail) return 'empty';
 switch (id) {
 case 'cockpit': return registryOverall >= 70 ? 'complete' : registryOverall > 0 ? 'partial' : 'empty';
 case 'datasets': {
 const tables = detail.tables?.length || 0;
 if (tables === 0) return 'empty';
 const trained = knowledgeFiles.filter((f: any) => f.type === 'tables').length;
 return trained >= tables ? 'complete' : 'partial';
 }
 case 'knowledge': return (detail.knowledge_vectors || 0) > 10 ? 'complete' : (detail.knowledge_vectors || 0) > 0 ? 'partial' : 'empty';
 case 'training': {
 const total = (training?.learnings || 0) + (training?.training_qa?.length || 0) + brainFeedback.length + brainPatterns.length + brainMemories.length;
 return total > 10 ? 'complete' : total > 0 ? 'partial' : 'empty';
 }
 case 'evals': return brainEvals.length > 3 ? 'complete' : brainEvals.length > 0 ? 'partial' : 'empty';
 case 'docs': return docs.length > 0 ? 'complete' : 'empty';
 case 'queries': {
 const qCount = knowledgeFiles.filter((f: any) => f.type === 'queries').length;
 return qCount > 2 ? 'complete' : qCount > 0 ? 'partial' : 'empty';
 }
 case 'lineage': { const _lc = [...(lineage?.relationships || []), ...relationships].length; return _lc > 2 ? 'complete' : _lc > 0 ? 'partial' : 'empty'; }
 case 'rules': return rules.length > 3 ? 'complete' : rules.length > 0 ? 'partial' : 'empty';
 case 'agents': return evolvedInstructions.current ? 'complete' : 'partial';
 case 'workflows': return workflows.length > 2 ? 'complete' : workflows.length > 0 ? 'partial' : 'empty';
 case 'schedules': return schedules.length > 0 ? 'complete' : 'empty';
 case 'users': return sharedUsers.length > 0 ? 'complete' : 'empty';
 case 'config': return 'complete';
 case 'self-learn': return learnRuns.length > 3 ? 'complete' : learnRuns.length > 0 ? 'partial' : 'empty';
 default: return 'empty';
 }
 }

 function tabStatusColor(id: string): string {
 const s = tabStatus(id);
 if (s === 'complete') return 'var(--pw-success)';
 if (s === 'partial') return '#cc7a00';
 return 'var(--pw-ink)';
 }

 function tabStatusIcon(id: string): string {
 const s = tabStatus(id);
 if (s === 'complete') return '';
 if (s === 'partial') return '◐';
 return '○';
 }

 // Auto-poll agent status every 30s while Agents tab open (passive re-activation)
 let _agentPollId: any = null;
 $effect(() => {
 if (activeTab === 'agents') {
 if (!_agentPollId) _agentPollId = setInterval(() => { loadAgents(); }, 30000);
 } else if (_agentPollId) {
 clearInterval(_agentPollId); _agentPollId = null;
 }
 });
 onDestroy(() => { if (_agentPollId) clearInterval(_agentPollId); });

 onMount(async () => {
 // Top-nav Upload link changes the hash while already on this page — switch tab.
 const _onHash = () => { const h = window.location.hash.slice(1); if (h && h !== activeTab) activeTab = h; };
 window.addEventListener('hashchange', _onHash);
 // Critical: wait only for project detail so shell + tabs render fast.
 await loadDetail();
 loading = false;
 // Background: hydrate everything else without blocking first paint.
 // allSettled so one failure can't block others.
 Promise.allSettled([
 loadLineage(), loadTraining(), loadDocs(), loadKnowledgeFiles(), loadWorkflows(),
 loadRules(), loadSuggestedRules(), loadSchedules(), loadSharedUsers(), loadPersona(),
 loadBrainData(), loadTrainingRuns(), loadDriftAlerts(), loadRelationships(),
 loadInsights(), loadPreferences(), loadMetaLearnings(), loadConsolidationStatus(),
 loadEvolvedInstructions(), loadResourceRegistry(), loadEvolutionHistory(),
 loadQueryPlans(), loadEvalHistory(), loadTransferCandidates(), loadAgents(),
 loadAgentSources(), loadAllUsers(), loadSpStatus(), loadSpSources(), loadGdStatus(),
 loadGdSources(), loadDbSources(), loadOdStatus(), loadOdSources(), loadSelfLearn(),
 loadDomainsList(), loadDriftCountsBySource(), loadCostSummary(), loadSlRuns(),
 loadDigestConfig(), loadFeatureConfig(), loadEmbeds(),
 loadRecentActivity(),
 loadTrainingSteps(), loadFlags(), loadCodexEnriched(),
 loadSqlStats(), loadSqlCacheStats(), loadQaDrops(),
 stageRehydrate(),
 ]).then(() => {
 // If a run is already in flight when the page loads, resume polling.
 if (trainStepsRunStatus === 'running') { isTraining = true; startTrainingStepsPoll(); }
 });

 // Auto-poll training runs every 5s while on Training tab + any run is active
 $effect(() => {
   if (activeTab !== 'training') return;
   // refresh Q&A drops on tab activate
   loadQaDrops();
   const id = setInterval(async () => {
     try { await loadTrainingRuns(); } catch {}
     try { await loadBrainData(); } catch {}
     try { await loadQaDrops(); } catch {}
   }, 5000);
   return () => clearInterval(id);
 });
 // Auto-load first table details
 if (detail?.tables?.length) {
 loadTableDetail(detail.tables[0].name);
 }
 // Handle OAuth callback redirects
 const urlParams = new URLSearchParams(window.location.search);
 if (urlParams.get('sharepoint') === 'connected') {
 activeTab = 'sources'; sourceType = 'sharepoint'; spLoadSites();
 window.history.replaceState({}, '', window.location.pathname);
 } else if (urlParams.get('gdrive') === 'connected') {
 activeTab = 'sources'; sourceType = 'gdrive'; gdBrowse();
 window.history.replaceState({}, '', window.location.pathname);
 } else if (urlParams.get('onedrive') === 'connected') {
 activeTab = 'sources'; sourceType = 'onedrive'; odVerifyAndLoadDrive();
 window.history.replaceState({}, '', window.location.pathname);
 }
 });

 onDestroy(() => { if (trainPollTimer) { clearInterval(trainPollTimer); trainPollTimer = null; } stopTrainingStepsPoll(); });

