 // ─── Per-source sync schedules (Phase 4) ────────────────────────────
 let sourceScheduleSaving = $state<string | null>(null);
 let sourceScheduleNote = $state<string>('');

 function _scheduleEndpointFor(src: any): string | null {
 const t = (src?.source_type || src?.db_type || src?.type || '').toLowerCase();
 if (!src?.id) return null;
 if (t === 'sharepoint') return `/api/sharepoint/sources/${src.id}/schedule`;
 if (t === 'gdrive' || t === 'google_drive') return `/api/gdrive/sources/${src.id}/schedule`;
 if (t === 'onedrive') return `/api/onedrive/sources/${src.id}/schedule`;
 if (['postgresql','mysql','fabric'].includes(t)) return `/api/connectors/sources/${src.id}/schedule`;
 return null;
 }

 async function updateSourceSchedule(src: any, schedule: string) {
 const key = `${(src.source_type||src.db_type||'?')}-${src.id}`;
 sourceScheduleSaving = key;
 sourceScheduleNote = '';
 const ep = _scheduleEndpointFor(src);
 if (!ep) { sourceScheduleNote = 'unknown source type'; sourceScheduleSaving = null; return; }
 try {
 const r = await fetch(ep, { method: 'POST', headers: { ..._h(), 'Content-Type': 'application/json' }, body: JSON.stringify({ sync_schedule: schedule }) });
 if (!r.ok) {
 if (r.status === 404 || r.status === 405) sourceScheduleNote = 'schedule endpoint not implemented yet (backend pending)';
 else sourceScheduleNote = `save failed (${r.status})`;
 } else {
 // optimistic local update + refresh
 src.sync_schedule = schedule;
 await Promise.all([loadDbSources(), loadSpSources(), loadGdSources(), loadOdSources()]);
 }
 } catch (e: any) { sourceScheduleNote = 'network error'; }
 finally { sourceScheduleSaving = null; }
 }

 function _nextFire(schedule: string, lastSync: string | null): string {
 if (!schedule || schedule === 'manual') return '—';
 const base = lastSync ? new Date(lastSync) : new Date();
 let next = new Date(base);
 if (schedule === 'hourly') next.setHours(next.getHours() + 1);
 else if (schedule === 'daily') next.setDate(next.getDate() + 1);
 else if (schedule === 'weekly') next.setDate(next.getDate() + 7);
 else return '—';
 if (next < new Date()) return 'pending';
 return next.toLocaleString('en-US', { month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit' });
 }

 let scheduleSources = $derived([
 ...(dbSources || []).map((s: any) => ({ ...s, _kind: (s.source_type || s.db_type || 'db').toUpperCase() })),
 ...(spSources || []).map((s: any) => ({ ...s, _kind: 'SHAREPOINT', source_type: 'sharepoint' })),
 ...(gdSources || []).map((s: any) => ({ ...s, _kind: 'GDRIVE', source_type: 'gdrive' })),
 ...(odSources || []).map((s: any) => ({ ...s, _kind: 'ONEDRIVE', source_type: 'onedrive' })),
 ]);

