 // ── Per-step training progress (live STEPS panel) ──────────────
 // Reads GET /api/projects/{slug}/training-steps which returns ALL steps with
 // their individual status + elapsed_ms, so concurrent tail steps stay visible
 // (the old single current_step indicator froze on one step while others ran).
 interface TrainStep { step_no: number; name: string; scope?: string; status: 'queued'|'running'|'done'|'skipped'|'failed'; elapsed_ms?: number; fp?: string; error?: string; started_at?: string; finished_at?: string; }
 let trainStepsRunId = $state<number | null>(null);
 let trainStepsRunStatus = $state<string>('');
 let trainStepsList = $state<TrainStep[]>([]);
 let trainStepsPollTimer: ReturnType<typeof setInterval> | null = null;
 let trainStepsDone = $derived(trainStepsList.filter(s => s.status === 'done').length);
 let trainStepsTotal = $derived(trainStepsList.length);

 // Pretty label for raw backend step keys (e.g. "vector_backfill" → "Vector Backfill").
 const _STEP_LABELS: Record<string, string> = {
 fingerprint: 'Fingerprint', drift: 'Drift Check', drift_detection: 'Drift Check',
 sql_profile: 'SQL Profile', profile: 'SQL Profile', dimension_catalog: 'Dimensions',
 hierarchy: 'Hierarchy', sample: 'Smart Sample', deep_analysis: 'Deep Analysis',
 metadata: 'Metadata', business_rules: 'Business Rules', qa: 'Q&A', qa_generation: 'Q&A',
 relationships: 'Relationships', persona: 'Persona', workflows: 'Workflows',
 synthesis: 'Synthesis', glossary: 'Glossary', calculations: 'Calculations',
 domain_knowledge: 'Domain Knowledge', langextract: 'Grounded Facts',
 knowledge_graph: 'Knowledge Graph', kg: 'Knowledge Graph', vector_backfill: 'Vector Backfill',
 codex_code_enrich: 'Codex Enrich', codex: 'Codex Enrich', scope: 'Scope',
 scope_derivation: 'Scope', goals: 'Learning Goals', learning_goals: 'Learning Goals',
 ml: 'ML Models', ml_auto_create: 'ML Models', evals: 'Evals', auto_config: 'Auto Config',
 reindex: 'Knowledge Index', knowledge_index: 'Knowledge Index', brain_fill: 'Brain Fill',
 memories: 'Memories', docs: 'Docs Index', dream_lite: 'Self-Learning',
 };
 function _prettyStep(name: string): string {
 if (!name) return '';
 const key = String(name).toLowerCase().replace(/\s+/g, '_');
 if (_STEP_LABELS[key]) return _STEP_LABELS[key];
 return String(name).replace(/_/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
 }
 function _pillStatus(s: string): string {
 if (s === 'running') return 'active';
 if (s === 'queued') return 'pending';
 if (s === 'skipped') return 'skipped';
 if (s === 'failed') return 'error';
 return s; // done
 }
 // Full pipeline pills = per-table steps (legacy 10, drift→persona-enrich)
 // THEN the backend-tracked tail steps (codex, vectors, KG, scope, ML, evals…),
 // deduped by label. Gives the complete flow, not just one phase.
 const pipelinePills = $derived.by(() => {
 const out: { name: string; status: string }[] = [];
 const seen = new Set<string>();
 for (const s of trainSteps) {
 if (seen.has(s.name)) continue;
 seen.add(s.name);
 out.push({ name: s.name, status: s.status });
 }
 for (const s of trainStepsList) {
 const label = _prettyStep(s.name);
 if (seen.has(label)) continue;
 seen.add(label);
 out.push({ name: label, status: _pillStatus(s.status) });
 }
 return out;
 });

 // ── Step inspector (Pipeline page) ─────────────────────────────────────
 let inspectStepName = $state<string | null>(null);
 // Which run the inspector shows. null → auto-pick the best recent run
 // (prefer one with tables + logs, since 0-table tail runs have no detail).
 let inspectRunId = $state<number | null>(null);
 const inspectRun = $derived.by(() => {
 const runs = trainingRuns || [];
 if (inspectRunId != null) return runs.find((r: any) => r.id === inspectRunId) || runs[0] || null;
 // auto: first run that has both tables and log lines, else latest.
 const rich = runs.find((r: any) => (r.tables || 0) > 0 && Array.isArray(r.logs) && r.logs.length > 0);
 return rich || runs.find((r: any) => Array.isArray(r.logs) && r.logs.length > 0) || runs[0] || null;
 });

 // The 10 per-table steps (these aren't persisted to dash_training_steps —
 // they only live in `trainSteps` during a live run). Static list so the
 // inspector shows the full pipeline even when idle.
 const _PERTABLE_STEPS = [
 'Drift Check', 'Deep Analysis', 'Q&A Generation', 'Persona',
 'Workflows + Synthesis', 'Relationships', 'Knowledge Index',
 'Brain Fill', 'Domain Knowledge', 'Persona Enrich',
 ];

 // Rich step rows for the inspector: tail steps carry fp/elapsed/scope/error
 // (from dash_training_steps); per-table steps come from the live list when
 // training, else a static list with status inferred from the last run.
 const inspectSteps = $derived.by(() => {
 const rich = trainStepsList.map((s) => ({
 name: _prettyStep(s.name), raw: s.name, status: _pillStatus(s.status),
 elapsed_ms: s.elapsed_ms, fp: s.fp, scope: s.scope, error: s.error,
 started_at: s.started_at, finished_at: s.finished_at,
 }));
 const seen = new Set(rich.map((r) => r.name));

 // Per-table steps: prefer the live `trainSteps`; otherwise the static 10
 // with status derived from the latest run (done if the run finished ok).
 let perTable: any[];
 if (trainSteps.length > 0) {
 perTable = trainSteps.map((s) => ({
 name: s.name, raw: s.name, status: s.status,
 elapsed_ms: undefined, fp: undefined, scope: 'table', error: undefined,
 }));
 } else {
 const lastRun = inspectRun;
 const runDone = lastRun && (lastRun.status === 'done' || lastRun.finished_at);
 const st = lastRun ? (runDone ? 'done' : (lastRun.status === 'failed' ? 'error' : 'active')) : 'pending';
 perTable = _PERTABLE_STEPS.map((name) => ({
 name, raw: name, status: st,
 elapsed_ms: undefined, fp: undefined, scope: 'table', error: undefined,
 }));
 }
 const legacy = perTable.filter((s) => !seen.has(s.name));
 return [...legacy, ...rich];
 });
 const inspectSelected = $derived(inspectSteps.find((s) => s.name === inspectStepName) || null);

 // Keyword map → pull the log lines that belong to a step from the latest run.
 const _STEP_KEYWORDS: Record<string, string[]> = {
 'Drift Check': ['drift'], 'Deep Analysis': ['deep analysis', 'analyzing'],
 'Q&A Generation': ['q&a', 'qa pairs', 'verified with real'], 'Persona': ['persona'],
 'Workflows + Synthesis': ['workflow', 'synthesis'], 'Relationships': ['relationship', 'join'],
 'Knowledge Index': ['index', 'reindex', 'vector backfill'], 'Brain Fill': ['brain', 'memor'],
 'Domain Knowledge': ['glossary', 'calculation', 'domain', 'kpi'], 'Persona Enrich': ['persona'],
 'Codex Enrich': ['codex', 'pipeline code', 'view ddl'], 'Knowledge Graph': ['knowledge graph', 'triple', 'kg'],
 'Derive Scope': ['scope', 'topics', 'denied'], 'Scope': ['scope', 'topics', 'denied'],
 'Vector Backfill': ['vector backfill', 'embed'], 'ML Models': ['ml ', 'ml_auto', 'model'],
 'Evals': ['eval', 'test case', 'passed'], 'Learning Goals': ['goals', 'learning_goals'],
 };
 function stepLogLines(name: string): { ts: string; msg: string }[] {
 const logs = (inspectRun?.logs || []) as any[];
 if (!logs.length) return [];
 const words = _STEP_KEYWORDS[name] || [name.toLowerCase().split(' ')[0]];
 return logs
 .filter((l) => { const m = String(l?.msg ?? '').toLowerCase(); return words.some((w) => m.includes(w)); })
 .map((l) => ({ ts: String(l.ts || ''), msg: typeof l.msg === 'string' ? l.msg : JSON.stringify(l.msg) }));
 }
 // Map an inspector step → the RUN SINGLE STEP id (so we can offer a re-run).
 const _STEP_RERUN_ID: Record<string, string> = {
 'Knowledge Graph': 'kg', 'Derive Scope': 'scope', 'Scope': 'scope', 'Persona': 'persona',
 'Persona Enrich': 'persona', 'Relationships': 'relationships', 'Learning Goals': 'goals',
 };

 function _trainStepGlyph(status: string): string {
 if (status === 'done') return '✓';
 if (status === 'skipped') return '⊘';
 if (status === 'running') return '●';
 if (status === 'failed') return '✗';
 return '○'; // queued
 }
 function _fmtElapsed(ms?: number): string {
 if (ms == null || ms < 0) return '';
 return `${Math.round(ms)}ms`;
 }

 let _cliLoggedSteps = new Set<string>();
 async function loadTrainingSteps() {
 try {
 const r = await fetch(`/api/projects/${slug}/training-steps`, { headers: _h() });
 if (!r.ok) return;
 const d = await r.json();
 const prevRunId = trainStepsRunId;
 trainStepsRunId = d.run_id ?? null;
 trainStepsRunStatus = d.run_status || '';
 const newSteps = Array.isArray(d.steps) ? d.steps : [];
 // Reset step log dedup on new run
 if (trainStepsRunId !== prevRunId) _cliLoggedSteps.clear();
 // Dispatch CLI log line for any step that transitioned to done/running
 for (const s of newSteps) {
 const key = `${trainStepsRunId}|${s.name || s.step}|${s.status}`;
 if (s.status && !_cliLoggedSteps.has(key)) {
 _cliLoggedSteps.add(key);
 const glyph = s.status === 'done' ? '✓' : s.status === 'running' ? '▸' : s.status === 'failed' ? '✗' : s.status === 'skipped' ? '⊘' : '○';
 const elapsed = s.elapsed_ms ? ` ${Math.round(s.elapsed_ms)}ms` : '';
 cLog(`${ts()} ${glyph} ${s.name || s.step}${elapsed}${s.status === 'failed' && s.error ? ` — ${s.error}` : ''}`);
 }
 }
 trainStepsList = newSteps;
 // Stop polling once the run reaches a terminal state.
 if (['done', 'failed', 'cancelled'].includes(trainStepsRunStatus)) {
 cLog(`${ts()} ━━━ training ${trainStepsRunStatus} ━━━`);
 stopTrainingStepsPoll();
 isTraining = false;
 }
 } catch {}
 }

 function startTrainingStepsPoll() {
 stopTrainingStepsPoll();
 loadTrainingSteps();
 trainStepsPollTimer = setInterval(loadTrainingSteps, 3000);
 }
 function stopTrainingStepsPoll() {
 if (trainStepsPollTimer) { clearInterval(trainStepsPollTimer); trainStepsPollTimer = null; }
 }

 const TRAIN_STEP_MAP: Record<string, number> = {
 'starting': 0, 'drift_detection': 0, 'deep_analysis': 1,
 'qa_generation': 2, 'persona': 3, 'synthesis': 4,
 'relationships': 5, 'reindex': 6, 'brain_fill': 7,
 'domain_knowledge': 8, 'persona_enrich': 9, 'complete': 10, 'cancelled': 10
 };

 function mapBackendStep(backendStep: string): number {
 return TRAIN_STEP_MAP[backendStep] ?? 0;
 }

 function cLog(text: string) {
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text } }));
 }

 function ts() {
 return new Date().toLocaleTimeString('en-US', {hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false});
 }

 async function stopTraining() {
 if (!isTraining) return;
 try {
 await fetch(`/api/projects/${slug}/stop-training`, { method: 'POST', headers: _h() });
 cLog(`${ts()} ── ⊘ training stopped by user`);
 if (trainPollTimer) { clearInterval(trainPollTimer); trainPollTimer = null; }
 stopTrainingStepsPoll();
 loadTrainingSteps();
 isTraining = false;
 trainSteps = trainSteps.map(s => s.status === 'active' ? { ...s, status: 'error' as any } : s.status === 'pending' ? { ...s, status: 'error' as any } : s);
 trainCurrentTable = ''; trainTableIndex = 0; trainTotalTables = 0; trainCurrentStepName = '';
 await Promise.all([loadDetail(), loadBrainData(), loadTrainingRuns()]);
 } catch {}
 }

 // ── Quality-review gate (runs before training) ───────────────────────
 let showQualityReview = $state(false);
 let qualityLoading = $state(false);
 let qualityItems = $state<any[]>([]);
 let qualityPicked = $state<Record<string, boolean>>({});

 async function openQualityReview() {
 qualityLoading = true;
 showQualityReview = true;
 qualityItems = [];
 qualityPicked = {};
 try {
 const r = await fetch(`/api/projects/${slug}/quality-check`, { headers: _h() });
 if (r.ok) {
 const d = await r.json();
 qualityItems = Array.isArray(d.items) ? d.items : [];
 // Pre-tick GOOD tables; leave WEAK/BAD unticked (smart default).
 const picks: Record<string, boolean> = {};
 for (const it of qualityItems) picks[it.table] = true;
 qualityPicked = picks;
 } else {
 qualityItems = [];
 }
 } catch {
 qualityItems = [];
 } finally {
 qualityLoading = false;
 }
 // No tables at all → fall straight through to normal train (doc-only project).
 if (qualityItems.length === 0) {
 showQualityReview = false;
 startTrainAll();
 }
 }

 function trainPickedTables() {
 const names = qualityItems.filter((it) => qualityPicked[it.table]).map((it) => it.table);
 if (!names.length) return;
 startTrainAll(names);
 }

 const qualitySelectedCount = $derived(
 qualityItems.filter((it) => qualityPicked[it.table]).length
 );

 async function startTrainAll(tableNames: string[] | null = null) {
 // Close the quality-review card if it was open.
 showQualityReview = false;
 isTraining = true;
 trainSteps = [
 { name: 'Drift Check', status: 'active' },
 { name: 'Deep Analysis', status: 'pending' },
 { name: 'Q&A Generation', status: 'pending' },
 { name: 'Persona', status: 'pending' },
 { name: 'Workflows + Synthesis', status: 'pending' },
 { name: 'Relationships', status: 'pending' },
 { name: 'Knowledge Index', status: 'pending' },
 { name: 'Brain Fill', status: 'pending' },
 { name: 'Domain Knowledge', status: 'pending' },
 { name: 'Persona Enrich', status: 'pending' },
 ];

 (window as any).__trainLogCount = 0;
 if (tableNames && tableNames.length) {
 cLog(`${ts()} ── starting TRAIN pipeline (${tableNames.length} selected table(s))...`);
 } else {
 cLog(`${ts()} ── starting TRAIN ALL pipeline...`);
 }

 // Fire retrain. When tableNames given, train only those (quality-review pick).
 try {
 fetch(`/api/projects/${slug}/retrain`, {
 method: 'POST',
 headers: tableNames && tableNames.length ? { ..._h(), 'Content-Type': 'application/json' } : _h(),
 body: tableNames && tableNames.length ? JSON.stringify({ table_names: tableNames }) : undefined,
 });
 } catch {}

 // Pop + stream the Activity terminal (bottom CLI) for this run.
 // stream-only event — layout won't fire a second retrain.
 try { window.dispatchEvent(new CustomEvent('dash-train-stream')); } catch {}

 // Begin live per-step polling (independent of legacy single-step stepper).
 startTrainingStepsPoll();

 // Poll training runs
 let trainLastUpdate = Date.now();
 let trainLastStep = '';
 trainPollTimer = setInterval(async () => {
 try {
 if (Date.now() - trainLastUpdate > 300000) { stopTraining(); return; }
 const r = await fetch(`/api/projects/${slug}/training-runs`, { headers: _h() });
 if (r.ok) {
 const d = await r.json();
 const runs = d.runs || [];
 if (runs.length > 0) {
 const latest = runs[0];
 const rawStep = latest.steps || '';
 // Parse enhanced format: "step_name|table_name|table_index|total_tables"
 let step = rawStep;
 if (rawStep.includes('|')) {
 const parts = rawStep.split('|');
 step = parts[0];
 trainCurrentTable = parts[1] || '';
 trainTableIndex = parseInt(parts[2] || '0', 10);
 trainTotalTables = parseInt(parts[3] || '0', 10);
 trainCurrentStepName = step.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
 } else {
 trainCurrentTable = '';
 trainTableIndex = 0;
 trainTotalTables = 0;
 trainCurrentStepName = '';
 }
 if (rawStep !== trainLastStep) { trainLastUpdate = Date.now(); trainLastStep = rawStep; }
 const activeIdx = mapBackendStep(step);

 trainSteps = trainSteps.map((s, i) => ({
 ...s,
 status: i < activeIdx ? 'done' : i === activeIdx ? 'active' : 'pending'
 }));

 // Display detailed logs from backend
 const logs = latest.logs || [];
 const loggedCount = (window as any).__trainLogCount || 0;
 if (logs.length > loggedCount) {
 for (let li = loggedCount; li < logs.length; li++) {
 const entry = logs[li];
 const _msg = typeof entry.msg === 'string' ? entry.msg : (entry.msg != null ? JSON.stringify(entry.msg) : '');
 if (_msg) cLog(`${entry.ts || ts()} │ ${_msg}`);
 }
 (window as any).__trainLogCount = logs.length;
 }

 if (latest.status === 'done' || latest.status === 'failed') {
 trainSteps = trainSteps.map(s => ({ ...s, status: 'done' }));
 if (trainPollTimer) { clearInterval(trainPollTimer); trainPollTimer = null; }
 loadTrainingSteps(); // final refresh; poll self-stops on terminal status
 cLog(`${ts()} ── training complete`);
 isTraining = false;
 trainCurrentTable = ''; trainTableIndex = 0; trainTotalTables = 0; trainCurrentStepName = '';

 // Reload data immediately so UI updates
 await Promise.all([loadDetail(), loadRules(), loadSuggestedRules(), loadBrainData(), loadTrainingRuns(), loadWorkflows(), loadDocs()]);

 // Phase 2: Run self-evolution in background (non-blocking)
 cLog(`${ts()} ── starting self-evolution (background)...`);
 (async () => {
 try {
 cLog(`${ts()} │ evolving instructions...`);
 const er = await fetch(`/api/projects/${slug}/evolve-instructions`, { method: 'POST', headers: _h() });
 const ed = await er.json();
 if (ed.status === 'ok') cLog(`${ts()} │ instructions evolved to v${ed.version}`);
 } catch {}

 try {
 cLog(`${ts()} │ mining conversation patterns...`);
 const mr = await fetch(`/api/projects/${slug}/mine-patterns`, { method: 'POST', headers: _h() });
 const md = await mr.json();
 if (md.status === 'ok') cLog(`${ts()} │ discovered ${md.workflows_created} new workflows`);
 else { const _d = typeof md.detail === 'string' ? md.detail : (md.detail ? JSON.stringify(md.detail) : 'no patterns found'); cLog(`${ts()} │ · ${_d}`); }
 } catch {}

 try {
 cLog(`${ts()} │ refreshing resource registry...`);
 const rr = await fetch(`/api/projects/${slug}/resource-registry/refresh`, { method: 'POST', headers: _h() });
 const rd = await rr.json();
 if (rd.overall_health !== undefined) cLog(`${ts()} │ overall health: ${rd.overall_health}/100`);
 } catch {}

 cLog(`${ts()} ── self-evolution complete`);
 await Promise.all([loadEvolvedInstructions(), loadResourceRegistry(), loadEvolutionHistory(), loadConsolidationStatus(), loadWorkflows()]);
 })();
 }
 }
 }
 } catch {}
 }, 2000);
 }
