 function setFile(f: File) {
 selectedFile = f;
 selectedFiles = [f];
 if (!tableName) tableName = f.name.replace(/\.[^.]+$/, '').toLowerCase().replace(/[^a-z0-9_]/g, '_');
 uploadResult = null; uploadResults = []; uploadError = ''; uploadSteps = [];
 // Detect file type from extension
 const ext = f.name.split('.').pop()?.toLowerCase() || '';
 if (ext === 'sql') uploadFileType = 'sql_patterns';
 else if (['md', 'txt', 'docx', 'pptx', 'pdf', 'jpg', 'jpeg', 'png'].includes(ext)) uploadFileType = 'document';
 else uploadFileType = 'data';
 uploadMatch = null;
 uploadAction = 'auto';
 }

 function setFiles(files: FileList) {
 const arr = Array.from(files);
 if (arr.length === 0) return;
 selectedFiles = arr;
 selectedFile = arr[0];
 if (!tableName && arr.length === 1) tableName = arr[0].name.replace(/\.[^.]+$/, '').toLowerCase().replace(/[^a-z0-9_]/g, '_');
 uploadResult = null; uploadResults = []; uploadError = ''; uploadSteps = [];
 const ext = arr[0].name.split('.').pop()?.toLowerCase() || '';
 if (ext === 'sql') uploadFileType = 'sql_patterns';
 else if (['md', 'txt', 'docx', 'pptx', 'pdf', 'jpg', 'jpeg', 'png'].includes(ext)) uploadFileType = 'document';
 else uploadFileType = 'data';
 uploadMatch = null;
 uploadAction = 'auto';
 }

 async function doUpload() {
 const filesToUpload = selectedFiles.length > 0 ? selectedFiles : (selectedFile ? [selectedFile] : []);
 if (filesToUpload.length === 0 || uploading) return;
 uploading = true; uploadError = ''; uploadResult = null; uploadResults = [];
 uploadSteps = []; liveAgents = {}; liveSteps = [];

 // Build per-file progress list
 uploadFileProgress = filesToUpload.map((f, i) => ({
 index: i, total: filesToUpload.length, name: f.name, status: 'pending'
 }));

 for (let fi = 0; fi < filesToUpload.length; fi++) {
 const currentFile = filesToUpload[fi];
 uploadFileProgress = uploadFileProgress.map((p, i) => i === fi ? { ...p, status: 'uploading' } : p);

 const fd = new FormData();
 fd.append('file', currentFile);
 if (filesToUpload.length === 1 && tableName) fd.append('table_name', tableName);
 if (uploadAction !== 'auto') fd.append('action', uploadAction);

 cLog(`${ts()} │ uploading ${fi + 1}/${filesToUpload.length}: ${currentFile.name}`);

 try {
 const ext = currentFile.name.split('.').pop()?.toLowerCase() || '';
 const isDoc = ['pptx', 'docx', 'pdf', 'md', 'txt', 'sql', 'py', 'jpg', 'jpeg', 'png'].includes(ext);
 // Use agent upload for data files (Excel/CSV/JSON), standard for docs
 const isData = ['xlsx', 'xls', 'csv', 'json', 'parquet', 'ods'].includes(ext);
 // Data files use rule-based /api/upload (fast, deterministic, chunked).
 // /api/upload-agent (LLM orchestrator) deprecated — was causing 60s+ stalls + persistence failures.
 const uploadUrl = isData
 ? `/api/upload?project=${slug}&action=${uploadAction}`
 : isDoc
 ? `/api/upload-doc?project=${slug}`
 : `/api/upload?project=${slug}&action=${uploadAction}`;

 // Use SSE streaming for doc uploads to show real-time progress
 if (isDoc) {
 const sseHeaders: Record<string, string> = { 'Accept': 'text/event-stream', ..._h() };
 const res = await fetch(uploadUrl, { method: 'POST', body: fd, headers: sseHeaders });
 if (!res.ok) {
 const e = await res.json().catch(() => ({ detail: 'Failed' }));
 const errMsg = typeof e.detail === 'string' ? e.detail : JSON.stringify(e.detail);
 cLog(`${ts()} │ ${currentFile.name}: ${errMsg}`);
 uploadFileProgress = uploadFileProgress.map((p, i) => i === fi ? { ...p, status: 'error' } : p);
 continue;
 }
 // Stream SSE events
 const reader = res.body?.getReader();
 const decoder = new TextDecoder();
 let result: any = null;
 let buffer = '';
 if (reader) {
 while (true) {
 const { done, value } = await reader.read();
 if (done) break;
 buffer += decoder.decode(value, { stream: true });
 const lines = buffer.split('\n');
 buffer = lines.pop() || '';
 for (const line of lines) {
 if (line.startsWith('data: ')) {
 try {
 const event = JSON.parse(line.slice(6));
 cLog(`${ts()} │ ${event.agent}: ${event.step} — ${event.detail}`);
 // Update live agent cards
 if (event.agent) {
 liveAgents = { ...liveAgents, [event.agent]: event.detail?.includes('done') ? 'done' : 'active' };
 liveSteps = [...liveSteps, { agent: event.agent, step: event.step, detail: event.detail }];
 }
 if (event.done && event.result) {
 result = event.result;
 // Mark all agents as done
 const doneAgents: Record<string, string> = {};
 for (const k of Object.keys(liveAgents)) doneAgents[k] = 'done';
 liveAgents = doneAgents;
 }
 } catch {}
 }
 }
 }
 }
 if (!result) result = { status: 'ok', filename: currentFile.name, type: ext, size: 0, indexed: true, tables_saved: 0 };
 const detail = result?.size ? `${result.size} chars indexed` : result?.tables_saved ? `${result.tables_saved} tables` : 'ok';
 uploadResults = [...uploadResults, { file: currentFile.name, detail, ...result }];
 uploadResult = result;
 uploadFileProgress = uploadFileProgress.map((p, i) => i === fi ? { ...p, status: 'done' } : p);
 } else {
 // Non-streaming upload for data files
 const res = await fetch(uploadUrl, { method: 'POST', body: fd, headers: _h() });
 if (!res.ok) {
 const e = await res.json().catch(() => ({ detail: 'Failed' }));
 if (res.status === 409 && e.detail?.match && filesToUpload.length === 1) {
 uploadMatch = e.detail.match;
 uploadError = `Table "${e.detail.match?.table}" already exists (${e.detail.match?.overlap_pct}% match). Choose an action below.`;
 uploadFileProgress = uploadFileProgress.map((p, i) => i === fi ? { ...p, status: 'error' } : p);
 uploading = false;
 return;
 }
 const errMsg = typeof e.detail === 'string' ? e.detail : JSON.stringify(e.detail);
 cLog(`${ts()} │ ${currentFile.name}: ${errMsg}`);
 uploadFileProgress = uploadFileProgress.map((p, i) => i === fi ? { ...p, status: 'error' } : p);
 continue;
 }
 const result = await res.json();
 const detail = result?.agent ? `${result.tables_created || 0} tables (agent)` :
 result?.multi_sheet ? `${result.tables_created} tables, ${result.total_rows} rows` :
 result?.rows ? `${result.rows} rows` :
 result?.size ? `${result.size} chars indexed` :
 result?.tables_saved ? `${result.tables_saved} tables` : 'ok';
 uploadResults = [...uploadResults, { file: currentFile.name, detail, ...result }];
 uploadResult = result;
 uploadFileProgress = uploadFileProgress.map((p, i) => i === fi ? { ...p, status: 'done' } : p);

 // Log agent report to CLI
 if (result?.agent && result?.agent_report) {
 cLog(`${ts()} │ Agent processed: ${result.tables_created || 0} tables`);
 const lines = result.agent_report.split('\n').filter((l: string) => l.trim()).slice(0, 8);
 for (const line of lines) cLog(`${ts()} │ ${line.trim().substring(0, 80)}`);
 }

 // Log processing steps to CLI
 if (result?.processing_steps?.length) {
 if (result.agents_used?.length) cLog(`${ts()} │ agents: ${result.agents_used.join(' → ')}`);
 for (const step of result.processing_steps) {
 const icon = step.status === 'done' ? '' : step.status === 'warn' ? '' : '';
 cLog(`${ts()} │ ${icon} ${step.agent}: ${step.step} — ${step.detail}`);
 }
 }
 }

 // Log to CLI (use uploadResult which is always in scope)
 if (uploadResult?.smart) {
 const smart = uploadResult.smart;
 if (smart.file_type) cLog(`${ts()} │ type: ${smart.file_type}`);
 if (smart.tables_created) cLog(`${ts()} │ ${smart.tables_created} tables created (multi-sheet)`);
 if (smart.rows_appended) cLog(`${ts()} │ ${smart.rows_appended} rows appended`);
 if (smart.rows_upserted) cLog(`${ts()} │ ${smart.rows_upserted} rows updated`);
 if (smart.annotations) cLog(`${ts()} │ ${smart.annotations} annotations saved`);
 if (smart.rules) cLog(`${ts()} │ ${smart.rules} rules extracted`);
 if (smart.patterns_saved) cLog(`${ts()} │ ${smart.patterns_saved} SQL patterns saved`);
 }
 } catch (e: any) {
 cLog(`${ts()} │ ${currentFile.name}: ${e.message}`);
 uploadFileProgress = uploadFileProgress.map((p, i) => i === fi ? { ...p, status: 'error' } : p);
 }
 }

 await loadDetail(); await loadKnowledgeFiles(); await loadRules(); await loadBrainData(); await loadDocs();
 const doneCount = uploadFileProgress.filter(p => p.status === 'done').length;
 if (doneCount === 0) {
 uploadError = 'All files failed to upload';
 } else {
 setTimeout(() => { showUpload = false; selectedFile = null; selectedFiles = []; uploadFileProgress = []; }, 5000);
 }
 uploading = false;
 }

 async function uploadDoc() {
 if (!docFile || docUploading) return;
 docUploading = true; docResult = null;
 const fd = new FormData(); fd.append('file', docFile);
 try { const r = await fetch(`/api/upload-doc?project=${slug}`, { method: 'POST', body: fd, headers: _h() }); if (r.ok) { docResult = await r.json(); await loadDocs(); } } catch {}
 docUploading = false;
 }

 async function deleteDoc(name: string) { if (!(await confirmDelete({ itemName: name, itemType: 'document' }))) return; try { await fetch(`/api/docs/${name}?project=${slug}`, { method: 'DELETE', headers: _h() }); await loadDocs(); } catch {} }

 function logTabSwitch(tabId: string) {
 const now = new Date();
 const ts = `${now.toLocaleDateString('en-US', { month: 'short', day: '2-digit' })} ${now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false })}`;

 const tabInfo: Record<string, () => string> = {
 datasets: () => {
 const tblCount = detail?.tables?.length || 0;
 const totalRows = detail?.tables?.reduce((s: number, t: any) => s + (t.rows || 0), 0) || 0;
 const docCount = docs.length;
 const totalChars = docs.reduce((s: number, d: any) => s + (d.text_chars || 0), 0);
 const totalImages = docs.reduce((s: number, d: any) => s + (d.images_described || 0), 0);
 const totalSlides = docs.reduce((s: number, d: any) => s + (d.slides || 0), 0);
 const totalPages = docs.reduce((s: number, d: any) => s + (d.pages || 0), 0);
 let parts = [`${tblCount} tables · ${totalRows.toLocaleString()} rows · ${docCount} docs`];
 if (totalChars > 0) parts.push(`${totalChars.toLocaleString()} chars extracted`);
 if (totalSlides > 0) parts.push(`${totalSlides} slides`);
 if (totalPages > 0) parts.push(`${totalPages} pages`);
 if (totalImages > 0) parts.push(`${totalImages} images described`);
 // Log per-file details
 setTimeout(() => {
 for (const d of docs) {
 let info = ` ${ts} │ ├─ ${d.name}`;
 if (d.slides) info += ` · ${d.slides} slides`;
 if (d.pages) info += ` · ${d.pages} pages`;
 if (d.text_chars) info += ` · ${d.text_chars.toLocaleString()} chars`;
 if (d.tables_extracted) info += ` · ${d.tables_extracted} tables`;
 if (d.images_described) info += ` · ${d.images_described} images`;
 if (d.scanned_pages) info += ` · ${d.scanned_pages} OCR`;
 if (d.notes_count) info += ` · ${d.notes_count} notes`;
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: info } }));
 }
 for (const t of (detail?.tables || [])) {
 const trained = knowledgeFiles.some((f: any) => f.type === 'tables' && f.name === t.name + '.json');
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: ` ${ts} │ ├─ ${t.name} · ${(t.rows || 0).toLocaleString()} rows · ${t.columns || 0} cols · ${trained ? 'TRAINED' : 'PENDING'}` } }));
 }
 if (docs.length === 0 && tblCount === 0) {
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: ` ${ts} │ └─ no files uploaded yet — drop or select files to begin` } }));
 } else {
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: ` ${ts} │ └─ ${docCount + tblCount} total files · supported: csv, xlsx, json, pptx, pdf, docx, jpg, png, md, txt` } }));
 }
 }, 100);
 return ` ${ts} │ ${parts.join(' · ')}`;
 },
 knowledge: () => ` ${ts} │ ${detail?.knowledge_vectors || 0} vector embeddings · ${knowledgeFiles.length} metadata files`,
 rules: () => ` ${ts} │ ${rules.length} active rules · ${suggestedRules.length} pending suggestions`,
 training: () => ` ${ts} │ ${training?.learnings || 0} error learnings · ${training?.training_qa?.length || 0} Q&A pairs`,
 docs: () => ` ${ts} │ ${docs.length} documents uploaded`,
 queries: () => ` ${ts} │ ${knowledgeFiles.filter((f: any) => f.type === 'queries').length} saved SQL patterns`,
 lineage: () => ` ${ts} │ ${lineage?.relationships?.length || 0} FK relationships detected`,
 agents: () => ` ${ts} │ Leader + Analyst + Engineer · model: gpt-5.4-mini`,
 workflows: () => ` ${ts} │ ${workflows.length} saved workflows`,
 schedules: () => ` ${ts} │ ${schedules.length} schedules · ${schedules.filter((s: any) => s.enabled).length} active`,
 users: () => ` ${ts} │ ${sharedUsers.length} users with access`,
 config: () => ` ${ts} │ agent: ${project?.agent_name} · personality: ${project?.agent_personality}`,
 };

 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: ` ${ts} ── accessing ${tabId.toUpperCase()} module` } }));

 const infoFn = tabInfo[tabId];
 if (infoFn) {
 const info = infoFn();
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: info } }));
 }
 }

 async function openInspect(tbl: any) {
 inspectTable = tbl; showInspect = true; inspectData = null;
 const now = new Date();
 const ts = `${now.toLocaleDateString('en-US', { month: 'short', day: '2-digit' })} ${now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false })}`;
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: ` ${ts} ── inspecting table: ${tbl.name}` } }));
 try {
 const r = await fetch(`/api/tables/${tbl.name}/inspect?project=${slug}`, { headers: _h() });
 if (r.ok) {
 inspectData = await r.json();
 window.dispatchEvent(new CustomEvent('dash-cli-log', { detail: { text: ` ${ts} │ ${inspectData.columns?.length || 0} columns · ${inspectData.sample?.length || 0} sample rows loaded` } }));
 }
 } catch {}
 }

 // ── One-Embed effects: load 24h stats when embed tab opens, sync test-access mode ──
 $effect(() => {
 if (activeTab === 'embed' && currentEmbed && !oneEmbed24h) {
 load24hStats(currentEmbed.embed_id);
 }
 });
 $effect(() => {
 if (activeTab === 'embed' && currentEmbed?.embed_id && embedRlsOpen && embedRlsLoaded !== currentEmbed.embed_id) {
 loadEmbedRls(currentEmbed.embed_id);
 }
 });
 $effect(() => {
 if (currentEmbed?.test_access_mode) {
 oneEmbedTestAccess = currentEmbed.test_access_mode as any;
 }
 if (currentEmbed?.answer_style) {
 oneEmbedAnswerStyle = currentEmbed.answer_style as any;
 }
 if (currentEmbed?.test_ip_allowlist && Array.isArray(currentEmbed.test_ip_allowlist)) {
 oneEmbedIpAllowlist = currentEmbed.test_ip_allowlist.join(', ');
 }
 });
</script>

<div class="set-shell">
  <aside class="set-rail">
    {#if !loading}
    {@const railTabs = tabs}
    {@const railIds = new Set(railTabs.map(t => t.id))}
    {@const groups = [
      { label: 'Workspace', icon: 'workspace', items: [
        { id: 'datasets', label: 'Cockpit' },
        { id: 'upload', label: 'Upload' },
        { id: 'data-quality', label: 'Data Quality' },
        { id: 'knowledge', label: 'Knowledge' },
        { id: 'training', label: 'Training' },
        { id: 'docs', label: 'Docs' },
        { id: 'queries', label: 'Queries' },
        { id: 'metrics', label: 'Definitions' },
        { id: 'lineage', label: 'Lineage' },
      ]},
      { label: 'Agents', icon: 'agents', items: [
        { id: 'agents', label: 'Agents' },
        { id: 'workflows', label: 'Workflows' },
        { id: 'schedules', label: 'Schedules' },
        { id: 'evals', label: 'Evals' },
      ]},
      { label: 'Sharing', icon: 'sharing', items: [
        { id: 'users', label: 'Users' },
        { id: 'config', label: 'Config' },
        { id: 'embed', label: 'Embed' },
        { id: 'rls', label: 'RLS' },
        { id: 'visibility', label: 'Visibility' },
        { id: 'sources', label: 'Sources' },
      ]},
      { label: 'Intelligence', icon: 'intel', items: [
        { id: 'self-learn', label: 'Learn' },
        { id: 'pipeline', label: 'Pipeline' },
        { id: 'graph', label: 'Graph' },
        { id: 'journal', label: 'Journal' },
        { id: 'canvas', label: 'Canvas' },
        { id: 'venture', label: 'VentureDesk' },
        { id: 'scenarios', label: 'Scenario Lab' },
        { id: 'fed-health', label: 'Federation' },
      ]},
    ]}
    {@const _connSrc = (spSources?.length ?? 0) + (gdSources?.length ?? 0) + (dbSources?.length ?? 0) + (odSources?.length ?? 0)}
    {#each groups as g}
      {@const visibleItems = g.items.filter(it => railIds.has(it.id)
        && !(it.id === 'scenarios' && !appFlags.sim_lab_enabled)
        && !(it.id === 'fed-health' && _connSrc < 2))}
      {#if visibleItems.length}
        <div class="set-rail-group">
          <div class="set-rail-grouplabel">{g.label}</div>
          {#each visibleItems as it}
            <button data-tab={it.id} class:active={activeTab === it.id} onclick={(e) => { activeTab = it.id; logTabSwitch(it.id); if (it.id === 'lineage' && detail?.tables) { for (const t of detail.tables) loadTableDetail(t.name); } if (it.id === 'fed-health') loadFedHealth(); if (it.id === 'rls' && !rlsConfig) { loadRlsConfig(); loadRlsSchemaHints(); } if (it.id === 'cockpit' && !agentTplLoaded) loadAgentTpl(); if (it.id === 'data-quality' && !dqLoaded) loadDataQuality(false); if (it.id === 'pipeline') { loadTrainingSteps(); loadTrainingRuns(); } if (it.id === 'datasets') { try { inspectsBatchLoaded = false; } catch {} if (!detail) { loadDetail()?.catch?.(()=>{}); } if (!extractionPlansLoaded) loadExtractionPlans(); } try { (e.currentTarget as HTMLElement)?.scrollIntoView({ block: 'nearest', behavior: 'smooth' }); } catch {} }}>
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
                {#if it.id === 'cockpit'}<circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="2" fill="currentColor"/>
                {:else if it.id === 'datasets'}<rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/>
                {:else if it.id === 'data-quality'}<path d="M12 2v20M2 12h20"/><circle cx="12" cy="12" r="9"/>
                {:else if it.id === 'knowledge'}<path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/>
                {:else if it.id === 'rules'}<path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/>
                {:else if it.id === 'training'}<path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c3 3 9 3 12 0v-5"/>
                {:else if it.id === 'docs'}<path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/>
                {:else if it.id === 'queries'}<circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/>
                {:else if it.id === 'metrics'}<path d="M3 3v18h18"/><path d="M18.7 8l-5.1 5.2-2.8-2.7L7 14.3"/>
                {:else if it.id === 'lineage'}<circle cx="6" cy="6" r="3"/><circle cx="18" cy="18" r="3"/><path d="M9 6h7a2 2 0 0 1 2 2v7"/>
                {:else if it.id === 'agents'}<circle cx="12" cy="8" r="4"/><path d="M4 21v-1a6 6 0 0 1 6-6h4a6 6 0 0 1 6 6v1"/>
                {:else if it.id === 'workflows'}<rect x="3" y="3" width="6" height="6"/><rect x="15" y="3" width="6" height="6"/><rect x="9" y="15" width="6" height="6"/><path d="M6 9v3h12V9M12 12v3"/>
                {:else if it.id === 'schedules'}<rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/>
                {:else if it.id === 'evals'}<path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/>
                {:else if it.id === 'users'}<path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="8.5" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/>
                {:else if it.id === 'config'}<circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 1 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 1 1-4 0v-.09a1.65 1.65 0 0 0-1-1.51 1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 1 1-2.83-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 1 1 0-4h.09a1.65 1.65 0 0 0 1.51-1 1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 1 1 2.83-2.83l.06.06a1.65 1.65 0 0 0 1.82.33h0a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51h0a1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 1 1 2.83 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82v0a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>
                {:else if it.id === 'embed'}<polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/>
                {:else if it.id === 'rls'}<rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/>
                {:else if it.id === 'visibility'}<path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7z"/><circle cx="12" cy="12" r="3"/>
                {:else if it.id === 'sources'}<ellipse cx="12" cy="5" rx="9" ry="3"/><path d="M21 12c0 1.66-4 3-9 3s-9-1.34-9-3"/><path d="M3 5v14c0 1.66 4 3 9 3s9-1.34 9-3V5"/>
                {:else if it.id === 'self-learn'}<path d="M12 2a4 4 0 0 0-4 4v12a4 4 0 0 0 8 0V6a4 4 0 0 0-4-4z"/><path d="M5 13a3 3 0 0 0 0 6"/><path d="M19 13a3 3 0 0 1 0 6"/>
                {:else if it.id === 'scenarios'}<circle cx="12" cy="12" r="9"/><path d="M9 12l2 2 4-4"/><path d="M3 12a9 9 0 0 1 9-9"/>
                {:else if it.id === 'fed-health'}<circle cx="12" cy="12" r="9"/><path d="M3 12h18M12 3a14 14 0 0 1 0 18M12 3a14 14 0 0 0 0 18"/>
                {:else if it.id === 'pipeline'}<path d="M3 7h13a3 3 0 0 1 0 6H8a3 3 0 0 0 0 6h13"/><circle cx="3" cy="7" r="1.5" fill="currentColor"/><circle cx="21" cy="19" r="1.5" fill="currentColor"/>
                {:else if it.id === 'graph'}<circle cx="12" cy="12" r="2"/><circle cx="5" cy="5" r="2"/><circle cx="19" cy="5" r="2"/><circle cx="5" cy="19" r="2"/><circle cx="19" cy="19" r="2"/><path d="M7 6l3.5 4.5M17 6l-3.5 4.5M7 18l3.5-4.5M17 18l-3.5-4.5"/>
                {:else if it.id === 'journal'}<path d="M4 4h14a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H4z"/><path d="M4 4v18"/><path d="M8 8h8M8 12h8M8 16h5"/>
                {:else if it.id === 'canvas'}<rect x="3" y="4" width="18" height="16" rx="1"/><path d="M3 9h18M9 4v16"/>
                {:else if it.id === 'venture'}<path d="M3 17l6-6 4 4 7-7"/><path d="M14 8h7v7"/>
                {/if}
              </svg>
              <span>{it.label}</span>
              {#if tv(it.id) && tv(it.id) !== '○' && tv(it.id) !== '' && tv(it.id) !== '◆' && tv(it.id) !== '—'}
                <span class="set-rail-count">{tv(it.id)}</span>
              {/if}
            </button>
          {/each}
        </div>
      {/if}
    {/each}
    {/if}
  </aside>

  <main class="set-main">

  <!-- Header -->
  <div class="set-head">
    <div class="set-head-left">
      <h1 class="set-title">{project?.agent_name || project?.name || 'Agent'}</h1>
      <p class="set-meta">
        {project?.category || 'General'}
        {#if detail?.tables?.length} · {detail.tables.length} table{detail.tables.length === 1 ? '' : 's'}{/if}
        {#if agentsData?.agents?.length} · {agentsData.agents.length} agent{agentsData.agents.length === 1 ? '' : 's'}{/if}
        {#if project?.created_at} · created {formatRelTime(project.created_at)}{/if}
      </p>
    </div>
    <div class="set-head-actions">
      <a class="set-ghost" href="{base}/projects" style="text-decoration: none;">← Projects</a>
      {#if canEdit && activeTab === 'cockpit'}
        {#if isTraining}
          <button class="set-cta" style="background: var(--pw-error); border-color: var(--pw-error);" onclick={stopTraining}>■ Stop training</button>
        {:else}
          <button class="set-cta" onclick={() => { openQualityReview(); }}><Icon name="zap" size={14} /> Train all</button>
        {/if}
      {/if}
      <button class="set-ghost" onclick={() => { loadResourceRegistry(); loadRecentActivity(); }}>↻ Refresh</button>
      <a class="set-ghost" href="{base}/project/{slug}" style="text-decoration: none;"><Icon name="message-circle" size={14} /> Chat</a>
    </div>
  </div>

  {#if (activeTab === 'cockpit' || activeTab === 'datasets' || activeTab === 'upload') && (isTraining || trainStepsRunStatus === 'running' || trainSteps.some(s => s.status === 'done'))}
  <div style="margin-bottom: 12px; padding: 10px 14px; border: 2px solid var(--pw-ink); background: var(--pw-surface); font-family: var(--pw-font-body);">
    <div style="display: flex; align-items: center; gap: 10px;">
      <div style="flex: 1; height: 4px; background: var(--pw-bg-alt); border: 1px solid var(--pw-muted);">
        <div style="height: 100%; background: var(--pw-accent); width: {trainSteps.length > 0 ? (trainTotalTables > 0 ? Math.min(100, Math.round((((trainTableIndex - 1) * trainSteps.length + trainSteps.filter(s => s.status === 'done').length) / (trainTotalTables * trainSteps.length)) * 100)) : Math.round((trainSteps.filter(s => s.status === 'done').length / trainSteps.length) * 100)) : 0}%; transition: width 0.5s ease;"></div>
      </div>
      <span style="font-size: 10px; font-weight: 900;">{trainSteps.length > 0 ? (trainTotalTables > 0 ? Math.min(100, Math.round((((trainTableIndex - 1) * trainSteps.length + trainSteps.filter(s => s.status === 'done').length) / (trainTotalTables * trainSteps.length)) * 100)) : Math.round((trainSteps.filter(s => s.status === 'done').length / trainSteps.length) * 100)) : 0}%</span>
      {#if trainSteps.find(s => s.status === 'active')}
        <span style="font-size: 11px; color: #cc7a00; font-weight: 900;">● {trainTotalTables > 0 ? `Table ${trainTableIndex}/${trainTotalTables}: ${trainCurrentTable} · ` : ''}{trainSteps.find(s => s.status === 'active')?.name}</span>
      {/if}
    </div>
    <!-- Live step pills (wrap) — full pipeline, light up left→right as training advances -->
    <div style="display: flex; flex-wrap: wrap; gap: 6px; margin-top: 10px;">
      {#each pipelinePills as st, pi (st.name + '_' + pi)}
        <span
          class="train-pill train-pill-{st.status}"
          style="display: inline-flex; align-items: center; gap: 5px; padding: 3px 9px; border-radius: 0; font-size: 10.5px; font-weight: 700; letter-spacing: 0.02em; white-space: nowrap;
            {st.status === 'done'
              ? 'background: var(--pw-success, #1a9c50); color: #fff; border: 1px solid var(--pw-success, #1a9c50);'
              : st.status === 'active'
                ? 'background: rgba(204,122,0,0.12); color: #cc7a00; border: 1px solid #cc7a00;'
                : st.status === 'skipped'
                  ? 'background: var(--pw-bg-alt, #f3f1ea); color: var(--pw-muted); border: 1px solid var(--pw-border, #d8d4ca);'
                  : st.status === 'error'
                    ? 'background: rgba(192,57,43,0.10); color: #c0392b; border: 1px solid #c0392b;'
                    : 'background: transparent; color: var(--pw-muted); border: 1px solid var(--pw-border, #d8d4ca);'}">
          <span>{st.status === 'done' ? '✓' : st.status === 'active' ? '●' : st.status === 'skipped' ? '⊘' : st.status === 'error' ? '✗' : '○'}</span>
          {st.name}
        </span>
      {/each}
    </div>
  </div>
  {/if}

{#if loading}
  <div style="text-align: center; padding: 40px; font-size: 11px; text-transform: uppercase; color: var(--pw-muted);">Loading...</div>
{:else}

  <div style="display: flex; flex-direction: column; flex: 1; min-height: 0;">

  <div class="dash-panel">

  <!-- ═══ COCKPIT ═══ -->
  {#if activeTab === 'cockpit'}

    <!-- Status bar (adaptive) -->
    {#if isTrained}
      <section class="set-section">
        <div class="set-trained-bar">
          <span class="set-trained-dot"></span>
          <span class="set-trained-text">Trained · {registryOverall}/100 · last activity {lastActivityText}</span>
          <button class="set-ghost set-trained-action" onclick={() => { loadResourceRegistry(); loadRecentActivity(); }}>Refresh</button>
        </div>
      </section>

      <section class="set-section">
        <h3 class="set-h3">Recent activity</h3>
        <div class="set-activity">
          {#if recentActivity.length === 0}
            <div class="set-activity-empty">No activity yet.</div>
          {:else}
            {#each recentActivity as ev}
              <div class="set-activity-row">
                <span class="set-activity-time">{ev.time}</span>
                <span class="set-activity-icon">{ev.icon}</span>
                <span class="set-activity-msg">{ev.msg}</span>
              </div>
            {/each}
          {/if}
        </div>
      </section>

      <section class="set-section">
        <div class="ds-grid ds-grid-3">
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Today</div>
            <div class="set-trained-stat-row"><span>Chats</span><b>{cockpitStats.chats}</b></div>
            <div class="set-trained-stat-row"><span>Queries</span><b>{cockpitStats.queries}</b></div>
            <div class="set-trained-stat-row"><span>Spent</span><b>${cockpitStats.cost}</b></div>
            <div class="set-trained-stat-row"><span>Insights</span><b>{cockpitStats.insightsCount}</b></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Performance</div>
            <div class="set-trained-stat-row"><span>Avg latency</span><b>{cockpitStats.latency}ms</b></div>
            <div class="set-trained-stat-row"><span>Quality (judge)</span><b>{cockpitStats.quality}/5</b></div>
            <div class="set-trained-stat-row" title="Answers that matched your pinned/proven truth (last 30d) — not a judge's opinion">
              <span>Verified accuracy</span>
              <b>{#if accuracy && accuracy.checked}<span class="set-dot trained"></span> {accuracy.pct}% <span style="color:var(--pw-muted);font-weight:400;">({accuracy.passed}/{accuracy.checked})</span>{:else}— no checks yet{/if}</b>
            </div>
            <div class="set-trained-stat-row"><span>Cache hit</span><b>{cockpitStats.cacheHit}%</b></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Health</div>
            <div class="set-trained-stat-row"><span>Brain</span><b><span class="set-dot trained"></span> {brainOk}/9 layers</b></div>
            <div class="set-trained-stat-row"><span>Tables</span><b><span class="set-dot trained"></span> healthy</b></div>
            <div class="set-trained-stat-row"><span>Connections</span><b><span class="set-dot trained"></span> online</b></div>
          </div>
        </div>
      </section>
    {/if}

    <section class="set-section">
      <h3 class="set-h3">Quick actions</h3>
      <div class="set-quick-grid">
        <a class="set-quick-card" href="{base}/project/{slug}/customer/list">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg></span>
          <span class="set-quick-name">Customers</span>
          <span class="set-quick-sub">View 360°</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/campaigns">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="m3 11 18-5v12L3 14v-3z"/><path d="M11.6 16.8a3 3 0 1 1-5.8-1.6"/></svg></span>
          <span class="set-quick-name">Campaigns</span>
          <span class="set-quick-sub">Auto + manual</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/dashboard">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="7" height="9"/><rect x="14" y="3" width="7" height="5"/><rect x="14" y="12" width="7" height="9"/><rect x="3" y="16" width="7" height="5"/></svg></span>
          <span class="set-quick-name">Dashboards</span>
          <span class="set-quick-sub">Pin charts</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/vectors">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="16" y="16" width="6" height="6" rx="1"/><rect x="2" y="16" width="6" height="6" rx="1"/><rect x="9" y="2" width="6" height="6" rx="1"/><path d="M5 16v-3a1 1 0 0 1 1-1h12a1 1 0 0 1 1 1v3M12 8v4"/></svg></span>
          <span class="set-quick-name">Vectors</span>
          <span class="set-quick-sub">Semantic search</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/search">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="7"/><path d="m21 21-4.3-4.3"/></svg></span>
          <span class="set-quick-name">Search</span>
          <span class="set-quick-sub">Hybrid BM25 + vector</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/attribution">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="6"/><circle cx="12" cy="12" r="2"/></svg></span>
          <span class="set-quick-name">Attribution</span>
          <span class="set-quick-sub">MTA</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/artifacts">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg></span>
          <span class="set-quick-name">Artifacts</span>
          <span class="set-quick-sub">Run outputs</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/rules">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg></span>
          <span class="set-quick-name">Rules</span>
          <span class="set-quick-sub">Learned from edits</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/minions">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M4 7h16M4 12h16M4 17h10"/><circle cx="19" cy="17" r="2"/></svg></span>
          <span class="set-quick-name">Minions</span>
          <span class="set-quick-sub">Jobs · Dream cycle</span>
        </a>
        <button type="button" class="set-quick-card" onclick={() => { activeTab = 'graph'; logTabSwitch('graph'); }}>
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="6" cy="6" r="3"/><circle cx="18" cy="18" r="3"/><circle cx="18" cy="6" r="3"/><circle cx="6" cy="18" r="3"/><path d="M9 6h6"/><path d="M9 18h6"/><path d="M6 9v6"/><path d="M18 9v6"/></svg></span>
          <span class="set-quick-name">Graph</span>
          <span class="set-quick-sub">Entities + links</span>
        </button>
        <a class="set-quick-card" href="{base}/project/{slug}/resolver">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M3 12h6"/><path d="M15 12h6"/><path d="M12 3v6"/><path d="M12 15v6"/></svg></span>
          <span class="set-quick-name">Resolver</span>
          <span class="set-quick-sub">Skill router</span>
        </a>
        <a class="set-quick-card" href="{base}/project/{slug}/pages">
          <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="8" y1="13" x2="16" y2="13"/><line x1="8" y1="17" x2="13" y2="17"/></svg></span>
          <span class="set-quick-name">Pages</span>
          <span class="set-quick-sub">Compiled truth + evidence</span>
        </a>
        {#if (agentTplStatus?.template?.name === 'saas') || (detail?.feature_config?.tools?.mrr_analytics === true) || (detail?.feature_config?.tools?.mrr_analytics === 'true')}
          <a class="set-quick-card" href="{base}/project/{slug}/revenue">
            <span class="set-quick-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg></span>
            <span class="set-quick-name">Revenue</span>
            <span class="set-quick-sub">MRR / ARR</span>
          </a>
        {/if}
      </div>
    </section>

    <!-- Agent Template status card -->
    {#if agentTplStatus?.applied}
      {@const s = agentTplStatus.summary || {}}
      {@const totalB = s.bindings_total || 0}
      {@const boundB = s.bindings_bound || 0}
      {@const pct = totalB > 0 ? Math.round((boundB / totalB) * 100) : 0}
      <div class="ink-border" style="margin-bottom: 16px; padding: 12px 14px; background: var(--pw-surface);">
        <div style="display:flex; justify-content:space-between; align-items:center; gap:12px;">
          <div style="flex:1;">
            <div style="font-size:11px; font-weight:900; letter-spacing:0.06em; color:var(--pw-ink); margin-bottom:4px;">
              <Icon name="package" size={14} /> AGENT TEMPLATE — {agentTplStatus.template_name?.toUpperCase()}
            </div>
            <div style="font-size:10px; color:var(--pw-muted);">
              <span style="color: {pct >= 70 ? 'var(--pw-accent)' : pct >= 40 ? '#cc7a00' : 'var(--pw-error)'}; font-weight:700;">{boundB}/{totalB} bindings</span>
              <span style="margin-left:8px;">·</span>
              <span style="margin-left:6px;">{s.workflows_active || 0}/{s.workflows_total || 0} workflows active</span>
              {#if s.bindings_needs_review > 0}
                <span style="margin-left:6px; color:#cc7a00;">· {s.bindings_needs_review} need review</span>
              {/if}
              {#if s.bindings_unbound > 0}
                <span style="margin-left:6px; color:var(--pw-muted);">· {s.bindings_unbound} unbound</span>
              {/if}
            </div>
          </div>
          {#if canEdit}
            <button onclick={openWorkflowsDrawer}
              style="padding:5px 12px; background:var(--pw-bg); border:1px solid var(--pw-ink); color:var(--pw-ink); cursor:pointer; font-family:monospace; font-size:10px; font-weight:700; letter-spacing:0.05em;">
              {agentTplShowWorkflows ? '▾ WORKFLOWS' : '▸ WORKFLOWS'}
            </button>
            <button onclick={runReconcile} disabled={agentTplReconciling}
              style="padding:5px 12px; background:var(--pw-ink); border:1px solid var(--pw-accent); color:var(--pw-accent); cursor:pointer; font-family:monospace; font-size:10px; font-weight:700; letter-spacing:0.05em;">
              {agentTplReconciling ? 'RECONCILING…' : '↻ RECONCILE'}
            </button>
          {/if}
        </div>
        {#if agentTplReconcileResult?.reconciled === false}
          <div style="margin-top:6px; font-size:10px; color:var(--pw-error);">{agentTplReconcileResult.reason}</div>
        {:else if agentTplReconcileResult?.reconciled}
          <div style="margin-top:6px; font-size:10px; color:var(--pw-accent);"><Icon name="check" size={14} /> reconciled · {agentTplReconcileResult.entities_matched}/{agentTplReconcileResult.entities_total} entities · {agentTplReconcileResult.workflows?.active || 0} workflows activated</div>
        {/if}

        {#if agentTplShowWorkflows}
          <div style="margin-top:14px; border-top:1px solid var(--pw-ink); padding-top:12px;">
            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">
              <div style="font-size:11px; font-weight:900; letter-spacing:0.06em;"><Icon name="settings" size={14} /> AUTONOMOUS WORKFLOWS ({agentTplWorkflows.length})</div>
              <button onclick={loadAgentTplInsights} style="padding:3px 10px; background:var(--pw-surface); border:1px solid var(--pw-dim); cursor:pointer; font-family:monospace; font-size:10px;">↻ REFRESH</button>
            </div>

            {#if agentTplWorkflows.length === 0}
              <div style="padding:20px; text-align:center; color:var(--pw-dim); font-size:11px;">no workflows — apply a template first</div>
            {:else}
              <div style="background:var(--pw-surface); border:1px solid var(--pw-ink); max-height:380px; overflow:auto;">
                <table style="width:100%; border-collapse:collapse; font-size:11px; font-family:monospace;">
                  <thead style="position:sticky; top:0; background:var(--pw-ink); color:var(--pw-surface);">
                    <tr>
                      <th style="padding:6px 10px; text-align:left; font-size:10px; letter-spacing:0.05em;">NAME</th>
                      <th style="padding:6px 10px; text-align:left; font-size:10px;">SCHEDULE</th>
                      <th style="padding:6px 10px; text-align:left; font-size:10px;">ACTION</th>
                      <th style="padding:6px 10px; text-align:left; font-size:10px;">STATUS</th>
                      <th style="padding:6px 10px; text-align:left; font-size:10px;">LAST RUN</th>
                      <th style="padding:6px 10px; text-align:left; font-size:10px; width:1%;">CONTROLS</th>
                    </tr>
                  </thead>
                  <tbody>
                    {#each agentTplWorkflows as w}
                      <tr style="border-top:1px solid var(--pw-border-soft);">
                        <td style="padding:6px 10px;">
                          <strong>{w.name}</strong>
                          {#if w.description}<div style="font-size:10px; color:var(--pw-muted);">{w.description}</div>{/if}
                          {#if w.last_error}<div style="font-size:10px; color:var(--pw-error); margin-top:2px;"><Icon name="alert-triangle" size={14} /> {w.last_error.slice(0,120)}</div>{/if}
                        </td>
                        <td style="padding:6px 10px; color:var(--pw-muted);">{w.schedule}</td>
                        <td style="padding:6px 10px; color:var(--pw-muted);">{w.action}</td>
                        <td style="padding:6px 10px;">
                          <span style="padding:2px 6px; font-size: 11px; font-weight:700; background:{w.status === 'active' ? 'var(--pw-success-soft)' : w.status === 'needs_review' ? '#fff4d4' : w.status === 'paused' ? 'var(--pw-border)' : 'var(--pw-error-soft)'}; border:1px solid var(--pw-border-strong);">{w.status}</span>
                        </td>
                        <td style="padding:6px 10px; color:var(--pw-muted); font-size:10px;">{formatRelTime(w.last_run_at)}</td>
                        <td style="padding:6px 10px; white-space:nowrap;">
                          {#if canEdit}
                            {#if w.status === 'active' && (!w.last_error)}
                              <button onclick={() => runWorkflowNow(w.id)} disabled={agentTplRunningWf === w.id}
                                style="padding:2px 8px; background:var(--pw-accent); color:var(--pw-ink); border:1px solid var(--pw-ink); cursor:pointer; font-family:monospace; font-size:10px; font-weight:900;">
                                {agentTplRunningWf === w.id ? '…' : '▶ RUN'}
                              </button>
                              <button onclick={() => toggleWorkflow(w.id, true)} disabled={agentTplToggling === w.id}
                                style="padding:2px 6px; background:var(--pw-surface); border:1px solid var(--pw-dim); cursor:pointer; font-family:monospace; font-size:10px; margin-left:3px;">
                                
                              </button>
                            {:else if w.status === 'paused'}
                              <button onclick={() => toggleWorkflow(w.id, false)} disabled={agentTplToggling === w.id}
                                style="padding:2px 8px; background:var(--pw-bg); color:var(--pw-ink); border:1px solid var(--pw-ink); cursor:pointer; font-family:monospace; font-size:10px;">
                                {agentTplToggling === w.id ? '…' : '▶ RESUME'}
                              </button>
                            {:else}
                              <span style="font-size:10px; color:var(--pw-dim);">— bind columns first —</span>
                            {/if}
                          {/if}
                        </td>
                      </tr>
                    {/each}
                  </tbody>
                </table>
              </div>

              {#if agentTplLastRunResult}
                <div style="margin-top:8px; padding:8px 12px; background:{agentTplLastRunResult.res.ok ? 'var(--pw-success-soft)' : 'var(--pw-error-soft)'}; border:1px solid var(--pw-ink); font-size:11px;">
                  {#if agentTplLastRunResult.res.ok}
                    <Icon name="check" size={14} /> workflow #{agentTplLastRunResult.id} ran · {agentTplLastRunResult.res.rows ?? 0} hit(s){#if agentTplLastRunResult.res.skipped} · {agentTplLastRunResult.res.skipped}{/if}
                  {:else}
                    <Icon name="x" size={14} /> workflow #{agentTplLastRunResult.id} error: {agentTplLastRunResult.res.error?.slice(0,150)}
                  {/if}
                </div>
              {/if}
            {/if}

            <!-- Insights feed -->
            <div style="margin-top:14px;">
              <div style="font-size:11px; font-weight:900; letter-spacing:0.06em; margin-bottom:6px;"> RECENT INSIGHTS ({agentTplInsights.length})</div>
              {#if agentTplInsights.length === 0}
                <div style="padding:10px; text-align:center; color:var(--pw-dim); font-size:11px; background:var(--pw-bg); border:1px solid var(--pw-border);">no autonomous insights yet — run a workflow above</div>
              {:else}
                <div style="background:var(--pw-surface); border:1px solid var(--pw-ink); max-height:300px; overflow:auto;">
                  {#each agentTplInsights as ins}
                    <div style="padding:8px 12px; border-bottom:1px solid var(--pw-border-soft); font-size:11px;">
                      <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:4px;">
                        <span style="padding:2px 6px; font-size: 11px; font-weight:700; background:{ins.severity === 'high' || ins.severity === 'critical' ? 'var(--pw-error-soft)' : ins.severity === 'warning' ? '#fff4d4' : 'var(--pw-success-soft)'}; border:1px solid var(--pw-border-strong);">{ins.severity}</span>
                        <span style="font-size:10px; color:var(--pw-dim);">{formatRelTime(ins.created_at)}</span>
                      </div>
                      <pre style="white-space:pre-wrap; margin:0; font-family:monospace; font-size:11px; line-height:1.4;">{ins.insight}</pre>
                    </div>
                  {/each}
                </div>
              {/if}
            </div>
          </div>
        {/if}
      </div>
    {/if}

    <!-- Train progress bar + stepper -->
    {#if isTraining && trainSteps.length > 0}
      {@const doneCount = trainSteps.filter(s => s.status === 'done').length}
      {@const activeStep = trainSteps.find(s => s.status === 'active')}
      {@const stepsPerTable = trainSteps.length}
      {@const pct = trainTotalTables > 0 ? Math.min(100, Math.round((((trainTableIndex - 1) * stepsPerTable + doneCount) / (trainTotalTables * stepsPerTable)) * 100)) : Math.round((doneCount / trainSteps.length) * 100)}
      <div class="ink-border" style="padding: 10px 14px; margin-bottom: 16px; background: var(--pw-surface);">
        <!-- Progress bar -->
        <div style="display: flex; align-items: center; gap: 10px; margin-bottom: 8px;">
          <div style="flex: 1; height: 6px; background: var(--pw-bg-alt); border: 1px solid var(--pw-muted);">
            <div style="height: 100%; background: var(--pw-accent); width: {pct}%; transition: width 0.5s ease;"></div>
          </div>
          <span style="font-size: 11px; font-weight: 900; min-width: 35px; text-align: right;">{pct}%</span>
        </div>
        <!-- Current step label -->
        {#if activeStep}
          <div style="font-size: 10px; color: #cc7a00; font-weight: 900; margin-bottom: 6px;">● {trainTotalTables > 0 ? `Table ${trainTableIndex}/${trainTotalTables}: ${trainCurrentTable} · ${activeStep.name}` : activeStep.name}...</div>
        {/if}
        <!-- Step badges -->
        <div style="display: flex; flex-wrap: wrap; gap: 4px; align-items: center;">
        {#each trainSteps as step}
          <span style="font-size: 11px; font-weight: 900; padding: 1px 6px; border: 1px solid {step.status === 'done' ? 'var(--pw-accent)' : step.status === 'active' ? '#cc7a00' : step.status === 'error' ? 'var(--pw-error)' : 'var(--pw-muted)'}; color: {step.status === 'done' ? 'var(--pw-accent)' : step.status === 'active' ? '#cc7a00' : step.status === 'error' ? 'var(--pw-error)' : 'var(--pw-muted)'};">
            {step.status === 'done' ? '' : step.status === 'active' ? '●' : step.status === 'error' ? '' : '○'} {step.name}
          </span>
        {/each}
        </div>
        <!-- Table progress list -->
        {#if trainTotalTables > 0 && detail?.tables?.length > 0}
          <div style="margin-top: 8px; padding-top: 8px; border-top: 1px solid var(--pw-muted);">
            <div style="font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.1em; color: var(--pw-muted); margin-bottom: 4px;">TABLE PROGRESS</div>
            {#each detail.tables as t, i}
              {@const tableNum = i + 1}
              {@const isDone = tableNum < trainTableIndex}
              {@const isActive = tableNum === trainTableIndex}
              {@const isPending = tableNum > trainTableIndex}
              <div style="font-size: 11px; font-weight: 700; font-family: var(--pw-font-body); padding: 1px 0; color: {isDone ? 'var(--pw-accent)' : isActive ? '#cc7a00' : 'var(--pw-muted)'};">
                {isDone ? '' : isActive ? '●' : '○'} {t.name} · {isDone ? 'done' : isActive ? trainCurrentStepName : 'pending'}
              </div>
            {/each}
          </div>
        {/if}
      </div>
    {/if}

    <section class="set-section">
      <div class="set-section-head">
        <h3 class="set-h3">Data tables</h3>
        <button class="set-ghost" onclick={() => { activeTab = 'datasets'; }}>Manage →</button>
      </div>
      {#if !detail?.tables || detail.tables.length === 0}
        <div class="set-empty">No tables yet. Drop files to get started.</div>
        <!-- svelte-ignore a11y_no_static_element_interactions -->
        <div class="set-drop-zone"
          ondragover={(e) => e.preventDefault()}
          ondrop={(e) => { e.preventDefault(); const files = e.dataTransfer?.files; if (files && files.length > 0) routeUpload(files); }}>
          <span class="set-drop-icon"><Icon name="arrow-up" size={14} /></span>
          <span>Drop CSV / Excel / PDF / DOCX or <button class="set-link" onclick={() => fileInputEl?.click()}>browse</button></span>
        </div>
      {:else}
        <div style="overflow-x: auto;">
          <table class="data-table" style="font-size: 11px; width: 100%;">
            <thead>
              <tr>
                <th style="text-align: left;">Table</th>
                <th style="text-align: left;">Source</th>
                <th>Rows</th>
                <th>Cols</th>
                <th>Trained</th>
                <th>Q&A</th>
                <th>Health</th>
              </tr>
            </thead>
            <tbody>
              {#each detail.tables as t}
                {@const isTrained = knowledgeFiles.some((f) => f.type === 'tables' && f.name === t.name + '.json')}
                {@const qaCount = (training?.training_qa || []).filter((q) => q.source_table === t.name).length}
                {@const health = t.health || (isTrained ? (qaCount > 0 ? 100 : 60) : 0)}
                <tr>
                  <td style="font-weight: 700;">{t.name}</td>
                  <td style="font-size: 11px; color: var(--pw-muted); max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="{t.source_file || ''}{t.source_detail ? ' → ' + t.source_detail : ''}{t.description ? ' — ' + t.description : ''}">
                    {#if t.source_file}
                      <span style="font-weight: 600; color: var(--pw-ink);">{t.source_file.split('.').pop()?.toUpperCase()}</span>
                      {#if t.source_detail}<span> {t.source_detail}</span>{/if}
                    {:else}
                      <span style="color: var(--pw-muted);">—</span>
                    {/if}
                  </td>
                  <td style="text-align: center;">{(t.rows || 0).toLocaleString()}</td>
                  <td style="text-align: center;">{t.columns || '—'}</td>
                  <td style="text-align: center;">
                    {#if isTrained}<span style="color: var(--pw-accent); font-weight: 700;"><Icon name="check" size={14} /></span>{:else}<span style="color: var(--pw-muted);">○</span>{/if}
                  </td>
                  <td style="text-align: center;">{qaCount}</td>
                  <td style="text-align: center;">
                    <span style="display: inline-block; width: 50px; height: 5px; background: rgba(0,0,0,0.08); border-radius: 0; overflow: hidden; vertical-align: middle;">
                      <span style="display: block; height: 100%; min-width: 2px; width: {Math.max(health, 0)}%; border-radius: 0; background: {health >= 67 ? 'var(--pw-success)' : health >= 34 ? 'var(--pw-warn, #cc7a00)' : 'var(--pw-error)'}; transition: width 0.3s ease, background 0.2s ease;"></span>
                    </span>
                    <span style="font-size: 11px; margin-left: 6px; color: var(--pw-muted);">{health}%</span>
                  </td>
                </tr>
              {/each}
            </tbody>
          </table>
        </div>
      {/if}
    </section>

    <section class="set-section">
      <div class="set-section-head">
        <div>
          <h3 class="set-h3">Agent brain</h3>
          <p class="set-meta">9 context layers powering the agent</p>
        </div>
      </div>
      <div class="set-brain-table">
        <div class="set-brain-row set-brain-head">
          <span>Layer</span>
          <span>Count</span>
          <span>Health</span>
          <span>Source</span>
        </div>
        {#each resourceRegistry as l}
          <div class="set-brain-row">
            <span style="text-transform: capitalize;">{l.type}</span>
            <span class="set-brain-num">{l.count}</span>
            <span class="set-brain-health">
              <span class="set-progress-track set-progress-track-sm">
                <span class="set-progress-fill" class:bar-low={(l.health || 0) < 34} class:bar-mid={(l.health || 0) >= 34 && (l.health || 0) < 67} class:bar-high={(l.health || 0) >= 67} style="width: {Math.max(l.health || 0, 0)}%"></span>
              </span>
              <span class="set-meta">{l.health}%</span>
            </span>
            <span class="set-brain-src"><code>dash_{l.type === 'instruction' ? 'evolved_instructions' : l.type === 'pattern' ? 'query_patterns' : l.type + 's'}</code></span>
          </div>
        {/each}
        {#if resourceRegistry.length === 0}
          <div class="set-brain-row"><span class="set-meta" style="grid-column: 1 / -1; text-align: center; padding: 8px 0;">No brain data yet — train the agent to populate layers.</span></div>
        {/if}
      </div>
    </section>

    <section class="set-section">
      <h3 class="set-h3">Training pipeline</h3>
      <div class="set-card">
        <div class="set-tp-status">
          <span class="set-tp-dot {isTrained ? 'ok' : 'idle'}"></span>
          <span class="set-tp-label">{isTrained ? `Last finished ${lastTrainedRel}` : 'Not trained yet. Click Train all to start.'}</span>
        </div>
        {#if isTraining || (trainingRuns && trainingRuns.length > 0)}
          {@const latestRun = trainingRuns?.[0]}
          {@const parsedStep = (() => {
            const raw = latestRun?.steps || '';
            if (raw && raw.includes('|')) {
              const p = raw.split('|');
              return { name: (p[0] || '').replace(/_/g, ' '), table: p[1] || '', idx: parseInt(p[2] || '0', 10), total: parseInt(p[3] || '0', 10) };
            }
            return { name: raw, table: '', idx: 0, total: 0 };
          })()}
          {@const stepList = (trainSteps && trainSteps.length > 0) ? trainSteps : [
            { name: 'Drift Check', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Deep Analysis', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Q&A Generation', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Persona', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Workflows + Synthesis', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Relationships', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Knowledge Index', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Brain Fill', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Domain Knowledge', status: latestRun?.status === 'done' ? 'done' : 'pending' },
            { name: 'Persona Enrich', status: latestRun?.status === 'done' ? 'done' : 'pending' },
          ]}
          <div class="pipeline-steps">
            {#each stepList as s}
              <div class="step-row" class:done={s.status === 'done'} class:running={s.status === 'active'} class:failed={s.status === 'failed'}>
                <span class="step-icon">{s.status === 'done' ? '' : s.status === 'active' ? '●' : s.status === 'failed' ? '' : '○'}</span>
                <span class="step-name">{s.name}</span>
                {#if s.status === 'active' && parsedStep.table}<span class="step-table">· {parsedStep.table}</span>{/if}
                {#if s.status === 'active' && parsedStep.idx && parsedStep.total}<span class="step-count">{parsedStep.idx}/{parsedStep.total}</span>{/if}
              </div>
            {/each}
          </div>
        {/if}

        <!-- Live per-step training progress: shows ALL steps + status + elapsed_ms.
             Replaces the single frozen current_step indicator so concurrent tail
             steps stay visible. Reads GET /api/projects/{slug}/training-steps. -->
        {#if trainStepsTotal > 0}
          <div class="train-steps-panel">
            <div class="train-steps-head">
              run #{trainStepsRunId ?? '—'} · <span class="tsp-status tsp-status--{trainStepsRunStatus}">{trainStepsRunStatus || 'unknown'}</span> · {trainStepsDone}/{trainStepsTotal} steps
            </div>
            <div class="train-steps-list">
              {#each trainStepsList as st (st.step_no)}
                <div class="tsp-row tsp-{st.status}" title={st.error || ''}>
                  <span class="tsp-glyph">{_trainStepGlyph(st.status)}</span>
                  <span class="tsp-name">{st.name}</span>
                  {#if st.scope}<span class="tsp-scope">{st.scope}</span>{/if}
                  {#if st.status === 'skipped'}
                    <span class="tsp-meta">skipped</span>
                  {:else if st.status === 'failed'}
                    <span class="tsp-meta tsp-meta--err">failed</span>
                  {:else if st.status === 'running'}
                    <span class="tsp-meta">running</span>
                  {:else if st.elapsed_ms != null}
                    <span class="tsp-meta">{_fmtElapsed(st.elapsed_ms)}</span>
                  {/if}
                </div>
              {/each}
            </div>
          </div>
        {/if}

        {#if trainingRuns && trainingRuns.length > 0}
          <div class="set-tp-runs">
            <span class="set-tp-runs-label">Last 10 runs</span>
            <div class="set-tp-spark">
              {#each trainingRuns.slice(0, 10) as r}
                <span class="set-tp-bar set-tp-bar--{r.status === 'success' ? 'ok' : r.status === 'failed' ? 'err' : 'pending'}" title="{r.status} · {r.duration_s ?? '—'}s"></span>
              {/each}
            </div>
          </div>
          <div class="set-tp-meta">
            <div><span>Avg time</span><b>{tpAvgTime}</b></div>
            <div><span>Success rate</span><b>{tpSuccessRate}%</b></div>
            <div><span>Last duration</span><b>{tpLastDuration}</b></div>
          </div>
        {/if}
      </div>
    </section>

    <section class="set-section">
      <div class="set-section-head">
        <h3 class="set-h3">Activity</h3>
        <p class="set-meta">Last 7 days</p>
      </div>
      <div class="set-act-grid">
        <div class="set-act-card">
          <span class="set-act-num">{activityStats.good || 0}</span>
          <span class="set-act-icon">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M7 10v12"/><path d="M15 5.88L14 10h5.83a2 2 0 0 1 1.92 2.56l-2.33 8A2 2 0 0 1 17.5 22H7V10l5-9 1.65 0.84a2 2 0 0 1 1.04 2.4z"/></svg>
          </span>
          <span class="set-act-label">Good feedback</span>
        </div>
        <div class="set-act-card">
          <span class="set-act-num">{activityStats.bad || 0}</span>
          <span class="set-act-icon">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M17 14V2"/><path d="M9 18.12L10 14H4.17a2 2 0 0 1-1.92-2.56l2.33-8A2 2 0 0 1 6.5 2H17v12l-5 9-1.65-0.84a2 2 0 0 1-1.04-2.4z"/></svg>
          </span>
          <span class="set-act-label">Bad feedback</span>
        </div>
        <div class="set-act-card">
          <span class="set-act-num">{activityStats.insights || 0}</span>
          <span class="set-act-icon">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2v4"/><path d="M12 18v4"/><path d="M4.93 4.93l2.83 2.83"/><path d="M16.24 16.24l2.83 2.83"/><path d="M2 12h4"/><path d="M18 12h4"/><path d="M4.93 19.07l2.83-2.83"/><path d="M16.24 7.76l2.83-2.83"/></svg>
          </span>
          <span class="set-act-label">Insights</span>
        </div>
        <div class="set-act-card">
          <span class="set-act-num">{activityStats.drift || 0}</span>
          <span class="set-act-icon">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M10.3 3.9 1.8 18.4a2 2 0 0 0 1.7 3h17a2 2 0 0 0 1.7-3L13.7 3.9a2 2 0 0 0-3.4 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
          </span>
          <span class="set-act-label">Drift alerts</span>
        </div>
        <div class="set-act-card">
          <span class="set-act-num">{activityStats.evolutions || 0}</span>
          <span class="set-act-icon">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M3 17l6-6 4 4 8-8"/><path d="M14 7h7v7"/></svg>
          </span>
          <span class="set-act-label">Evolutions</span>
        </div>
      </div>
    </section>

    <section class="set-section">
      <div class="set-section-head">
        <h3 class="set-h3">Tab completion</h3>
        <p class="set-meta">{tabsFilledCount} of {tabsTotalCount} tabs have content</p>
      </div>
      <div class="set-tc-strip">
        {#each tabCompletionPills as t}
          <span class="set-tc-pill" class:filled={t.count > 0} title="{t.count} item{t.count !== 1 ? 's' : ''}">
            <span class="set-tc-dot"></span>
            {t.label}
            {#if t.count > 0}<span class="set-tc-count">{t.count}</span>{/if}
          </span>
        {/each}
      </div>
    </section>

  <!-- ═══ DATASETS (merged with Cockpit) ═══ -->
  {:else if activeTab === 'datasets' || activeTab === 'upload'}
    {@const _totalTables = detail?.tables?.length || 0}
    {@const _totalDocs = docs.length}
    {@const _totalRows = (detail?.tables || []).reduce((s: number, t: any) => s + (t.rows || 0), 0)}
    {@const _trainedCount = (detail?.tables || []).filter((t: any) => knowledgeFiles.some((f: any) => f.type === 'tables' && f.name === t.name + '.json')).length}
    {@const _driftTotal = Object.values(driftCountsBySource).reduce((a: number, b: number) => a + (b || 0), 0)}
    {@const _connectedSources = spSources.length + gdSources.length + dbSources.length + odSources.length}
    {@const _castedCount = (detail?.tables || []).filter((t: any) => _isCasted(t.name)).length}

    {#if activeTab === 'datasets'}
    <!-- ═══ ONE COMPACT COCKPIT HEADER ═══ -->
    {#if isTrained}
      <section class="set-section cp-band">
        <div class="cp-header-strip" style="flex-wrap: wrap; gap: 10px;">
          <span class="cp-hdr-badge cp-hdr-trained"><span class="set-trained-dot"></span> Trained · {registryOverall}/100</span>
          <span class="cp-hdr-badge cp-hdr-quality"><Icon name="star" size={14} /> {cockpitStats.quality}/5</span>
          <span class="cp-hdr-meta"><strong>{_totalTables}</strong> tables · <strong>{_totalDocs}</strong> docs · <strong>{_totalRows.toLocaleString()}</strong> rows · Trained <strong>{_trainedCount}/{_totalTables}</strong></span>
          {#if trainingRuns[0]}
            <span class="cp-hdr-meta">· last trained {trainingRuns[0].finished_at ? formatRelTime(trainingRuns[0].finished_at) : '—'} ({trainingRuns[0].status || '—'}{trainingRuns[0].duration_sec ? `, ${Math.round(trainingRuns[0].duration_sec)}s` : ''})</span>
          {/if}
          {#if _driftTotal > 0}
            <button class="ds-drift-chip" onclick={openDriftDrawer} aria-label="Open drift events drawer">
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
              <span>Drift · {_driftTotal}</span>
            </button>
          {/if}
          {#if _castedCount > 0}
            <label style="display: inline-flex; align-items: center; gap: 4px; font-size: 11px; color: var(--pw-muted); cursor: pointer;" title="Tables ending in _casted are training artifacts">
              <input type="checkbox" bind:checked={showCastedTables} />
              Show casted ({_castedCount})
            </label>
          {/if}
          <span style="flex: 1;"></span>
          <div class="cp-pipeline-strip" style="margin: 0;">
            {#each [
              {key:'analysis', label:'ANALYSIS'},
              {key:'qa', label:'Q&A'},
              {key:'persona', label:'PERSONA'},
              {key:'workflows', label:'WORKFLOWS'},
              {key:'relationships', label:'RELATIONSHIPS'},
              {key:'knowledge_index', label:'KNOWLEDGE'},
            ] as step}
              {@const done = trainingRuns[0]?.status === 'done' || (trainingRuns[0]?.steps_done ?? 0) >= 6}
              <span class="cp-pipe-pill" class:cp-pipe-done={done} title={step.label}>{done ? '✓' : '○'}</span>
            {/each}
          </div>
          <button class="set-ghost" onclick={() => { loadResourceRegistry(); loadRecentActivity(); loadRecentChats(); loadTrainingRuns(); loadActivityMetrics(); loadTabCompletion(); loadSkillsSummary(); loadAntiPatternsSummary(); loadSqlStats(); loadSqlCacheStats(); }}>Refresh</button>
        </div>
      </section>
    {/if}

      <!-- STRIPPED: moved below Datasets content as 6-band layout -->
      {#if false}
      <!-- PIPELINE STATUS -->
      <section class="set-section">
        <h3 class="set-h3">Pipeline status</h3>
        <div class="ds-grid ds-grid-3">
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Last training</div>
            <div class="set-trained-stat-row"><span>When</span><b>{trainingRuns[0]?.finished_at ? formatRelTime(trainingRuns[0].finished_at) : '—'}</b></div>
            <div class="set-trained-stat-row"><span>Steps</span><b>{trainingRuns[0]?.steps_done ?? '—'}/{trainingRuns[0]?.steps_total ?? '—'}</b></div>
            <div class="set-trained-stat-row"><span>Duration</span><b>{trainingRuns[0]?.duration_sec ? `${Math.round(trainingRuns[0].duration_sec)}s` : '—'}</b></div>
            <div class="set-trained-stat-row"><span>Cost</span><b>{trainingRuns[0]?.cost_usd ? `$${trainingRuns[0].cost_usd.toFixed(4)}` : '—'}</b></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Schedule</div>
            <div class="set-trained-stat-row"><span>Next</span><b>{(agentTplWorkflows || []).find((w: any) => w.schedule)?.schedule || 'On-demand'}</b></div>
            <div class="set-trained-stat-row"><span>Active workflows</span><b>{(agentTplWorkflows || []).filter((w: any) => w.status === 'active').length}</b></div>
            <div style="margin-top: 8px;"><button class="set-ghost" onclick={() => { openQualityReview(); }} disabled={isTraining}>{isTraining ? 'Training…' : 'Train now'}</button></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Drift</div>
            <div class="set-trained-stat-row"><span>Alerts</span><b><span class="set-dot {_driftTotalCock === 0 ? 'trained' : 'warn'}"></span> {_driftTotalCock}</b></div>
            <div class="set-trained-stat-row"><span>Casted</span><b>{_castedCount}</b></div>
            {#if _driftTotalCock > 0}<div style="margin-top: 8px;"><button class="set-ghost" onclick={openDriftDrawer}>Review →</button></div>{/if}
          </div>
        </div>
      </section>

      <!-- TODAY / PERFORMANCE / HEALTH -->
      <section class="set-section">
        <h3 class="set-h3">At a glance</h3>
        <div class="ds-grid ds-grid-3">
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Today</div>
            <div class="set-trained-stat-row"><span>Chats</span><b>{cockpitStats.chats}</b></div>
            <div class="set-trained-stat-row"><span>Queries</span><b>{cockpitStats.queries}</b></div>
            <div class="set-trained-stat-row"><span>Spent</span><b>${cockpitStats.cost}</b></div>
            <div class="set-trained-stat-row"><span>Insights</span><b>{cockpitStats.insightsCount}</b></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Performance</div>
            <div class="set-trained-stat-row"><span>Avg latency</span><b>{cockpitStats.latency}ms</b></div>
            <div class="set-trained-stat-row"><span>Quality (judge)</span><b>{cockpitStats.quality}/5</b></div>
            <div class="set-trained-stat-row" title="Answers that matched your pinned/proven truth (last 30d) — not a judge's opinion">
              <span>Verified accuracy</span>
              <b>{#if accuracy && accuracy.checked}<span class="set-dot trained"></span> {accuracy.pct}% <span style="color:var(--pw-muted);font-weight:400;">({accuracy.passed}/{accuracy.checked})</span>{:else}— no checks yet{/if}</b>
            </div>
            <div class="set-trained-stat-row"><span>Cache hit</span><b>{cockpitStats.cacheHit}%</b></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Health</div>
            <div class="set-trained-stat-row"><span>Brain</span><b><span class="set-dot trained"></span> {brainOk}/9 layers</b></div>
            <div class="set-trained-stat-row"><span>Tables</span><b><span class="set-dot trained"></span> {_trainedCount}/{_totalTables}</b></div>
            <div class="set-trained-stat-row"><span>Sources</span><b><span class="set-dot {_connectedSources > 0 ? 'trained' : 'idle'}"></span> {_connectedSources} connected</b></div>
          </div>
          {#if sqlStats || sqlCacheStats}
            <div class="ds-card-flat">
              <div class="set-trained-stat-head">SQL safety</div>
              <div class="set-trained-stat-row"><span>Auto-fixes (7d)</span><b>{((sqlStats?.auto_fix_count ?? 0) + (sqlStats?.chat_autofix_count ?? 0))}</b></div>
              <div class="set-trained-stat-row"><span>Q&amp;A drops</span><b>{sqlStats?.qa_drop_count ?? '—'}</b></div>
              <div class="set-trained-stat-row"><span>Cache hit</span><b>{sqlCacheStats?.hit_rate != null ? `${sqlCacheStats.hit_rate}%` : '—'}</b></div>
            </div>
          {/if}
        </div>
      </section>

      <!-- KNOWLEDGE / AGENTS / COST -->
      <section class="set-section">
        <h3 class="set-h3">Intelligence</h3>
        <div class="ds-grid ds-grid-3">
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Knowledge & Brain</div>
            <div class="set-trained-stat-row"><span>Knowledge files</span><b>{knowledgeFiles.length}</b></div>
            <div class="set-trained-stat-row"><span>KG triples</span><b>{_kgCount}</b></div>
            <div class="set-trained-stat-row"><span>Brain layers</span><b>{brainOk}/9</b></div>
            <div style="margin-top: 8px;"><button class="set-ghost" onclick={() => { activeTab = 'knowledge'; }}>Open knowledge →</button></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Agents</div>
            <div class="set-trained-stat-row"><span>Configured</span><b>{(project as any)?.agents_count ?? 41}</b></div>
            <div class="set-trained-stat-row"><span>Active workflows</span><b>{(agentTplWorkflows || []).filter((w: any) => w.status === 'active').length}</b></div>
            <div class="set-trained-stat-row"><span>Bindings</span><b>{(agentTplBindings || []).filter((b: any) => b.status === 'bound').length}/{(agentTplBindings || []).length}</b></div>
            <div style="margin-top: 8px;"><button class="set-ghost" onclick={() => { activeTab = 'agents'; }}>Open agents →</button></div>
          </div>
          <div class="ds-card-flat">
            <div class="set-trained-stat-head">Cost & quota</div>
            <div class="set-trained-stat-row"><span>Today</span><b>${cockpitStats.cost}</b></div>
            <div class="set-trained-stat-row"><span>Cap</span><b>${costCapInput.toFixed(2)}</b></div>
            <div style="margin-top: 6px; height: 6px; background: var(--pw-bg-alt); border-radius: 0; overflow: hidden;">
              <div style="width: {_pct}%; height: 100%; background: {_pct > 80 ? '#ff4040' : 'var(--pw-accent)'};"></div>
            </div>
            <div class="set-trained-stat-row" style="margin-top: 6px;"><span>Used</span><b>{_pct.toFixed(1)}%</b></div>
          </div>
        </div>
      </section>

      <!-- Recent activity -->
      <section class="set-section">
        <h3 class="set-h3">Recent activity</h3>
        <div class="set-activity">
          {#if recentActivity.length === 0}
            <div class="set-activity-empty">No activity yet.</div>
          {:else}
            {#each recentActivity as ev}
              <div class="set-activity-row">
                <span class="set-activity-time">{ev.time}</span>
                <span class="set-activity-icon">{ev.icon}</span>
                <span class="set-activity-msg">{ev.msg}</span>
              </div>
            {/each}
          {/if}
        </div>
      </section>

      <!-- Recent chats -->
      <section class="set-section">
        <h3 class="set-h3">Recent chats</h3>
        {#if recentChats.length === 0}
          <div class="set-activity-empty">No chats yet.</div>
        {:else}
          <div class="set-activity">
            {#each recentChats as c}
              <div class="set-activity-row">
                <span class="set-activity-time">{c.updated_at ? formatRelTime(c.updated_at) : '—'}</span>
                <span class="set-activity-msg" style="flex: 1;">{c.first_message || '(no preview)'}</span>
                {#if c.score !== null && c.score !== undefined}<span style="font-size: 11px; color: var(--pw-muted);">{c.score}/5</span>{/if}
                <a href="{base}/project/{slug}?session={c.session_id}" class="set-ghost" style="font-size: 11px;">Open →</a>
              </div>
            {/each}
          </div>
        {/if}
      </section>
    {/if}
    {/if}<!-- end cockpit summary (datasets-only) -->

    {#if activeTab === 'upload'}
    <input type="file" accept=".csv,.xlsx,.xls,.json,.sql,.md,.txt,.py,.pptx,.docx,.pdf,.jpg,.jpeg,.png,.tiff,.bmp,.gif,.webp,.parquet,.ods,.xml,.html,.htm,.zip,.eml" multiple onchange={(e) => { const files = (e.target as HTMLInputElement).files; if (files && files.length > 0) routeUpload(files); }} bind:this={fileInputEl} style="display: none;" />

    {#if canEdit}
      <!-- Compact dropzone -->
      <button
        type="button"
        class="ds-drop"
        ondragover={(e) => { e.preventDefault(); }}
        ondrop={(e) => { e.preventDefault(); const files = e.dataTransfer?.files; if (files && files.length > 0) routeUpload(files); }}
        onclick={() => fileInputEl?.click()}
        aria-label="Upload files"
      >
        <span class="ds-drop-icon">
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
        </span>
        <span class="ds-drop-main">Drop files or browse</span>
        <span class="ds-drop-sub">Validate before load · CSV · Excel · PDF · DOCX · PPTX · JSON · 200 MB</span>
      </button>

      {#if stageBusy}<div class="cp-hdr-meta" style="margin-top:6px;">staging…</div>{/if}
      {#if stageResult}
        <div class="cp-hdr-meta" style="margin-top:6px;">
          Promote result — {stageResult.status} · {stageResult.loaded_files} loaded · {stageResult.quarantined} quarantined
          {#if stageResult.status !== 'undone' && stageBatchId}
            <button class="set-link" disabled={stageBusy} style="margin-left:8px; color:#c43;" onclick={stageUndo}>{stageUndoArm ? 'click again to confirm undo' : 'undo'}</button>
          {/if}
        </div>
      {/if}

      {#if gdSetupWarning}
        <div class="ds-warn">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
          <span>Google Drive is not configured. <code>GOOGLE_CLIENT_ID</code> / <code>GOOGLE_CLIENT_SECRET</code> must be set by an administrator.</span>
          <a href="/ui/command-center?tab=integrations" target="_blank" rel="noopener" class="ds-warn-link">Open integrations →</a>
          <button onclick={() => { gdSetupWarning = false; }} class="ds-warn-close" aria-label="Dismiss"><Icon name="x" size={14} /></button>
        </div>
      {/if}

      <!-- Train (minimal Upload tab) -->
      {#if _totalTables > 0 || _totalDocs > 0 || stageBatchId}
        <div class="ds-section-head" style="margin-top:18px;">
          <h3 class="ds-section-title">Train the agent</h3>
          <button class="ds-btn ds-btn-sm ds-btn-primary" onclick={() => { openQualityReview(); }} disabled={!!trainingTable || isTraining}>
            <Icon name="zap" size={13} /> {isTraining ? 'Training…' : 'Train all'}
          </button>
        </div>
        <p class="cp-hdr-meta" style="margin-top:4px;">Training updates the agent's brain — knowledge, definitions, Q&A — from your uploaded data.</p>
      {/if}

      {#if false}
      <!-- Connected sources (hidden on Upload tab) -->
      <div class="ds-section-head">
        <h3 class="ds-section-title">Connected sources <span class="ds-count">({_connectedSources})</span></h3>
        <div class="ds-chip-row">
          <button class="ds-chip" onclick={() => { if (!spConfigured) { spSetupModal = true; } else { activeTab = 'sources'; sourceType = 'sharepoint'; spStartConnect(); } }} title={spConfigured ? 'SharePoint' : 'Setup needed'}>
            <span class="ds-chip-plus">+</span> SharePoint
          </button>
          <button class="ds-chip" onclick={gdriveIconClick} title={gdConfigured ? 'Connect Google Drive' : 'Click to check setup'}>
            <span class="ds-chip-plus">+</span> Drive
          </button>
          <button class="ds-chip" onclick={() => { dbType = 'postgresql'; dbStep = 'form'; connectorModal = 'postgres'; }} title="PostgreSQL">
            <span class="ds-chip-plus">+</span> Postgres
          </button>
          <button class="ds-chip" onclick={() => { dbType = 'mysql'; dbStep = 'form'; connectorModal = 'mysql'; }} title="MySQL">
            <span class="ds-chip-plus">+</span> MySQL
          </button>
          <button class="ds-chip" onclick={() => { dbType = 'fabric'; dbStep = 'form'; connectorModal = 'fabric'; }} title="Microsoft Fabric / SQL Server">
            <span class="ds-chip-plus">+</span> Fabric
          </button>
        </div>
      </div>

      {#if _connectedSources === 0}
        <div class="ds-empty-line">No remote sources connected yet.</div>
      {:else}
        <div class="ds-source-list">
          {#each dbSources as src (src.id)}
            {@const cfg = src.config || {}}
            {@const tbls = cfg.selected_tables || src.selected_tables || []}
            {@const dialect = (cfg.db_type || src.source_type || '').toLowerCase()}
            {@const lastSync = src.last_sync_at ? String(src.last_sync_at).slice(0, 16).replace('T', ' ') : 'never'}
            <div class="ds-source-row">
              <span class="ds-source-dot"></span>
              <span class="ds-source-kind">{dialect}</span>
              <span class="ds-source-meta">
                {#if src.name}<strong>{src.name}</strong> · {/if}{cfg.host || src.host || '?'}:{cfg.port || src.port || ''}/{cfg.database || src.database || '?'}
                <span class="ds-source-sub">tables: {tbls.length} · last sync: {lastSync}</span>
              </span>
              <span class="ds-source-actions">
                <button class="ds-btn ds-btn-sm" onclick={() => openAddTables(src)} title="Add more tables">+ Tables</button>
                <button class="ds-btn ds-btn-sm" disabled={dbSyncing} onclick={() => dbSync(src.id)} title="Re-sync">{dbSyncing ? '…' : 'Sync'}</button>
                <button class="ds-btn ds-btn-sm ds-btn-danger" onclick={async () => { if (await confirmDelete({ itemName: src.name || `${dialect} source`, itemType: 'database source' })) dbDelete(src.id); }} title="Disconnect">Remove</button>
              </span>
            </div>
            {#if tbls.length > 0}
              <div class="ds-source-tables">{tbls.join(' · ')}</div>
            {/if}
          {/each}
          {#each spSources as src (src.id)}
            <div class="ds-source-row">
              <span class="ds-source-dot"></span>
              <span class="ds-source-kind">sharepoint</span>
              <span class="ds-source-meta">{src.site_name || src.folder_path || 'connected'}</span>
              <span class="ds-source-sub-inline">manage on sources tab</span>
            </div>
          {/each}
          {#each gdSources as src (src.id)}
            <div class="ds-source-row">
              <span class="ds-source-dot"></span>
              <span class="ds-source-kind">drive</span>
              <span class="ds-source-meta">{src.folder_path || 'My Drive'}</span>
              <span class="ds-source-sub-inline">manage on sources tab</span>
            </div>
          {/each}
          {#each odSources as src (src.id)}
            <div class="ds-source-row">
              <span class="ds-source-dot"></span>
              <span class="ds-source-kind">onedrive</span>
              <span class="ds-source-meta">{src.folder_path || src.site_name || 'connected'}</span>
              <span class="ds-source-sub-inline">manage on sources tab</span>
            </div>
          {/each}
        </div>
      {/if}

      <!-- ADD MORE TABLES modal -->
      {#if showQualityReview}
        <!-- svelte-ignore a11y_no_static_element_interactions -->
        <!-- svelte-ignore a11y_click_events_have_key_events -->
        <div style="position: fixed; inset: 0; background: rgba(0,0,0,0.55); z-index: 1001; display: flex; align-items: center; justify-content: center; padding: 20px;" onclick={(e) => { if (e.target === e.currentTarget && !isTraining) showQualityReview = false; }}>
          <div class="ink-border stamp-shadow" style="background: var(--pw-surface); width: 560px; max-width: 94vw; max-height: 88vh; overflow-y: auto;">
            <div class="dark-title-bar" style="padding: 10px 14px; font-size: 11px; display: flex; justify-content: space-between; align-items: center;">
              <span>QUALITY CHECK — pick what to train</span>
              <button style="background: none; border: none; color: var(--pw-surface); cursor: pointer; font-size: 13px;" onclick={() => { if (!isTraining) showQualityReview = false; }}>×</button>
            </div>
            <div style="padding: 14px; font-size: 12px;">
              {#if qualityLoading}
                <div style="color: var(--pw-muted); padding: 20px; text-align: center;">Checking data quality… (fast, free)</div>
              {:else if qualityItems.length === 0}
                <div style="color: var(--pw-muted); padding: 20px; text-align: center;">No data tables found.</div>
              {:else}
                <div style="color: var(--pw-muted); margin-bottom: 10px;">Good tables are pre-selected. Untick anything you don't want trained — or tick a weak one to train it anyway.</div>
                <div style="display: flex; flex-direction: column; gap: 6px;">
                  {#each qualityItems as it (it.table)}
                    {@const color = it.verdict === 'GOOD' ? '#1a9c50' : (it.verdict === 'WEAK' ? '#c87a1a' : '#c0392b')}
                    {@const glyph = it.verdict === 'GOOD' ? '✓' : (it.verdict === 'WEAK' ? '⚠' : '✗')}
                    <!-- svelte-ignore a11y_label_has_associated_control -->
                    <label style="display: flex; gap: 10px; align-items: flex-start; padding: 10px 12px; border: 1px solid var(--pw-border, #e3e0d8); border-radius: 0; cursor: pointer; background: {qualityPicked[it.table] ? 'rgba(201,99,66,0.04)' : 'transparent'};">
                      <input type="checkbox" bind:checked={qualityPicked[it.table]} style="margin-top: 2px;" />
                      <span style="flex: 1; min-width: 0;">
                        <span style="display: flex; justify-content: space-between; align-items: center; gap: 8px;">
                          <span style="font-weight: 700; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">{it.table}</span>
                          <span style="flex-shrink: 0; font-weight: 700; color: {color};">{glyph} {it.verdict} · {it.score}/100</span>
                        </span>
                        <span style="display: block; color: var(--pw-muted); font-size: 11px; margin-top: 2px;">{(it.rows || 0).toLocaleString()} rows · {it.cols || 0} cols — {Array.isArray(it.reasons) ? it.reasons.join(' · ') : ''}</span>
                      </span>
                    </label>
                  {/each}
                </div>
              {/if}
            </div>
            {#if !qualityLoading && qualityItems.length > 0}
              <div style="padding: 12px 14px; border-top: 1px solid var(--pw-border, #e3e0d8); display: flex; justify-content: space-between; align-items: center; gap: 10px;">
                <button class="set-ghost" onclick={() => { showQualityReview = false; }} disabled={isTraining}>Cancel</button>
                <button class="set-cta" onclick={trainPickedTables} disabled={isTraining || qualitySelectedCount === 0}>
                  <Icon name="zap" size={14} /> Train {qualitySelectedCount} selected
                </button>
              </div>
            {/if}
          </div>
        </div>
      {/if}

      {#if addTablesModal}
        <!-- svelte-ignore a11y_no_static_element_interactions -->
        <!-- svelte-ignore a11y_click_events_have_key_events -->
        <div style="position: fixed; inset: 0; background: rgba(0,0,0,0.55); z-index: 200; display: flex; align-items: center; justify-content: center;" onclick={(e) => { if (e.target === e.currentTarget) addTablesModal = null; }}>
          <div class="ink-border stamp-shadow" style="background: var(--pw-surface); width: 480px; max-height: 92vh; overflow-y: auto;">
            <div class="dark-title-bar" style="padding: 10px 14px; font-size: 11px; display: flex; justify-content: space-between; align-items: center;">
              <span>+ ADD TABLES — {(addTablesModal.config?.host || '?')}/{(addTablesModal.config?.database || '?')}</span>
              <button style="background: none; border: none; color: var(--pw-surface); cursor: pointer; font-size: 13px;" onclick={() => addTablesModal = null}>×</button>
            </div>
            <div style="padding: 14px; font-size: 11px;">
              {#if addTablesLoading && addTablesRemote.length === 0}
                <div style="color: var(--pw-muted);">Fetching remote tables…</div>
              {:else if addTablesRemote.length === 0}
                <div style="color: var(--pw-muted);">No additional tables on the remote DB. All tables already synced.</div>
              {:else}
                {@const _filtered = addTablesRemote.filter(t => t.toLowerCase().includes(addTablesFilter.toLowerCase()))}
                {@const _allVisiblePicked = _filtered.length > 0 && _filtered.every(t => addTablesPicked.includes(t))}
                <div style="margin-bottom: 8px; color: var(--pw-muted);">{addTablesRemote.length} unsynced table{addTablesRemote.length === 1 ? '' : 's'} on remote:</div>
                <div style="display: flex; align-items: center; gap: 6px; margin-bottom: 8px;">
                  <span style="color: var(--pw-success);">$</span>
                  <input
                    type="text"
                    placeholder="filter tables…"
                    bind:value={addTablesFilter}
                    style="flex: 1; background: var(--pw-ink); border: 1px solid var(--pw-muted); color: var(--pw-success); font-family: ui-monospace, monospace; font-size: 11px; padding: 5px 7px; outline: none;"
                  />
                  <span style="font-size: 10px; color: var(--pw-success); border: 1px solid var(--pw-success); padding: 2px 6px; white-space: nowrap;">{addTablesPicked.length} of {addTablesRemote.length} selected</span>
                </div>
                <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px; font-size: 10px; color: var(--pw-muted);">
                  <span>showing {_filtered.length} of {addTablesRemote.length}</span>
                  <button
                    type="button"
                    style="background: none; border: 1px solid var(--pw-muted); color: var(--pw-success); font-family: ui-monospace, monospace; font-size: 10px; padding: 3px 8px; cursor: pointer;"
                    disabled={_filtered.length === 0}
                    onclick={() => {
                      if (_allVisiblePicked) {
                        const visible = new Set(_filtered);
                        addTablesPicked = addTablesPicked.filter(x => !visible.has(x));
                      } else {
                        const merged = new Set([...addTablesPicked, ..._filtered]);
                        addTablesPicked = [...merged];
                      }
                    }}
                  >{_allVisiblePicked ? 'DESELECT ALL VISIBLE' : 'SELECT ALL VISIBLE'}</button>
                </div>
                <div style="max-height: 280px; overflow-y: auto; border: 1px solid var(--pw-muted); padding: 8px;">
                  {#if _filtered.length === 0}
                    <div style="color: var(--pw-muted); font-style: italic;">no tables match '{addTablesFilter}'</div>
                  {:else}
                    {#each _filtered as t}
                      <label style="display: flex; align-items: center; gap: 6px; padding: 3px 0; cursor: pointer;">
                        <input type="checkbox" checked={addTablesPicked.includes(t)} onchange={(e) => { if ((e.target as HTMLInputElement).checked) addTablesPicked = [...addTablesPicked, t]; else addTablesPicked = addTablesPicked.filter(x => x !== t); }} />
                        <span>{t}</span>
                      </label>
                    {/each}
                  {/if}
                </div>
                <div style="display: flex; gap: 8px; margin-top: 12px;">
                  <button class="send-btn" style="flex: 1; padding: 8px; font-size: 10px;" disabled={addTablesLoading || addTablesPicked.length === 0} onclick={commitAddTables}>{addTablesLoading ? '● SYNCING…' : `ADD + SYNC (${addTablesPicked.length})`}</button>
                  <button class="feedback-btn" style="flex: 1; padding: 8px; font-size: 10px;" onclick={() => addTablesModal = null}>Cancel</button>
                </div>
              {/if}
            </div>
          </div>
        </div>
      {/if}

      <!-- SharePoint setup-needed modal -->
      {#if spSetupModal}
        <!-- svelte-ignore a11y_no_static_element_interactions -->
        <!-- svelte-ignore a11y_click_events_have_key_events -->
        <div style="position: fixed; inset: 0; background: rgba(0,0,0,0.55); z-index: 200; display: flex; align-items: center; justify-content: center;" onclick={(e) => { if (e.target === e.currentTarget) spSetupModal = false; }}>
          <div class="ink-border stamp-shadow" style="background: var(--pw-surface); width: 460px;">
            <div class="dark-title-bar" style="padding: 10px 14px; font-size: 11px; display: flex; justify-content: space-between; align-items: center;">
              <span>SHAREPOINT — SETUP NEEDED</span>
              <button style="background: none; border: none; color: var(--pw-surface); cursor: pointer; font-size: 13px;" onclick={() => spSetupModal = false}>×</button>
            </div>
            <div style="padding: 16px; font-size: 11px; line-height: 1.6;">
              <div style="color: var(--pw-error); font-weight: 900; margin-bottom: 8px;">Microsoft Entra ID credentials are not configured.</div>
              <div style="margin-bottom: 10px;">A super-admin must register an Azure App and set these environment variables on the server:</div>
              <div style="font-family: monospace; background: var(--pw-surface); padding: 8px 10px; border: 1px solid var(--pw-muted); margin-bottom: 12px; font-size: 10px;">
                MS_CLIENT_ID=...<br/>
                MS_CLIENT_SECRET=...<br/>
                MS_TENANT_ID=...
              </div>
              <div style="margin-bottom: 12px;">After setting them, configure the connector from <strong>Command Center → INTEGRATIONS</strong>.</div>
              <div style="display: flex; gap: 8px;">
                <button class="feedback-btn" style="flex: 1; padding: 8px; font-size: 10px;" onclick={() => spSetupModal = false}>Close</button>
                <a href="/ui/command-center?tab=integrations" class="send-btn" style="flex: 1; padding: 8px; font-size: 10px; text-align: center; text-decoration: none; display: inline-block;">OPEN COMMAND CENTER</a>
              </div>
            </div>
          </div>
        </div>
      {/if}

      <!-- DB connector modal -->
      {#if connectorModal}
        <!-- svelte-ignore a11y_no_static_element_interactions -->
        <!-- svelte-ignore a11y_click_events_have_key_events -->
        <div style="position: fixed; inset: 0; background: rgba(0,0,0,0.55); z-index: 200; display: flex; align-items: center; justify-content: center;" onclick={(e) => { if (e.target === e.currentTarget) connectorModal = ''; }}>
          <div class="ink-border stamp-shadow" style="background: var(--pw-surface); width: 460px; max-height: 92vh; overflow-y: auto;">
            <div class="dark-title-bar" style="padding: 10px 14px; font-size: 11px; display: flex; justify-content: space-between; align-items: center;">
              <span>CONNECT {connectorModal === 'postgres' ? 'POSTGRESQL' : connectorModal === 'mysql' ? 'MYSQL' : 'MICROSOFT FABRIC'}</span>
              <button style="background: none; border: none; color: var(--pw-surface); cursor: pointer; font-size: 13px;" onclick={() => connectorModal = ''}>×</button>
            </div>
            <div style="padding: 16px; display: flex; flex-direction: column; gap: 10px; font-size: 11px;">
              {#if dbStep === 'form' || dbStep === 'idle'}
                <!-- honeypot to absorb browser autofill -->
                <input type="text" name="username" autocomplete="username" style="display: none;" tabindex="-1" aria-hidden="true" />
                <input type="password" name="password" autocomplete="current-password" style="display: none;" tabindex="-1" aria-hidden="true" />
                <label>Host
                  <input type="text" bind:value={dbHost} name="db_host_{connectorModal}" autocomplete="off" data-lpignore="true" data-1p-ignore data-form-type="other" placeholder={connectorModal === 'fabric' ? 'xxx.datawarehouse.fabric.microsoft.com' : 'localhost'} style="width: 100%; padding: 6px; border: 2px solid var(--pw-ink); background: var(--pw-surface); margin-top: 4px;" />
                </label>
                <div style="display: flex; gap: 8px;">
                  <label style="flex: 1;">Port
                    <input type="text" bind:value={dbPort} name="db_port_{connectorModal}" autocomplete="off" data-lpignore="true" data-1p-ignore style="width: 100%; padding: 6px; border: 2px solid var(--pw-ink); background: var(--pw-surface); margin-top: 4px;" />
                  </label>
                  <label style="flex: 2;">Database
                    <input type="text" bind:value={dbName} name="db_name_{connectorModal}" autocomplete="off" data-lpignore="true" data-1p-ignore style="width: 100%; padding: 6px; border: 2px solid var(--pw-ink); background: var(--pw-surface); margin-top: 4px;" />
                  </label>
                </div>
                <label>Username
                  <input type="text" bind:value={dbUser} name="db_user_{connectorModal}" autocomplete="off" data-lpignore="true" data-1p-ignore style="width: 100%; padding: 6px; border: 2px solid var(--pw-ink); background: var(--pw-surface); margin-top: 4px;" />
                </label>
                <label>Password
                  <input type="text" bind:value={dbPass} name="db_pass_{connectorModal}" autocomplete="off" data-lpignore="true" data-1p-ignore style="width: 100%; padding: 6px; border: 2px solid var(--pw-ink); background: var(--pw-surface); margin-top: 4px; font-family: monospace; -webkit-text-security: disc; text-security: disc;" />
                </label>
                <div style="display: flex; gap: 8px; margin-top: 6px;">
                  <button class="send-btn" style="flex: 1; padding: 8px; font-size: 10px;" disabled={dbTesting || !dbHost || !dbUser} onclick={dbTestConnection}>{dbTesting ? '● TESTING…' : 'TEST + LIST TABLES'}</button>
                  <button class="feedback-btn" style="flex: 1; padding: 8px; font-size: 10px;" onclick={() => connectorModal = ''}>Cancel</button>
                </div>
                {#if dbTestResult?.error}
                  <div style="font-size: 10px; color: var(--pw-error);">{dbTestResult.error}</div>
                {/if}
              {/if}
              {#if dbStep === 'tables' && dbRemoteTables.length > 0}
                <div style="font-size: 10px; color: var(--pw-muted);">Pick tables to sync:</div>
                <div style="max-height: 240px; overflow-y: auto; border: 1px solid var(--pw-muted); padding: 6px;">
                  {#each dbRemoteTables as t}
                    <label style="display: flex; align-items: center; gap: 6px; padding: 3px 0; font-size: 10px; cursor: pointer;">
                      <input type="checkbox" checked={dbSelectedTables.includes(t.name || t)} onchange={(e) => { const v = t.name || t; if ((e.target as HTMLInputElement).checked) dbSelectedTables = [...dbSelectedTables, v]; else dbSelectedTables = dbSelectedTables.filter((x) => x !== v); }} />
                      <span>{t.name || t}{t.row_count !== undefined ? ` · ${t.row_count} rows` : ''}</span>
                    </label>
                  {/each}
                </div>
                <div style="display: flex; gap: 8px;">
                  <button class="send-btn" style="flex: 1; padding: 8px; font-size: 10px;" disabled={dbLoading || dbSyncing || dbSelectedTables.length === 0} onclick={async () => { const sid = await dbConnect(); if (sid) { await dbSync(sid); } await loadDetail(); connectorModal = ''; }}>{dbLoading ? '● CONNECTING…' : dbSyncing ? '● SYNCING…' : `CONNECT + SYNC (${dbSelectedTables.length})`}</button>
                  <button class="feedback-btn" style="flex: 1; padding: 8px; font-size: 10px;" onclick={() => { dbStep = 'form'; }}>BACK</button>
                </div>
              {/if}
            </div>
          </div>
        </div>
      {/if}
    {/if}

    <!-- Upload progress (shows after file selected) -->
    {#if showUpload && (selectedFile || selectedFiles.length > 0)}
      <div class="ink-border" style="padding: 12px 16px; margin-bottom: 16px; background: var(--pw-surface);">
        <div class="flex items-center justify-between mb-2">
          {#if selectedFiles.length > 1}
            <div>
              <span style="font-weight: 900; font-size: 11px;">{selectedFiles.length} files selected</span>
              <span style="font-size: 10px; color: var(--pw-muted); margin-left: 6px;">({(selectedFiles.reduce((s, f) => s + f.size, 0) / 1024).toFixed(1)} KB)</span>
            </div>
          {:else if selectedFile}
            <div class="flex items-center gap-2">
              <span style="font-weight: 900; font-size: 11px;">{selectedFile.name}</span>
              <span style="font-size: 11px; font-weight: 900; padding: 1px 6px; background: {uploadFileType === 'data' ? 'var(--pw-accent)' : uploadFileType === 'sql_patterns' ? 'var(--pw-accent-ink)' : '#cc7a00'}; color: white; text-transform: uppercase;">{uploadFileType === 'data' ? 'DATA' : uploadFileType === 'sql_patterns' ? 'SQL' : 'DOC'}</span>
              <span style="font-size: 10px; color: var(--pw-muted);">({(selectedFile.size / 1024).toFixed(1)} KB)</span>
            </div>
          {/if}
          <button onclick={() => { showUpload = false; selectedFile = null; selectedFiles = []; uploadSteps = []; uploadResult = null; uploadError = ''; }} style="background: none; border: none; cursor: pointer; font-size: 13px; color: var(--pw-muted);">&times;</button>
        </div>

        {#if selectedFile || selectedFiles.length > 0}
          {#if uploadFileType === 'data' && selectedFiles.length <= 1}
            <input type="text" bind:value={tableName} placeholder="Table name (auto-generated)" style="width: 100%; border: 1px solid var(--pw-bg-alt); padding: 5px 10px; font-family: var(--pw-font-body); font-size: 11px; background: var(--pw-surface); margin-bottom: 8px;" />
          {/if}

          {#if uploadMatch}
            <div class="ink-border" style="margin-top: 10px; padding: 8px 12px; background: #fff4d4; border-color: #cc7a00;">
              <div style="font-size: 10px; font-weight: 900; text-transform: uppercase; color: #cc7a00; margin-bottom: 4px;">TABLE MATCH FOUND</div>
              <div style="font-size: 11px;">Table <strong>{uploadMatch.table}</strong> exists ({uploadMatch.overlap_pct}% overlap, {uploadMatch.existing_rows} rows)</div>
              <div style="display: flex; gap: 6px; margin-top: 8px;">
                <button class="feedback-btn" class:send-btn={uploadAction === 'append'} onclick={() => uploadAction = 'append'} style="font-size: 11px; padding: 3px 10px; font-weight: 900;">APPEND</button>
                <button class="feedback-btn" class:send-btn={uploadAction === 'upsert'} onclick={() => uploadAction = 'upsert'} style="font-size: 11px; padding: 3px 10px; font-weight: 900;">UPSERT</button>
                <button class="feedback-btn" class:send-btn={uploadAction === 'replace'} onclick={() => uploadAction = 'replace'} style="font-size: 11px; padding: 3px 10px; font-weight: 900;">REPLACE</button>
              </div>
            </div>
          {/if}

          {#if !uploadResult && uploadResults.length === 0}
            <button class="send-btn" onclick={doUpload} disabled={uploading} style="margin-top: 10px; padding: 8px 14px; font-size: 11px; width: 100%;">{uploading ? 'UPLOADING...' : selectedFiles.length > 1 ? `▶ UPLOAD ${selectedFiles.length} FILES` : '▶ UPLOAD'}</button>
          {/if}
        {/if}

        {#if uploadFileProgress.length > 0 || uploading}
          {#if true}
            {@const done = uploadFileProgress.filter(p => p.status === 'done').length}
            {@const errors = uploadFileProgress.filter(p => p.status === 'error').length}
            {@const total = uploadFileProgress.length || 1}
            {@const pct = Math.round(((done + errors) / total) * 100)}
          <div style="margin-top: 10px; padding: 10px; background: var(--pw-bg-alt); border-left: 3px solid var(--pw-accent);">
            <div style="margin-bottom: 8px;">
              <div style="display: flex; justify-content: space-between; font-size: 10px; font-weight: 900; margin-bottom: 3px;">
                <span>{uploading ? `Processing ${done + errors + 1}/${total}` : `${done} of ${total} completed`}</span>
                <span>{uploading ? `${pct}%` : (errors > 0 ? `${done} ok · ${errors} failed` : '100%')}</span>
              </div>
              <div style="height: 6px; background: var(--pw-surface); border-radius: 0; overflow: hidden;">
                {#if uploading && pct === 0}
                  <div style="height: 100%; width: 100%; background: linear-gradient(90deg, transparent 0%, var(--pw-accent) 50%, transparent 100%); animation: shimmer 1.5s infinite;"></div>
                {:else}
                  <div style="height: 100%; width: {pct}%; background: var(--pw-accent); transition: width 0.3s;"></div>
                {/if}
              </div>
            </div>
            <!-- Live Agent Cards -->
            {#if uploading && Object.keys(liveAgents).length > 0}
              <div style="display: flex; gap: 8px; margin-bottom: 10px; flex-wrap: wrap;">
                {#each ['Conductor', 'Scanner', 'Parser', 'Vision', 'Inspector', 'Engineer'] as agentName}
                  {#if liveAgents[agentName]}
                    {@const status = liveAgents[agentName]}
                    {@const lastStep = liveSteps.filter(s => s.agent === agentName).at(-1)}
                    <div style="flex: 1; min-width: 100px; padding: 6px 8px; border-radius: 0; border: 1px solid {status === 'active' ? 'var(--pw-accent)' : 'var(--pw-surface)'}; background: {status === 'active' ? 'rgba(0,255,0,0.05)' : 'var(--pw-bg-alt)'};">
                      <div style="display: flex; align-items: center; gap: 4px; margin-bottom: 2px;">
                        <span style="font-size: 10px; {status === 'active' ? 'animation: pulse 1s infinite;' : ''}">{status === 'done' ? '' : status === 'active' ? '●' : '○'}</span>
                        <span style="font-size: 10px; font-weight: 900; color: {status === 'active' ? 'var(--pw-accent)' : 'var(--pw-muted)'};">{agentName}</span>
                      </div>
                      {#if lastStep}
                        <div style="font-size: 11px; color: var(--pw-muted); overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="{lastStep.detail}">{lastStep.detail?.substring(0, 40)}</div>
                      {/if}
                    </div>
                  {/if}
                {/each}
              </div>
            {/if}

            <!-- Live processing steps -->
            {#if uploading && liveSteps.length > 0}
              <div style="margin-bottom: 8px; padding: 6px 8px; background: rgba(0,0,0,0.15); border-radius: 0; max-height: 120px; overflow-y: auto;">
                {#each liveSteps as ls}
                  <div style="font-size: 11px; display: flex; gap: 6px; padding: 1px 0; color: var(--pw-muted);">
                    <span style="flex-shrink: 0; width: 10px; color: {ls.detail?.includes('done') || ls.detail?.includes('') ? 'var(--pw-accent)' : '#cc7a00'};">{ls.detail?.includes('done') || ls.detail?.includes('') ? '' : '●'}</span>
                    <span style="flex-shrink: 0; width: 55px; font-weight: 700; color: var(--pw-accent); opacity: 0.7;">{ls.agent}</span>
                    <span style="flex: 1; opacity: 0.8;">{ls.step} — {ls.detail}</span>
                  </div>
                {/each}
              </div>
            {/if}

            <!-- Per-file list -->
            <div style="max-height: 250px; overflow-y: auto;">
              {#each uploadFileProgress as fp, idx}
                <div style="font-size: 11px; padding: 2px 0; display: flex; align-items: center; gap: 6px;">
                  {#if fp.status === 'done'}
                    <span style="color: var(--pw-accent); flex-shrink: 0;"><Icon name="check" size={14} /></span>
                  {:else if fp.status === 'uploading'}
                    <span style="color: #cc7a00; flex-shrink: 0; animation: pulse 1s infinite;">●</span>
                  {:else if fp.status === 'error'}
                    <span style="color: var(--pw-error); flex-shrink: 0;"><Icon name="x" size={14} /></span>
                  {:else}
                    <span style="color: var(--pw-muted); flex-shrink: 0;">○</span>
                  {/if}
                  <span style="font-size: 11px; color: var(--pw-muted); flex-shrink: 0; width: 24px;">{idx + 1}.</span>
                  <span style="flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; {fp.status === 'uploading' ? 'font-weight: 700;' : ''}">{fp.name}</span>
                  {#if fp.status === 'done'}
                    {@const r = uploadResults.find(r => r.file === fp.name)}
                    {#if r?.detail}
                      <span style="font-size: 11px; color: var(--pw-accent); flex-shrink: 0;">{r.detail}</span>
                    {/if}
                  {:else if fp.status === 'uploading'}
                    <span style="font-size: 11px; color: #cc7a00; flex-shrink: 0;">processing...</span>
                  {/if}
                </div>
                <!-- Agent processing steps for completed files -->
                {#if fp.status === 'done'}
                  {@const fileResult = uploadResults.find(r => r.file === fp.name)}
                  {#if fileResult?.processing_steps?.length}
                    <div style="margin-left: 36px; margin-bottom: 6px; padding: 6px 8px; background: rgba(0,255,0,0.03); border-left: 2px solid var(--pw-surface);">
                      {#if fileResult.agents_used?.length}
                        <div style="font-size: 11px; color: var(--pw-muted); margin-bottom: 4px; font-weight: 700;">
                          {fileResult.agents_used.length} agents: {fileResult.agents_used.join(' → ')}
                        </div>
                      {/if}
                      {#each fileResult.processing_steps as step}
                        <div style="font-size: 11px; display: flex; gap: 6px; padding: 1px 0; color: {step.status === 'error' ? 'var(--pw-error)' : step.status === 'warn' ? '#cc7a00' : 'var(--pw-muted)'};">
                          <span style="flex-shrink: 0; width: 10px;">{step.status === 'done' ? '' : step.status === 'warn' ? '' : step.status === 'error' ? '' : '○'}</span>
                          <span style="flex-shrink: 0; width: 60px; font-weight: 700; color: var(--pw-accent); opacity: 0.7;">{step.agent}</span>
                          <span style="flex-shrink: 0; width: 120px;">{step.step}</span>
                          <span style="flex: 1; opacity: 0.6;">{step.detail}</span>
                        </div>
                      {/each}
                    </div>
                  {/if}
                {/if}
              {/each}
            </div>
            <!-- Summary when done -->
            {#if !uploading && uploadResults.length > 0}
              {#if true}
                {@const totalTables = uploadResults.reduce((s, r) => s + (r.tables_created || (r.table_name ? 1 : 0) || r.tables_saved || 0), 0)}
                {@const totalRows = uploadResults.reduce((s, r) => s + (r.total_rows || r.rows || 0), 0)}
                {@const totalIndexed = uploadResults.filter(r => r.indexed).length}
                {@const hasEngineer = uploadResults.some(r => r.engineer)}
                <div style="margin-top: 8px; padding-top: 8px; border-top: 1px solid var(--pw-surface); font-size: 11px; font-weight: 900; color: var(--pw-accent);">
                  <Icon name="check" size={14} /> {uploadResults.length} files uploaded
                  {#if totalTables > 0} · {totalTables} tables{/if}
                  {#if totalRows > 0} · {totalRows} rows{/if}
                  {#if totalIndexed > 0} · {totalIndexed} docs indexed{/if}
                </div>
                {#if hasEngineer}
                  <div style="font-size: 10px; color: #cc7a00; margin-top: 4px;"><Icon name="settings" size={14} /> Engineer running — creating views and discovering relationships...</div>
                {/if}
              {/if}
            {/if}
            {#if uploadError}<div style="margin-top: 6px; font-size: 11px; color: var(--pw-error);">{uploadError}</div>{/if}
          </div>
          {/if}
        {/if}
      </div>
    {/if}

    <!-- Unified files table (staged + live in one) -->
    {#if docs.length > 0 || (detail?.tables?.length || 0) > 0 || (stageBatchId && stageFilesMeta.length > 0)}
      <div class="ds-section-head" style="margin-top: 24px;">
        <h3 class="ds-section-title">Files <span class="ds-count">({_totalDocs + _totalTables + (stageBatchId ? stageFilesMeta.length : 0)})</span></h3>
        <div class="ds-chip-row">
          {#if stageBatchId && stageFilesMeta.length > 0}
            <span class="cp-hdr-meta" style="font-size:11px;">batch {stageBatchId}</span>
            <button class="ds-btn ds-btn-sm ds-btn-primary" disabled={stageBusy} onclick={() => stagePromote(true, true)} title="Load all files + start training (bypasses quality gate)">{stageBusy ? 'Working…' : 'Train'}</button>
            <button class="ds-btn ds-btn-sm ds-btn-link-danger" disabled={stageBusy} onclick={stageReject}>Reject batch</button>
          {/if}
          <button class="ds-btn ds-btn-sm" onclick={() => { loadResourceRegistry?.(); loadKnowledgeFiles?.(); loadRecentActivity?.(); }} title="Refresh">
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="23 4 23 10 17 10"/><polyline points="1 20 1 14 7 14"/><path d="M3.51 9a9 9 0 0 1 14.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0 0 20.49 15"/></svg>
            Refresh
          </button>
          {#if canEdit && (detail?.tables?.length || 0) > 0}
            <button class="ds-btn ds-btn-sm ds-btn-primary" onclick={() => { openQualityReview(); }} disabled={!!trainingTable || isTraining}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/></svg>
              Train all
            </button>
          {/if}
        </div>
      </div>

      <div class="ds-table-wrap">
        <table class="ds-table">
          <thead>
            <tr>
              <th style="width: 28px;"></th>
              <th>Name</th>
              <th style="width: 60px;">Type</th>
              <th style="width: 80px;">Size</th>
              <th style="width: 90px;">Rows</th>
              <th style="width: 70px;">Cols</th>
              <th style="width: 60px;">Q&amp;A</th>
              <th style="width: 110px;">Health</th>
              <th style="width: 130px;">Status</th>
              <th style="width: 60px;"></th>
            </tr>
          </thead>
          <tbody>
            {#if stageBatchId && Array.isArray(stageFilesMeta)}
              {#each stageFilesMeta as f}
                {@const verdictColor = f.verdict==='exact'?'#1f8f4e':f.verdict==='drift'?'#c43322':'#3a8dff'}
                {@const isQuar = f.status==='quarantine'}
                <tr style="background: rgba(58,141,255,0.04);">
                  <td></td>
                  <td class="ds-name" title="{f.filename} → {f.target_table || f.dataset || '—'}">
                    {f.filename}
                    <span style="margin-left:8px; padding:1px 6px; font-weight:700; font-size:10.5px; background:{verdictColor}22; color:{verdictColor};">{(f.verdict||'new').toUpperCase()}</span>
                  </td>
                  <td><span class="ds-type-chip">stage</span></td>
                  <td class="ds-num">—</td>
                  <td class="ds-num">{f.rows ?? 0}</td>
                  <td class="ds-num">—</td>
                  <td class="ds-num">—</td>
                  <td>
                    <span class="cp-hdr-meta" style="font-size:10.5px;">→ {f.target_table || f.dataset || '—'}</span>
                  </td>
                  <td>
                    <span class="ds-status">
                      <span class="ds-status-dot" style="background:{isQuar?'#c43322':'#cc7a00'};"></span>
                      {isQuar ? 'QUARANTINE' : 'STAGED'}
                    </span>
                    {#if f.reason}<div class="cp-hdr-meta" style="font-size:10px;">{f.reason}</div>{/if}
                  </td>
                  <td>
                    {#if isQuar && f.verdict==='drift'}
                      <button class="ds-btn-link" disabled={stageBusy} onclick={() => stageResolveDrift(f.filename)} title="Accept drift">Accept</button>
                    {:else if isQuar}
                      <button class="ds-btn-link" disabled={stageBusy} onclick={() => stageRecheckFile(f.filename)} title="Re-check">Re-check</button>
                    {/if}
                  </td>
                </tr>
              {/each}
            {/if}
            {#each docs as d}
              <tr>
                <td></td>
                <td class="ds-name" title="{d.name}">{d.name}</td>
                <td><span class="ds-type-chip">{d.type.replace('.','')}</span></td>
                <td class="ds-num">{d.file_size ? (d.file_size / 1024 / 1024).toFixed(1) + ' MB' : (d.size / 1024).toFixed(1) + ' KB'}</td>
                <td class="ds-num">—</td>
                <td class="ds-num">—</td>
                <td class="ds-num">—</td>
                <td>
                  <div class="ds-health">
                    <div class="ds-health-track"><div class="ds-health-fill ds-health-good" style="width: 100%;"></div></div>
                    <span class="ds-health-pct">100%</span>
                  </div>
                </td>
                <td><span class="ds-status"><span class="ds-status-dot ds-status-dot-good"></span>Indexed</span></td>
                <td>
                  {#if canEdit}
                    <button class="ds-btn-link ds-btn-link-danger" onclick={() => deleteDoc(d.name)} title="Delete">Delete</button>
                  {/if}
                </td>
              </tr>
            {/each}
            {#each (detail?.tables || []).filter((t: any) => showCastedTables || !_isCasted(t.name)) as t}
              {@const isTrained = knowledgeFiles.some((f: any) => f.type === 'tables' && f.name === t.name + '.json')}
              {@const qaCount = (training?.training_qa || []).filter((q: any) => q.source_table === t.name).length}
              {@const health = t.health || (isTrained ? (qaCount > 0 ? 100 : 60) : 0)}
              {@const isExpanded = expandedTables[t.name] ?? false}
              {@const isTraining = trainingTable === t.name}
              {@const meta = tableMetaCache[t.name]}
              {@const inspData = tableInspectCache[t.name]}
              {@const dqCount = dqData?.by_table?.[t.name] || 0}
              <tr class="ds-row-clickable" onclick={() => toggleTableExpand(t.name)}>
                <td class="ds-toggle">
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="transform: rotate({isExpanded ? 90 : 0}deg); transition: transform 120ms ease;"><polyline points="9 18 15 12 9 6"/></svg>
                </td>
                <td class="ds-name" title="{t.name}">
                  {t.name}
                  {#if codexEnriched.has(t.name) || meta?.pipeline_logic?.code_enriched === true}
                    <span
                      title="Enriched from source pipeline code (view DDL / table logic)"
                      style="margin-left: 8px; padding: 1px 6px; border: 1px solid #2f7d4f; color: #2f7d4f; background: transparent; font-size: 11px; font-weight: 800; letter-spacing: 0.04em; vertical-align: middle;"
                    >CODE</span>
                  {/if}
                  {#if dqCount > 0}
                    <button
                      onclick={(e) => { e.stopPropagation(); openDataQualityForTable(t.name); }}
                      title="Open Data Quality filtered by this table"
                      style="margin-left: 8px; padding: 1px 6px; border: 1px solid #cc7a00; color: #cc7a00; background: transparent; font-size: 11px; font-weight: 800; cursor: pointer; letter-spacing: 0.04em; vertical-align: middle;"
                    ><Icon name="hospital" size={14} /> {dqCount} issue{dqCount === 1 ? '' : 's'}</button>
                  {/if}
                </td>
                <td><span class="ds-type-chip ds-type-tbl">tbl</span></td>
                <td class="ds-num">—</td>
                <td class="ds-num">{(t.rows || 0).toLocaleString()}</td>
                <td class="ds-num">{t.columns || 0}</td>
                <td class="ds-num">{qaCount}</td>
                <td>
                  <div class="ds-health">
                    <div class="ds-health-track">
                      <div class="ds-health-fill {health >= 67 ? 'ds-health-good' : health >= 34 ? 'ds-health-warn' : 'ds-health-low'}" style="width: {Math.max(health, 0)}%;"></div>
                    </div>
                    <span class="ds-health-pct">{health}%</span>
                  </div>
                </td>
                <td>
                  <span class="ds-status">
                    <span class="ds-status-dot {isTraining ? 'ds-status-dot-warn' : isTrained ? 'ds-status-dot-good' : 'ds-status-dot-muted'}"></span>
                    {isTraining ? 'training…' : isTrained ? 'trained' : 'untrained'}
                  </span>
                </td>
                <td onclick={(e) => e.stopPropagation()}>
                  {#if canEdit}
                    <button class="ds-btn-link ds-btn-link-danger" onclick={() => deleteTable(t.name)} title="Delete table">Delete</button>
                  {/if}
                </td>
              </tr>
              {#if isExpanded}
                <tr class="ds-expand-row">
                  <td></td>
                  <td colspan="9">
                    <div class="ds-expand">
                      {#if t.source_file || t.description}
                        <div class="ds-expand-source">
                          {#if t.source_file}<span><strong>Source:</strong> {t.source_file}{#if t.source_detail} <span class="ds-expand-source-detail">{t.source_detail}</span>{/if}</span>{/if}
                          {#if t.description}<span class="ds-expand-source-desc">— {t.description}</span>{/if}
                        </div>
                      {/if}

                      <div class="ds-expand-actions">
                        {#if canEdit}
                          <button class="ds-btn ds-btn-sm ds-btn-primary" onclick={() => trainTable(t.name)} disabled={!!trainingTable}>
                            {isTrained ? 'Retrain' : 'Train'}
                          </button>
                        {/if}
                        <button class="ds-btn ds-btn-sm" onclick={() => openInspect(t)}>Full inspect</button>
                        <button class="ds-btn ds-btn-sm" onclick={async () => {
                          const r = await fetch(`/api/tables/${t.name}/download?format=csv&project=${slug}`, { headers: _h() });
                          if (r.ok) { const blob = await r.blob(); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = `${t.name}.csv`; a.click(); URL.revokeObjectURL(url); }
                        }}>Download CSV</button>
                        <button class="ds-btn ds-btn-sm" onclick={async () => {
                          const r = await fetch(`/api/tables/${t.name}/download?format=excel&project=${slug}`, { headers: _h() });
                          if (r.ok) { const blob = await r.blob(); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = `${t.name}.xlsx`; a.click(); URL.revokeObjectURL(url); }
                        }}>Download Excel</button>
                        {#if canEdit}
                          <button class="ds-btn ds-btn-sm ds-btn-danger-ghost" onclick={() => deleteTable(t.name)}>Delete</button>
                        {/if}
                      </div>

                      <!-- ═══ EXTRACTION PLAN (P4) ═══ -->
                      {#if true}
                      {@const _plan = extractionPlans[t.name]}
                      {@const _edit = extractionPlanEdits[t.name] || { header_row: '', skip_rows: '', busy: false, saved: false }}
                      <div class="ds-card" style="margin-top: 14px; padding: 12px;">
                        <div style="display:flex; align-items:center; gap:10px; margin-bottom:10px;">
                          <strong style="font-size:11.5px; letter-spacing:0.06em; text-transform:uppercase;">Extraction plan</strong>
                          {#if _plan}
                            {@const _strat = String(_plan.strategy || '')}
                            {@const _color = _strat === 'llm-rescued' ? '#cc7a00' : _strat === 'rules-split' ? '#2f7d4f' : _strat === 'ai-unpivot' ? '#7a3fbf' : '#3a5f8a'}
                            <span style="padding:1px 8px; border:1px solid {_color}; color:{_color}; font-size:11px; font-weight:800; letter-spacing:0.04em;">{_strat || 'unknown'}</span>
                            {#if _plan.llm_rescued}
                              <span style="padding:1px 8px; border:1px solid #cc7a00; color:#cc7a00; font-size:11px; font-weight:800;">LLM rescued: yes</span>
                            {/if}
                          {/if}
                        </div>

                        {#if !_plan}
                          <div style="font-size:12px; color:var(--pw-muted);">No extraction plan recorded for this table.</div>
                        {:else}
                          <div style="display:grid; grid-template-columns: 1fr 1fr; gap:12px; margin-bottom:10px;">
                            <label style="display:flex; flex-direction:column; gap:4px;">
                              <span style="font-size:11px; text-transform:uppercase; letter-spacing:0.04em; color:var(--pw-muted);">Header row</span>
                              <input
                                class="ds-input"
                                type="number"
                                min="0"
                                placeholder={String(_plan.header_row ?? 0)}
                                value={_edit.header_row}
                                oninput={(e) => {
                                  const v = (e.currentTarget as HTMLInputElement).value;
                                  extractionPlanEdits = { ...extractionPlanEdits, [t.name]: { ..._edit, header_row: v, saved: false, err: undefined } };
                                }}
                                disabled={!canEdit || _edit.busy}
                              />
                            </label>
                            <label style="display:flex; flex-direction:column; gap:4px;">
                              <span style="font-size:11px; text-transform:uppercase; letter-spacing:0.04em; color:var(--pw-muted);">Skip rows (comma-separated)</span>
                              <input
                                class="ds-input"
                                type="text"
                                placeholder={(Array.isArray(_plan.skip_rows) && _plan.skip_rows.length ? _plan.skip_rows.join(', ') : 'e.g. 0,1,5')}
                                value={_edit.skip_rows}
                                oninput={(e) => {
                                  const v = (e.currentTarget as HTMLInputElement).value;
                                  extractionPlanEdits = { ...extractionPlanEdits, [t.name]: { ..._edit, skip_rows: v, saved: false, err: undefined } };
                                }}
                                disabled={!canEdit || _edit.busy}
                              />
                            </label>
                          </div>

                          <div style="display:grid; grid-template-columns: repeat(4, 1fr); gap:10px; margin-bottom:10px; font-size:12px;">
                            <div>
                              <div style="color:var(--pw-muted); font-size:10.5px; text-transform:uppercase; letter-spacing:0.04em;">Rows in</div>
                              <div>{_plan.row_count_in ?? '—'}</div>
                            </div>
                            <div>
                              <div style="color:var(--pw-muted); font-size:10.5px; text-transform:uppercase; letter-spacing:0.04em;">Rows out</div>
                              <div>{_plan.row_count_out ?? '—'}</div>
                            </div>
                            <div>
                              <div style="color:var(--pw-muted); font-size:10.5px; text-transform:uppercase; letter-spacing:0.04em;">Sheet</div>
                              <div>{_plan.sheet_name || '—'}</div>
                            </div>
                            <div>
                              <div style="color:var(--pw-muted); font-size:10.5px; text-transform:uppercase; letter-spacing:0.04em;">Source file</div>
                              <div style="overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title={_plan.source_file || ''}>{_plan.source_file || '—'}</div>
                            </div>
                          </div>

                          {#if _plan.rescue_reasoning}
                            <div style="font-size:11.5px; color:var(--pw-muted); margin-bottom:10px; padding:8px; background:var(--pw-bg-alt); border:1px solid var(--pw-border);">
                              <strong>Rescue reasoning:</strong> {_plan.rescue_reasoning}
                            </div>
                          {/if}

                          <div style="display:flex; align-items:center; gap:10px;">
                            {#if canEdit}
                              <button
                                class="ds-btn ds-btn-sm ds-btn-primary"
                                onclick={() => reIngestExtractionPlan(t.name)}
                                disabled={_edit.busy}
                              >
                                {_edit.busy ? 'Re-ingesting…' : 'Re-ingest with overrides'}
                              </button>
                            {/if}
                            {#if _edit.saved}
                              <span style="color:#2f7d4f; font-size:12px; font-weight:600;">✓ Saved</span>
                            {/if}
                            {#if _edit.err}
                              <span style="color:#c0392b; font-size:12px;">{_edit.err}</span>
                            {/if}
                          </div>
                        {/if}
                      </div>
                      {/if}
                    </div>
                  </td>
                </tr>
              {/if}
            {/each}
          </tbody>
        </table>
        <div class="ds-table-foot">
          <span>{_totalTables} tables · {_totalRows.toLocaleString()} rows</span>
        </div>
      </div>

      <!-- ═══ Table details — rich per-table cards ═══ -->
      {#if (detail?.tables?.length || 0) > 0}
        {@const _allOpen = (detail?.tables || []).every((t: any) => tableCardOpen[t.name] ?? true)}
        {@const _filteredTables = (detail?.tables || []).filter((t: any) => {
          if (tableCardFilter === 'all') return true;
          if (tableCardFilter === 'trained') return isTableTrained(t.name);
          if (tableCardFilter === 'untrained') return !isTableTrained(t.name);
          return true;
        })}
        <div class="ds-section-head" style="margin-top: 28px;">
          <h3 class="ds-section-title">Table details <span class="ds-count">({_filteredTables.length})</span></h3>
          <div class="ds-chip-row">
            <select class="dt-filter" bind:value={tableCardFilter} aria-label="Filter tables">
              <option value="all">All tables</option>
              <option value="trained">Trained only</option>
              <option value="untrained">Untrained only</option>
            </select>
            <button class="ds-btn ds-btn-sm" onclick={() => expandAllCards(!_allOpen)}>
              {_allOpen ? 'Collapse all' : 'Expand all'}
            </button>
          </div>
        </div>

        <div class="dt-card-list">
          {#each _filteredTables as t (t.name)}
            {@const _open = tableCardOpen[t.name] ?? true}
            {@const _meta = tableMetaCache[t.name]}
            {@const _insp = tableInspectCache[t.name]}
            {@const _cols = _insp?.columns || _meta?.table_columns || []}
            {@const _sample = _insp?.sample || []}
            {@const _sampleLimit = tableSampleLimit[t.name] ?? 10}
            {@const _qaCount = (training?.training_qa || []).filter((q: any) => q.source_table === t.name).length}
            {@const _health = t.health ?? (isTableTrained(t.name) ? (_qaCount > 0 ? 100 : 60) : 0)}
            {@const _status = tableStatus(t)}
            {@const _rels = (tableRelationships || []).filter((r: any) => r.from_table === t.name || r.to_table === t.name || r.from === t.name || r.to === t.name)}
            {@const _cm = columnMapCache[t.name]}
            {@const _isTraining = trainingTable === t.name}
            <div class="dt-card">
              <!-- 1. Header bar -->
              <!-- svelte-ignore a11y_click_events_have_key_events -->
              <!-- svelte-ignore a11y_no_static_element_interactions -->
              <div class="dt-head" onclick={() => toggleCard(t.name)} role="button" tabindex="0">
                <span class="dt-caret">{_open ? '▾' : '▸'}</span>
                <span class="dt-title">{t.name}</span>
                <span class="dt-pill {_status.cls}"><span class="dt-pill-dot"></span>{_status.label}</span>
                <span class="dt-meta-sep">·</span>
                <span class="dt-meta">{(t.rows || 0).toLocaleString()} rows</span>
                <span class="dt-meta-sep">·</span>
                <span class="dt-meta">{t.columns || _cols.length || 0} cols</span>
                {#if t.size_bytes || t.size}
                  <span class="dt-meta-sep">·</span>
                  <span class="dt-meta">{((t.size_bytes || t.size || 0) / 1024).toFixed(1)} KB</span>
                {/if}
                {#if t.created_at}
                  <span class="dt-meta-sep">·</span>
                  <span class="dt-meta">created {relTime(t.created_at)}</span>
                {/if}
                {#if t.last_trained_at || _meta?.last_trained_at}
                  <span class="dt-meta-sep">·</span>
                  <span class="dt-meta">last trained {relTime(t.last_trained_at || _meta?.last_trained_at)}</span>
                {/if}
                {#if t.source_file || t.source}
                  <span class="dt-meta-sep">·</span>
                  <span class="dt-meta dt-mono" title="{t.source_file || t.source}">{t.source_file || t.source}</span>
                {/if}
                <span class="dt-head-spacer"></span>
                {#if canEdit}
                  <button class="dt-icon-btn dt-icon-danger" title="Delete table" onclick={(e) => { e.stopPropagation(); deleteTable(t.name); }} aria-label="Delete">⊝</button>
                {/if}
              </div>

              {#if _open}
                <div class="dt-body">
                  <!-- 2. Overview -->
                  <div class="dt-section">
                    <div class="dt-section-label">Overview</div>
                    <div class="dt-grid dt-grid-overview">
                      <div class="dt-stat"><span class="dt-stat-k">Purpose</span><span class="dt-stat-v">{_meta?.table_description || _meta?.purpose || t.description || '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Grain</span><span class="dt-stat-v">{_meta?.grain || '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Primary key</span><span class="dt-stat-v dt-mono">{(_meta?.primary_keys || []).join(', ') || _meta?.primary_key || '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Refresh</span><span class="dt-stat-v">{_meta?.refresh_cadence || _meta?.freshness || '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Used by</span><span class="dt-stat-v dt-mono">{(_meta?.downstream_tables || []).join(', ') || '—'}</span></div>
                    </div>
                  </div>

                  <!-- 2.5 Column Map — grouped by dimension / measure(unit) / id / date / text -->
                  {#if _cm?.groups?.length}
                    <div class="dt-section">
                      <div class="dt-section-label">Column Map <span class="dt-section-count">({_cm.total})</span></div>
                      <div style="display:grid; grid-template-columns:repeat(auto-fit,minmax(220px,1fr)); gap:10px; margin-top:6px;">
                        {#each _cm.groups as grp}
                          {@const gmeta = grp.group === 'DIMENSION' ? {ic:'◇', c:'#3a8dff', lbl:'Dimensions'} : grp.group === 'MEASURE' ? {ic:'∑', c:'#1a9c50', lbl:'Measures'} : grp.group === 'IDENTIFIER' ? {ic:'#', c:'#9b6dff', lbl:'Identifiers'} : grp.group === 'DATE' ? {ic:'⏱', c:'#cc7a00', lbl:'Dates'} : {ic:'¶', c:'var(--pw-muted)', lbl:'Text'}}
                          <div style="border:1px solid var(--pw-border); border-radius: 0; padding:8px 10px; background:var(--pw-surface);">
                            <div style="font-size:10px; font-weight:900; letter-spacing:0.06em; text-transform:uppercase; color:{gmeta.c}; margin-bottom:6px;">{gmeta.ic} {gmeta.lbl} ({grp.columns.length})</div>
                            {#each grp.columns as c}
                              {@const uic = c.unit === 'currency' ? '$' : c.unit === 'percentage' ? '%' : c.unit === 'count' ? '#' : c.unit === 'time' ? '⏱' : c.unit === 'physical' ? '▱' : c.unit === 'number' ? '∑' : '◇'}
                              <div style="display:flex; align-items:baseline; gap:6px; font-size:11px; padding:2px 0; line-height:1.5;">
                                <span style="color:{gmeta.c}; width:12px; flex-shrink:0;">{uic}</span>
                                <span class="dt-mono" style="font-weight:700;">{c.name}</span>
                                <span class="dt-muted" style="font-size:10px; margin-left:auto; text-align:right;">
                                  {#if c.unit && c.unit !== 'none' && c.unit !== 'number'}{c.unit} · {/if}{#if grp.group === 'MEASURE' && c.min != null}{Number(c.min).toLocaleString()}–{Number(c.max).toLocaleString()}{:else if grp.group === 'DATE' && c.min_date}{c.min_date} → {c.max_date}{:else if c.unique_count != null}{c.unique_count} values{/if}
                                </span>
                              </div>
                            {/each}
                          </div>
                        {/each}
                      </div>
                    </div>
                  {/if}

                  <!-- 3. Schema -->
                  <div class="dt-section">
                    <div class="dt-section-label">Schema <span class="dt-section-count">({_cols.length})</span></div>
                    {#if _cols.length > 0}
                      <div class="dt-table-wrap">
                        <table class="dt-table">
                          <thead>
                            <tr>
                              <th>Column</th>
                              <th style="width: 100px;">Type</th>
                              <th style="width: 50px;">Null</th>
                              <th style="width: 60px;">Unique</th>
                              <th style="width: 40px;">PK</th>
                              <th style="width: 40px;">FK</th>
                              <th>Sample</th>
                              <th>Description</th>
                            </tr>
                          </thead>
                          <tbody>
                            {#each _cols as col}
                              {@const _metaCol = (_meta?.table_columns || []).find((c: any) => c.name === col.name)}
                              {@const _sampleVal = _sample.length > 0 ? String(_sample[0][col.name] ?? '').slice(0, 30) : ''}
                              <tr>
                                <td class="dt-mono">{col.name}</td>
                                <td class="dt-mono dt-muted">{col.type || _metaCol?.type || '—'}</td>
                                <td class="dt-num">{col.nullable === false ? '' : col.null_pct != null ? `${col.null_pct}%` : '—'}</td>
                                <td class="dt-num">{col.unique_pct != null ? `${col.unique_pct}%` : col.distinct != null ? col.distinct : '—'}</td>
                                <td class="dt-num">{col.is_pk || (_meta?.primary_keys || []).includes(col.name) ? '●' : ''}</td>
                                <td class="dt-num">{col.is_fk ? '●' : ''}</td>
                                <td class="dt-mono dt-muted">{_sampleVal}</td>
                                <td class="dt-muted">{_metaCol?.description || col.description || ''}</td>
                              </tr>
                            {/each}
                          </tbody>
                        </table>
                      </div>
                    {:else if _insp === undefined}
                      <div class="dt-empty">Loading schema…</div>
                    {:else}
                      <div class="dt-empty">No columns available.</div>
                    {/if}
                  </div>

                  <!-- 4. Sample data -->
                  <div class="dt-section">
                    <div class="dt-section-label">
                      Sample data <span class="dt-section-count">(first {Math.min(_sampleLimit, _sample.length)} of {_sample.length} loaded)</span>
                      <span class="dt-section-actions">
                        {#if _sample.length > _sampleLimit}
                          <button class="dt-link" onclick={() => tableSampleLimit = { ...tableSampleLimit, [t.name]: _sampleLimit + 10 }}>load more</button>
                        {/if}
                        <button class="dt-link" onclick={() => downloadTable(t.name, 'csv')}>↓ CSV</button>
                      </span>
                    </div>
                    {#if _sample.length > 0}
                      <div class="dt-table-wrap">
                        <table class="dt-table">
                          <thead>
                            <tr>
                              <th style="width: 28px;">#</th>
                              {#each Object.keys(_sample[0] || {}) as h}
                                <th>{h}</th>
                              {/each}
                            </tr>
                          </thead>
                          <tbody>
                            {#each _sample.slice(0, _sampleLimit) as row, ri}
                              <tr>
                                <td class="dt-num dt-muted">{ri + 1}</td>
                                {#each Object.values(row) as val}
                                  <td class="dt-mono">{val ?? ''}</td>
                                {/each}
                              </tr>
                            {/each}
                          </tbody>
                        </table>
                      </div>
                    {:else if _insp === undefined}
                      <div class="dt-empty">Loading sample…</div>
                    {:else}
                      <div class="dt-empty">No sample rows available.</div>
                    {/if}
                  </div>

                  <!-- 5. Data quality -->
                  <div class="dt-section">
                    <div class="dt-section-label">Data quality</div>
                    <div class="dt-quality">
                      <div class="dt-bar">
                        <div class="dt-bar-fill {_health >= 67 ? 'dt-bar-good' : _health >= 34 ? 'dt-bar-warn' : 'dt-bar-low'}" style="width: {Math.max(_health, 0)}%;"></div>
                      </div>
                      <span class="dt-bar-pct">{_health}%</span>
                    </div>
                    <div class="dt-grid dt-grid-quality">
                      <div class="dt-stat"><span class="dt-stat-k">Nulls</span><span class="dt-stat-v">{_insp?.quality?.nulls ?? _insp?.null_pct ?? '—'}{_insp?.quality?.nulls != null ? '%' : ''}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Duplicates</span><span class="dt-stat-v">{_insp?.quality?.duplicates ?? '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Outliers</span><span class="dt-stat-v">{_insp?.quality?.outliers ?? '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Schema drift</span><span class="dt-stat-v">{_insp?.quality?.drift ?? ((driftAlerts || []).filter((d: any) => d.table_name === t.name).length || '0')}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Issues</span><span class="dt-stat-v">{(_meta?.data_quality_notes || []).length || '0'}</span></div>
                    </div>
                    {#if (_meta?.data_quality_notes || []).length > 0}
                      <ul class="dt-notes">
                        {#each _meta.data_quality_notes as note}
                          <li><Icon name="alert-triangle" size={14} /> {note}</li>
                        {/each}
                      </ul>
                    {/if}
                  </div>

                  <!-- 6. Distributions -->
                  <div class="dt-section">
                    <div class="dt-section-label">Distributions</div>
                    {#if _sample.length > 0 && _cols.length > 0}
                      {@const _catCols = _cols.filter((c: any) => {
                        const tp = String(c.type || '').toLowerCase();
                        return tp.includes('text') || tp.includes('char') || tp.includes('str') || tp.includes('enum') || tp.includes('bool');
                      }).slice(0, 3)}
                      {@const _numCol = _cols.find((c: any) => {
                        const tp = String(c.type || '').toLowerCase();
                        return tp.includes('int') || tp.includes('num') || tp.includes('float') || tp.includes('decimal') || tp.includes('double');
                      })}
                      <div class="dt-grid dt-grid-distros">
                        {#each _catCols as col}
                          {@const bars = distroBars(_sample, col.name, 5)}
                          {#if bars.length > 0}
                            <div class="dt-distro">
                              <div class="dt-distro-label">{col.name}</div>
                              {#each bars as b}
                                <div class="dt-distro-row">
                                  <span class="dt-distro-name" title="{b.label}">{b.label}</span>
                                  <div class="dt-distro-bar"><div class="dt-distro-fill" style="width: {b.pct}%;"></div></div>
                                  <span class="dt-distro-pct">{b.pct}%</span>
                                </div>
                              {/each}
                            </div>
                          {/if}
                        {/each}
                        {#if _numCol}
                          {@const five = fiveNum(_sample, _numCol.name)}
                          {#if five}
                            <div class="dt-distro">
                              <div class="dt-distro-label">{_numCol.name} <span class="dt-muted">(5-num)</span></div>
                              <div class="dt-fivenum">
                                <span><em>min</em> {five.min}</span>
                                <span><em>p25</em> {five.p25}</span>
                                <span><em>p50</em> {five.p50}</span>
                                <span><em>p75</em> {five.p75}</span>
                                <span><em>max</em> {five.max}</span>
                              </div>
                            </div>
                          {/if}
                        {/if}
                      </div>
                    {:else}
                      <div class="dt-empty">No distribution data — train table to populate.</div>
                    {/if}
                  </div>

                  <!-- 7. Relationships -->
                  <div class="dt-section">
                    <div class="dt-section-label">Relationships <span class="dt-section-count">({_rels.length})</span></div>
                    {#if _rels.length > 0}
                      <div class="dt-table-wrap">
                        <table class="dt-table">
                          <thead><tr><th>From</th><th>To</th><th style="width: 100px;">Confidence</th><th style="width: 100px;">Status</th></tr></thead>
                          <tbody>
                            {#each _rels as r}
                              <tr>
                                <td class="dt-mono">{r.from_table || r.from || ''}{r.from_column ? '.' + r.from_column : ''}</td>
                                <td class="dt-mono">{r.to_table || r.to || ''}{r.to_column ? '.' + r.to_column : ''}</td>
                                <td class="dt-num">{r.confidence != null ? `${Math.round(r.confidence * 100)}%` : '—'}</td>
                                <td>{r.verified ? 'verified' : r.status || 'discovered'}</td>
                              </tr>
                            {/each}
                          </tbody>
                        </table>
                      </div>
                    {:else}
                      <div class="dt-empty">No relationships found yet.</div>
                    {/if}
                  </div>

                  <!-- 8. Knowledge / Q&A -->
                  <div class="dt-section">
                    <div class="dt-section-label">Knowledge &amp; Q&amp;A</div>
                    {#if true}
                      {@const _evals = (training?.training_qa || []).filter((q: any) => q.source_table === t.name)}
                      {@const _patterns = (queryPlans || []).filter((p: any) => Array.isArray(p.tables) && p.tables.includes(t.name))}
                      {@const _memories = (insights || []).filter((m: any) => Array.isArray(m.tables) && m.tables.includes(t.name))}
                      <div class="dt-grid dt-grid-quality">
                        <div class="dt-stat"><span class="dt-stat-k">Q&amp;A evals</span><span class="dt-stat-v">{_evals.length}</span></div>
                        <div class="dt-stat"><span class="dt-stat-k">Query patterns</span><span class="dt-stat-v">{_patterns.length}</span></div>
                        <div class="dt-stat"><span class="dt-stat-k">Memories</span><span class="dt-stat-v">{_memories.length}</span></div>
                      </div>
                      {#if _evals.length === 0 && _patterns.length === 0 && _memories.length === 0}
                        <div class="dt-empty dt-empty-cta">
                          No Q&amp;A generated yet — train table to populate.
                          {#if canEdit}
                            <button class="dt-link" onclick={() => trainTable(t.name)} disabled={!!trainingTable}>Run training</button>
                          {/if}
                        </div>
                      {/if}
                    {/if}
                  </div>

                  <!-- 9. Lineage -->
                  <div class="dt-section">
                    <div class="dt-section-label">Lineage</div>
                    <div class="dt-grid dt-grid-overview">
                      <div class="dt-stat"><span class="dt-stat-k">Upstream source</span><span class="dt-stat-v dt-mono">{t.source_file || t.source || _meta?.upstream_source || '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Downstream tables</span><span class="dt-stat-v dt-mono">{(_meta?.downstream_tables || []).join(', ') || '—'}</span></div>
                      <div class="dt-stat"><span class="dt-stat-k">Views</span><span class="dt-stat-v dt-mono">{(_meta?.views || []).join(', ') || '—'}</span></div>
                    </div>
                  </div>

                  <!-- 10. Activity -->
                  <div class="dt-section">
                    <div class="dt-section-label">Activity</div>
                    {#if true}
                      {@const _activity = [
                        ...(t.created_at ? [{ ts: t.created_at, label: 'created' }] : []),
                        ...((t.last_trained_at || _meta?.last_trained_at) ? [{ ts: t.last_trained_at || _meta?.last_trained_at, label: 'trained' }] : []),
                        ...((trainingRuns || []).filter((r: any) => Array.isArray(r.tables) && r.tables.includes(t.name)).slice(0, 3).map((r: any) => ({ ts: r.created_at || r.started_at, label: r.status || 'training run' }))),
                      ].filter(e => e.ts).sort((a, b) => new Date(b.ts).getTime() - new Date(a.ts).getTime()).slice(0, 5)}
                      {#if _activity.length > 0}
                        <ul class="dt-activity">
                          {#each _activity as ev}
                            <li><span class="dt-mono dt-muted">{relTime(ev.ts)}</span> · {ev.label}</li>
                          {/each}
                        </ul>
                      {:else}
                        <div class="dt-empty">No activity recorded yet.</div>
                      {/if}
                    {/if}
                  </div>

                  <!-- 11. Actions footer -->
                  <div class="dt-actions">
                    {#if canEdit}
                      <button class="ds-btn ds-btn-sm ds-btn-primary" onclick={() => trainTable(t.name)} disabled={!!trainingTable}>
                        {_isTraining ? '● Training…' : isTableTrained(t.name) ? '▶ Retrain' : '▶ Train'}
                      </button>
                    {/if}
                    <button class="ds-btn ds-btn-sm" onclick={() => openInspect(t)}>⊙ Full inspect</button>
                    <button class="ds-btn ds-btn-sm" onclick={() => downloadTable(t.name, 'csv')}>↓ CSV</button>
                    <button class="ds-btn ds-btn-sm" onclick={() => downloadTable(t.name, 'excel')}>↓ Excel</button>
                    {#if canEdit}
                      <button class="ds-btn ds-btn-sm ds-btn-danger-ghost" onclick={() => deleteTable(t.name)}>⊝ Delete</button>
                    {/if}
                  </div>
                </div>
              {/if}
            </div>
          {/each}
        </div>
      {/if}
    {:else}
      <div class="ds-empty-card">
        <p>No data yet. Drop files above to begin.</p>
      </div>
    {/if}

    <!-- ═══ STATUS BANDS (below DATA & UPLOAD) ═══ -->
    {#if isTrained}
      {@const _driftTotalCock = Object.values(driftCountsBySource).reduce((a: number, b: number) => a + (b || 0), 0)}
      {@const _todayCostNum = parseFloat(cockpitStats.cost as any) || 0}
      {@const _capNum = Math.max(0.01, costCapInput)}
      {@const _pct = Math.min(100, (_todayCostNum / _capNum) * 100)}

      <!-- ═══ STATUS — 4-card row (Today / Performance / Health / Cost) ═══ -->
      <section class="set-section cp-band">
        <div class="cp-band-head"><Icon name="bar-chart" size={14} /> Status</div>
        <div class="cp-grid-4">
          <div class="cp-card cp-card-blue">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="bar-chart" size={14} /></span> TODAY</div>
            <div class="cp-kv"><span>Chats</span><b>{cockpitStats.chats}</b></div>
            <div class="cp-kv"><span>Queries</span><b>{cockpitStats.queries}</b></div>
            <div class="cp-kv"><span>Insights</span><b>{cockpitStats.insightsCount}</b></div>
            <div class="cp-kv"><span>Spent</span><b>${cockpitStats.cost}</b></div>
          </div>
          <div class="cp-card cp-card-purple">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="zap" size={14} /></span> PERFORMANCE</div>
            <div class="cp-kv"><span>Latency</span><b>{cockpitStats.latency}ms</b></div>
            <div class="cp-kv"><span>Quality</span><b>{cockpitStats.quality}/5</b></div>
            <div class="cp-kv"><span>Cache hit</span><b>{cockpitStats.cacheHit}%</b></div>
          </div>
          <div class="cp-card cp-card-green">
            <div class="cp-card-head"><span class="cp-card-icon"></span> HEALTH</div>
            <div class="cp-kv"><span>Brain</span><b><span class="set-dot trained"></span> {brainOk}/9</b></div>
            <div class="cp-kv"><span>Tables</span><b><span class="set-dot trained"></span> {_trainedCount}/{_totalTables}</b></div>
            <div class="cp-kv"><span>Sources</span><b><span class="set-dot {_connectedSources > 0 ? 'trained' : 'idle'}"></span> {_connectedSources}</b></div>
          </div>
          <div class="cp-card cp-card-coral">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="dollar-sign" size={14} /></span> COST</div>
            <div class="cp-kv"><span>Today</span><b>${cockpitStats.cost}</b></div>
            <div class="cp-kv"><span>Cap</span><b>${costCapInput.toFixed(2)}</b></div>
            <div class="cp-bar"><div class="cp-bar-fill" style="width: {_pct}%; background: {_pct > 80 ? '#ff4040' : 'var(--pw-accent)'};"></div></div>
            <div class="cp-kv"><span>Used</span><b>{_pct.toFixed(1)}%</b></div>
          </div>
        </div>
      </section>

      <!-- ═══ ACTIVITY — 5-card metric strip ═══ -->
      <section class="set-section cp-band">
        <div class="cp-band-head"><Icon name="bar-chart" size={14} /> Activity</div>
        <div class="cp-grid-5">
          <div class="cp-metric-card cp-metric-good">
            <div class="cp-metric-num">{activityMetrics?.good_feedback ?? 0}</div>
            <div class="cp-metric-label">GOOD FEEDBACK</div>
          </div>
          <div class="cp-metric-card cp-metric-bad">
            <div class="cp-metric-num">{activityMetrics?.bad_feedback ?? 0}</div>
            <div class="cp-metric-label">BAD FEEDBACK</div>
          </div>
          <div class="cp-metric-card cp-metric-info">
            <div class="cp-metric-num">{activityMetrics?.insights ?? 0}</div>
            <div class="cp-metric-label">INSIGHTS</div>
          </div>
          <div class="cp-metric-card cp-metric-warn">
            <div class="cp-metric-num">{activityMetrics?.drift_alerts ?? 0}</div>
            <div class="cp-metric-label">DRIFT ALERTS</div>
          </div>
          <div class="cp-metric-card cp-metric-evo">
            <div class="cp-metric-num">{activityMetrics?.evolutions ?? 0}</div>
            <div class="cp-metric-label">EVOLUTIONS</div>
          </div>
        </div>
      </section>

      <!-- ═══ PIPELINE — 3-card row (Last training / Schedule / Drift) ═══ -->
      <section class="set-section cp-band">
        <div class="cp-band-head"><Icon name="settings" size={14} /> Pipeline</div>
        <div class="cp-grid-3">
          <div class="cp-card cp-card-slate">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="settings" size={14} /></span> LAST TRAINING</div>
            <div class="cp-kv"><span>When</span><b>{trainingRuns[0]?.finished_at ? formatRelTime(trainingRuns[0].finished_at) : '—'}</b></div>
            <div class="cp-kv"><span>Steps</span><b>{trainingRuns[0]?.steps_done ?? '—'}/{trainingRuns[0]?.steps_total ?? '—'}</b></div>
            <div class="cp-kv"><span>Duration</span><b>{trainingRuns[0]?.duration_sec ? `${Math.round(trainingRuns[0].duration_sec)}s` : '—'}</b></div>
            <div class="cp-kv"><span>Cost</span><b>{trainingRuns[0]?.cost_usd ? `$${trainingRuns[0].cost_usd.toFixed(4)}` : '—'}</b></div>
          </div>
          <div class="cp-card cp-card-blue">
            <div class="cp-card-head"><span class="cp-card-icon"></span> SCHEDULE</div>
            <div class="cp-kv"><span>Next</span><b>{(Array.isArray(agentTplWorkflows) ? agentTplWorkflows : []).find((w: any) => w.schedule)?.schedule || 'On-demand'}</b></div>
            <div class="cp-kv"><span>Active workflows</span><b>{(Array.isArray(agentTplWorkflows) ? agentTplWorkflows : []).filter((w: any) => w.status === 'active').length}</b></div>
            <div style="margin-top: 8px;"><button class="set-ghost" onclick={() => { openQualityReview(); }} disabled={isTraining}>{isTraining ? 'Training…' : 'Train now'}</button></div>
          </div>
          <div class="cp-card cp-card-amber">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="alert-triangle" size={14} /></span> DRIFT</div>
            <div class="cp-kv"><span>Alerts</span><b><span class="set-dot {_driftTotalCock === 0 ? 'trained' : 'warn'}"></span> {_driftTotalCock}</b></div>
            <div class="cp-kv"><span>Casted</span><b>{_castedCount}</b></div>
            {#if _driftTotalCock > 0}<div style="margin-top: 8px;"><button class="set-ghost" onclick={openDriftDrawer}>Review →</button></div>{/if}
          </div>
        </div>
      </section>

      <!-- ═══ INTELLIGENCE — 3×3 grid (9 cards) ═══ -->
      <section class="set-section cp-band">
        <div class="cp-band-head"><Icon name="brain" size={14} /> Intelligence</div>
        <div class="cp-grid-3">
          <!-- Row 1 -->
          <div class="cp-card cp-card-teal">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="book" size={14} /></span> KNOWLEDGE</div>
            <div class="cp-card-big-num">{(Array.isArray(knowledgeFiles) ? knowledgeFiles : []).length}</div>
            <div class="cp-card-sub">files indexed</div>
            <div class="cp-card-list">
              {#each ['tables','docs','vectors','qa'] as kt}
                {@const cnt = (Array.isArray(knowledgeFiles) ? knowledgeFiles : []).filter((f: any) => f.type === kt).length}
                <div class="cp-kv"><span>{kt}</span><b>{cnt}</b></div>
              {/each}
            </div>
            <button class="cp-card-cta" onclick={() => { activeTab = 'knowledge'; }}>Open → </button>
          </div>
          <div class="cp-card cp-card-amber">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="brain" size={14} /></span> BRAIN</div>
            <div class="cp-card-big-num">{brainOk}/9</div>
            <div class="cp-card-sub">layers populated</div>
            <div class="cp-card-list">
              {#each (Array.isArray(resourceRegistry) ? resourceRegistry : []).slice(0, 5) as l}
                <div class="cp-kv"><span style="text-transform: capitalize;">{l.type}</span><b>{l.count ?? 0}</b></div>
              {/each}
            </div>
            <button class="cp-card-cta" onclick={() => { activeTab = 'knowledge'; }}>Open → </button>
          </div>
          <div class="cp-card cp-card-violet">
            <div class="cp-card-head"><span class="cp-card-icon"></span> KNOWLEDGE GRAPH</div>
            <div class="cp-card-big-num">{(Array.isArray(kgTriples) ? kgTriples : []).length}</div>
            <div class="cp-card-sub">triples extracted</div>
            <div class="cp-card-list">
              {#if Array.isArray(kgTriples) && kgTriples.length > 0}
                {@const topEntities = (() => {
                  const counts: Record<string, number> = {};
                  for (const t of kgTriples) {
                    const s = t?.subject || '—';
                    counts[s] = (counts[s] || 0) + 1;
                  }
                  return Object.entries(counts).sort((a: any, b: any) => b[1] - a[1]).slice(0, 3);
                })()}
                {#each topEntities as [ent, cnt]}
                  <div class="cp-kv"><span title={ent}>{ent.length > 22 ? ent.slice(0,22) + '…' : ent}</span><b>{cnt}</b></div>
                {/each}
              {:else}
                <div class="cp-kv"><span>no triples yet</span><b>—</b></div>
              {/if}
            </div>
            <button class="cp-card-cta" onclick={() => { activeTab = 'lineage'; }}>Open → </button>
          </div>
          <!-- Row 2 -->
          <div class="cp-card cp-card-coral">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="bot" size={14} /></span> AGENTS</div>
            <div class="cp-card-big-num">{(project as any)?.agents_count ?? 34}</div>
            <div class="cp-card-sub">configured</div>
            <div class="cp-card-list">
              <div class="cp-kv"><span>Active workflows</span><b>{(Array.isArray(agentTplWorkflows) ? agentTplWorkflows : []).filter((w: any) => w.status === 'active').length}</b></div>
              <div class="cp-kv"><span>Bindings bound</span><b>{(Array.isArray(agentTplBindings) ? agentTplBindings : []).filter((b: any) => b.status === 'bound').length}</b></div>
              <div class="cp-kv"><span>Bindings total</span><b>{(Array.isArray(agentTplBindings) ? agentTplBindings : []).length}</b></div>
            </div>
            <button class="cp-card-cta" onclick={() => { activeTab = 'agents'; }}>Open → </button>
          </div>
          <!-- Row 3 -->
          <div class="cp-card cp-card-emerald">
            <div class="cp-card-head"><span class="cp-card-icon"><Icon name="wrench" size={14} /></span> SKILLS LIBRARY</div>
            <div class="cp-card-big-num">{skillsSummary?.count ?? 0}</div>
            <div class="cp-card-sub">proven recipes</div>
            <div class="cp-card-list">
              {#if Array.isArray(skillsSummary?.top) && skillsSummary.top.length > 0}
                {#each skillsSummary.top.slice(0, 3) as s}
                  <div class="cp-kv"><span title={s.name || s.description || ''}>{((s.name || s.description || '—') + '').slice(0, 24)}</span><b>{s.success_count ?? s.uses ?? '—'}</b></div>
                {/each}
              {:else}
                <div class="cp-kv"><span>no skills yet</span><b>—</b></div>
              {/if}
            </div>
            <button class="cp-card-cta" onclick={() => { activeTab = 'self-learn'; }}>Open → </button>
          </div>
          <div class="cp-card cp-card-red">
            <div class="cp-card-head"><span class="cp-card-icon"></span> ANTI-PATTERNS</div>
            <div class="cp-card-big-num">{antiPatternsSummary?.count ?? 0}</div>
            <div class="cp-card-sub">active rules</div>
            <div class="cp-card-list">
              {#if Array.isArray(antiPatternsSummary?.top) && antiPatternsSummary.top.length > 0}
                {#each antiPatternsSummary.top.slice(0, 3) as a}
                  <div class="cp-kv"><span title={a.pattern || a.description || ''}>{((a.pattern || a.description || '—') + '').slice(0, 24)}</span><b>{a.hit_count ?? '—'}</b></div>
                {/each}
              {:else}
                <div class="cp-kv"><span>none active</span><b>—</b></div>
              {/if}
            </div>
            <button class="cp-card-cta" onclick={() => { activeTab = 'self-learn'; }}>Open → </button>
          </div>
          <div class="cp-card cp-card-slate">
            <div class="cp-card-head"><span class="cp-card-icon"></span> LINEAGE</div>
            <div class="cp-card-big-num">{(Array.isArray(agentTplBindings) ? agentTplBindings : []).length || (Array.isArray(relationships) ? relationships.length : 0)}</div>
            <div class="cp-card-sub">links tracked</div>
            <div class="cp-card-list">
              <div class="cp-kv"><span>Bindings</span><b>{(Array.isArray(agentTplBindings) ? agentTplBindings : []).length}</b></div>
              <div class="cp-kv"><span>Relationships</span><b>{(Array.isArray(relationships) ? relationships : []).length}</b></div>
            </div>
            <button class="cp-card-cta" onclick={() => { activeTab = 'lineage'; }}>Open lineage → </button>
          </div>
        </div>
      </section>

      <!-- <Icon name="check" size={14} /> Tab Completion -->
      <section class="set-section cp-band">
        <div class="cp-band-head"><Icon name="check" size={14} /> Tab Completion</div>
        <div class="cp-tab-grid">
          {#each [
            {id:'datasets', label:'DATASETS', count: tabCompletion?.datasets ?? 0},
            {id:'knowledge', label:'KNOWLEDGE', count: tabCompletion?.knowledge ?? 0},
            {id:'rules', label:'RULES', count: tabCompletion?.rules ?? 0},
            {id:'training', label:'TRAINING', count: tabCompletion?.training ?? 0},
            {id:'docs', label:'DOCS', count: tabCompletion?.docs ?? 0},
            {id:'queries', label:'QUERIES', count: tabCompletion?.queries ?? 0},
            {id:'lineage', label:'LINEAGE', count: tabCompletion?.lineage ?? 0},
            {id:'agents', label:'AGENTS', count: tabCompletion?.agents ?? 0},
            {id:'workflows', label:'WORKFLOWS', count: tabCompletion?.workflows ?? 0},
            {id:'schedules', label:'SCHEDULES', count: tabCompletion?.schedules ?? 0},
            {id:'evals', label:'EVALS', count: tabCompletion?.evals ?? 0},
            {id:'users', label:'USERS', count: tabCompletion?.users ?? 0},
            {id:'config', label:'CONFIG', count: 1},
          ] as t}
            <button class="cp-tab-card" class:cp-tab-done={t.count > 0} onclick={() => { activeTab = t.id; }}>
              <div class="cp-tab-label">{t.label}</div>
              <div class="cp-tab-state">{t.count > 0 ? '' : '○'}</div>
              <div class="cp-tab-count">{t.count}</div>
            </button>
          {/each}
        </div>
      </section>

      <!-- ═══ ACTIVITY — AI Working + Ready For You ═══ -->
      <section class="set-section cp-band">
        <div class="cp-band-head"><Icon name="message-circle" size={14} /> Live Feed</div>
        <div class="cp-grid-2">
          <div class="cp-card">
            <div class="cp-card-head"><Icon name="bot" size={14} /> AI WORKING ON</div>
            <div class="cp-empty">Nothing running right now.</div>
            <div class="cp-row cp-row-dim"><span class="cp-row-icon">·</span><span>03:00 ontology cluster</span></div>
          </div>
          <div class="cp-card">
            <div class="cp-card-head"><Icon name="check" size={14} /> READY FOR YOU</div>
            {#if (cockpitStats.insightsCount || 0) === 0}
              <div class="cp-empty">No new insights yet.</div>
            {:else}
              {#if cockpitStats.insightsCount > 0}<div class="cp-row"><span class="cp-row-icon"><Icon name="star" size={14} /></span><span>{cockpitStats.insightsCount} proactive insight{cockpitStats.insightsCount === 1 ? '' : 's'}</span></div>{/if}
            {/if}
          </div>
        </div>

        <!-- Recent chats full-width -->
        <div class="cp-card" style="margin-top: 12px;">
          <div class="cp-card-head"><Icon name="message-circle" size={14} /> RECENT CHATS</div>
          {#if recentChats.length === 0}
            <div class="cp-empty">No chats yet.</div>
          {:else}
            <div class="cp-list">
              {#each recentChats as c}
                <div class="cp-chat-row">
                  <span class="cp-chat-time">{c.updated_at ? formatRelTime(c.updated_at) : '—'}</span>
                  {#if c.score !== null && c.score !== undefined}<span class="cp-chat-score"><Icon name="star" size={14} /> {c.score}</span>{:else}<span class="cp-chat-score cp-chat-score-blank">—</span>{/if}
                  <span class="cp-chat-msg" title={c.first_message}>{c.first_message || '(no preview)'}</span>
                  <a href="{base}/project/{slug}?session={c.session_id}" class="cp-chat-open">Open →</a>
                </div>
              {/each}
            </div>
          {/if}
        </div>

        <!-- Recent activity full-width -->
        <div class="cp-card" style="margin-top: 12px;">
          <div class="cp-card-head"><Icon name="clipboard" size={14} /> RECENT ACTIVITY</div>
          {#if recentActivity.length === 0}
            <div class="cp-empty">No activity yet.</div>
          {:else}
            <div class="cp-list">
              {#each recentActivity as ev}
                <div class="cp-act-row">
                  <span class="cp-act-time">{ev.time}</span>
                  <span class="cp-act-icon">{ev.icon}</span>
                  <span class="cp-act-msg">{ev.msg}</span>
                </div>
              {/each}
            </div>
          {/if}
        </div>
      </section>

    {/if}

  <!-- ═══ DATA QUALITY ═══ -->
      {/if}<!-- end hidden legacy: sources/files/table details -->
    {/if}<!-- end upload tab -->
  {:else if activeTab === 'data-quality'}
    {@const _dqIssues = dqFilteredIssues()}
    {@const _dqAllTables = dqData?.by_table ? Object.keys(dqData.by_table).sort() : []}
    <div style="display: flex; flex-direction: column; gap: 14px;">
      <!-- Score / counts strip -->
      <div style="display: flex; align-items: center; gap: 18px; padding: 14px 18px; border: 2px solid var(--pw-ink); background: var(--pw-surface);">
        <div style="display: flex; flex-direction: column; align-items: center; min-width: 92px;">
          <div style="font-size: 28px; font-weight: 900; color: {dqScoreColor(dqData?.score ?? 100)}; font-family: var(--pw-font-serif, ui-serif);">
            {dqData?.score ?? '—'}
          </div>
          <div style="font-size: 10px; color: var(--pw-muted); letter-spacing: 0.06em; text-transform: uppercase;">QUALITY SCORE</div>
        </div>
        <div style="display: flex; gap: 10px; flex-wrap: wrap; flex: 1;">
          {#if dqData}
            <span style="padding: 4px 10px; border: 1px solid var(--pw-error, #c14a3a); color: var(--pw-error, #c14a3a); font-size: 11px; font-weight: 700;">
              ● {dqData.by_severity.high} HIGH
            </span>
            <span style="padding: 4px 10px; border: 1px solid #cc7a00; color: #cc7a00; font-size: 11px; font-weight: 700;">
              ◐ {dqData.by_severity.medium} MED
            </span>
            <span style="padding: 4px 10px; border: 1px solid #888; color: #888; font-size: 11px; font-weight: 700;">
              ○ {dqData.by_severity.low} LOW
            </span>
            <span style="padding: 4px 10px; border: 1px solid var(--pw-muted); color: var(--pw-muted); font-size: 11px; font-weight: 700;">
              ⓘ {dqData.by_severity.info} INFO
            </span>
          {:else if dqLoading}
            <span style="color: var(--pw-muted); font-size: 11px;">scanning…</span>
          {/if}
          {#if dqData?.last_scanned}
            <span style="margin-left: auto; font-size: 10px; color: var(--pw-muted);">last scan: {dqData.last_scanned}</span>
          {/if}
        </div>
        <button
          class="set-cta"
          style="padding: 8px 14px;"
          disabled={dqRescanning}
          onclick={rescanDataQuality}
        >{dqRescanning ? '● SCANNING…' : '↻ RESCAN'}</button>
      </div>

      {#if dqData?.error}
        <div style="padding: 10px 14px; border: 1px solid var(--pw-error, #c14a3a); color: var(--pw-error, #c14a3a); font-size: 11px;">
          <Icon name="alert-triangle" size={14} /> {dqData.error}
        </div>
      {/if}

      <!-- Filters -->
      {#if dqData && dqData.issue_count}
        <div style="display: flex; gap: 10px; align-items: center; flex-wrap: wrap;">
          <span style="font-size: 10px; color: var(--pw-muted); letter-spacing: 0.06em; text-transform: uppercase;">FILTER</span>
          {#each ['all', 'high', 'medium', 'low', 'info'] as sev}
            <button
              onclick={() => { dqSeverityFilter = sev as any; }}
              style="padding: 4px 10px; border: 1.5px solid {dqSeverityFilter === sev ? 'var(--pw-ink)' : 'var(--pw-muted)'}; background: {dqSeverityFilter === sev ? 'var(--pw-ink)' : 'transparent'}; color: {dqSeverityFilter === sev ? 'var(--pw-surface)' : 'var(--pw-ink)'}; font-size: 10px; font-weight: 700; cursor: pointer; letter-spacing: 0.06em; text-transform: uppercase;"
            >{sev}</button>
          {/each}
          <span style="margin-left: 12px; font-size: 10px; color: var(--pw-muted);">|</span>
          <select
            bind:value={dqTableFilter}
            style="padding: 4px 8px; border: 1.5px solid var(--pw-muted); background: var(--pw-surface); font-size: 11px;"
          >
            <option value="">all tables ({_dqAllTables.length})</option>
            {#each _dqAllTables as tn}
              <option value={tn}>{tn} ({dqData.by_table[tn]})</option>
            {/each}
          </select>
          {#if dqTableFilter || dqSeverityFilter !== 'all'}
            <button
              onclick={() => { dqTableFilter = ''; dqSeverityFilter = 'all'; }}
              style="padding: 4px 8px; border: none; background: none; color: var(--pw-muted); font-size: 11px; cursor: pointer; text-decoration: underline;"
            >clear filters</button>
          {/if}
          <span style="margin-left: auto; font-size: 11px; color: var(--pw-muted);">
            showing {_dqIssues.length} of {dqData.issue_count}
          </span>
        </div>
      {/if}

      <!-- Issue list -->
      {#if dqLoading && !dqData}
        <div style="padding: 40px; text-align: center; color: var(--pw-muted); font-size: 11px;">● scanning project tables…</div>
      {:else if dqData && dqData.score >= 100 && dqData.issue_count === 0}
        <div style="padding: 60px 20px; text-align: center; border: 2px dashed var(--pw-success, #2d8a4a); background: rgba(45,138,74,0.04);">
          <div style="font-size: 30px; margin-bottom: 8px;"><Icon name="star" size={14} /></div>
          <div style="font-size: 13px; font-weight: 700; color: var(--pw-success, #2d8a4a);">No data quality issues detected</div>
          <div style="font-size: 11px; color: var(--pw-muted); margin-top: 6px;">All {dqData.table_count} table(s) passed every check.</div>
        </div>
      {:else if _dqIssues.length === 0}
        <div style="padding: 40px; text-align: center; color: var(--pw-muted); font-size: 11px;">
          No issues match the active filter.
        </div>
      {:else}
        <div style="display: flex; flex-direction: column; gap: 6px;">
          {#each _dqIssues as it, ix}
            <div style="border: 1.5px solid var(--pw-ink); border-left: 4px solid {dqSeverityColor(it.severity)}; background: var(--pw-surface);">
              <button
                onclick={() => { dqExpanded[ix] = !dqExpanded[ix]; dqExpanded = {...dqExpanded}; }}
                style="width: 100%; display: grid; grid-template-columns: 32px 92px 1fr auto auto; gap: 12px; align-items: center; padding: 10px 14px; background: none; border: none; cursor: pointer; text-align: left; font: inherit; color: inherit;"
              >
                <span style="color: {dqSeverityColor(it.severity)}; font-size: 14px; font-weight: 700;">{dqSeverityIcon(it.severity)}</span>
                <span style="padding: 2px 8px; border: 1px solid {dqSeverityColor(it.severity)}; color: {dqSeverityColor(it.severity)}; font-size: 11px; font-weight: 800; letter-spacing: 0.05em; text-align: center;">{dqTypeLabel(it.type)}</span>
                <div style="display: flex; flex-direction: column; gap: 2px; min-width: 0;">
                  <div style="font-size: 11px; font-weight: 700; color: var(--pw-ink); white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">
                    {it.table}{#if it.column}<span style="color: var(--pw-muted); font-weight: 400;">.</span><span style="color: var(--pw-ink);">{it.column}</span>{/if}
                  </div>
                  <div style="font-size: 11px; color: var(--pw-muted); white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">{it.message}</div>
                </div>
                <span style="font-size: 10px; color: var(--pw-muted); text-transform: uppercase; letter-spacing: 0.04em;">{it.severity}</span>
                <span style="color: var(--pw-muted); font-size: 13px; transform: rotate({dqExpanded[ix] ? 90 : 0}deg); transition: transform 120ms;">▸</span>
              </button>
              {#if dqExpanded[ix]}
                <div style="padding: 12px 18px 14px 58px; border-top: 1px dashed var(--pw-muted); background: var(--pw-bg-alt, rgba(0,0,0,0.02)); font-size: 11px; line-height: 1.55;">
                  <div style="margin-bottom: 8px;"><strong>Issue:</strong> {it.message}</div>
                  <div><strong>Suggestion:</strong></div>
                  <pre style="margin: 6px 0 0 0; padding: 10px 12px; background: #1a1614; color: #e8e3d6; font-family: ui-monospace, monospace; font-size: 11px; overflow-x: auto; white-space: pre-wrap; word-break: break-word;">{it.suggestion}</pre>
                </div>
              {/if}
            </div>
          {/each}
        </div>
      {/if}
    </div>

  <!-- ═══ KNOWLEDGE ═══ -->
  {:else if activeTab === 'knowledge'}
    <div class="cli-terminal" style="margin-bottom: 16px; padding: 8px 14px;">
      <div class="cli-line">
        <span class="cli-prompt">$</span>
        <span class="cli-command">dash knowledge</span>
        <span class="cli-output">--status</span>
        <span class="cli-success" style="margin-left: auto;">&#10003; {detail?.knowledge_vectors || 0} vectors · {knowledgeFiles.length} files</span>
      </div>
      <div class="cli-line">
        <span style="color: var(--pw-muted);">&gt;</span>
        <span class="cli-output">{knowledgeFiles.filter((f: any) => f.type === 'tables').length} table metadata · {knowledgeFiles.filter((f: any) => f.type === 'queries').length} query patterns · {knowledgeFiles.filter((f: any) => f.type === 'business').length} business rules</span>
      </div>
    </div>

    <!-- Full breakdown grid: all knowledge items by subdir -->
    {#if knowledgeFiles.length > 0}
      {@const groups = Array.from(new Set(knowledgeFiles.map((f: any) => f.type))).sort()}
      <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 8px; margin-bottom: 20px;">
        {#each groups as g}
          {@const items = knowledgeFiles.filter((f: any) => f.type === g)}
          <div class="ink-border" style="padding: 10px 12px; background: var(--pw-bg-alt);">
            <div style="font-size: 11px; font-weight: 700; text-transform: uppercase; color: var(--pw-muted); letter-spacing: 0.06em; margin-bottom: 4px;">{g}</div>
            <div style="font-size: 19px; font-weight: 800; color: var(--pw-ink); line-height: 1;">{items.length}</div>
            <div style="font-size: 10px; color: var(--pw-muted); margin-top: 4px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title={items.map((i: any) => i.name).join(', ')}>{items.slice(0, 3).map((i: any) => i.name).join(', ')}{items.length > 3 ? ` +${items.length - 3}` : ''}</div>
          </div>
        {/each}
      </div>
    {/if}

    <div style="font-size: 16px; font-weight: 900; text-transform: uppercase; margin-bottom: 16px;">Knowledge</div>

    {#each knowledgeFiles.filter(f => f.type === 'tables') as f}
      {#await fetch(`/api/knowledge-file-content/${f.name}?project=${slug}&subdir=tables`, { headers: _h() }).then(r => r.json()) then data}
        {#if data.type === 'json' && data.content}
          <div class="ink-border mb-3" style="background: var(--pw-surface);">
            <div class="dark-title-bar" style="padding: 6px 12px; font-size: 10px;">{data.content.table_name || f.name}</div>
            <div style="padding: 12px; font-size: 11px;">
              <div style="margin-bottom: 8px; color: var(--pw-muted);">{data.content.table_description || ''}</div>
              {#if data.content.table_purpose || data.content.grain || (Array.isArray(data.content.primary_keys) && data.content.primary_keys.length) || (Array.isArray(data.content.foreign_keys) && data.content.foreign_keys.length) || (Array.isArray(data.content.usage_patterns) && data.content.usage_patterns.length) || data.content.freshness || data.content.refresh_cadence || (Array.isArray(data.content.alternate_tables) && data.content.alternate_tables.length) || (Array.isArray(data.content.relationships) && data.content.relationships.length)}
                <div class="codex-meta">
                  {#if data.content.table_purpose}<div class="codex-row"><span class="codex-lbl">PURPOSE</span><span class="codex-val">{data.content.table_purpose}</span></div>{/if}
                  {#if data.content.grain}<div class="codex-row"><span class="codex-lbl">GRAIN</span><span class="codex-val">{data.content.grain}</span></div>{/if}
                  {#if Array.isArray(data.content.primary_keys) && data.content.primary_keys.length}<div class="codex-row"><span class="codex-lbl">PRIMARY KEYS</span><span class="codex-val">{data.content.primary_keys.join(', ')}</span></div>{/if}
                  {#if Array.isArray(data.content.foreign_keys) && data.content.foreign_keys.length}<div class="codex-row"><span class="codex-lbl">FOREIGN KEYS</span><span class="codex-val">{data.content.foreign_keys.map((fk: any) => typeof fk === 'string' ? fk : `${fk.column || fk.from || ''} → ${fk.references || fk.to || ''}`).join(', ')}</span></div>{/if}
                  {#if Array.isArray(data.content.usage_patterns) && data.content.usage_patterns.length}<div class="codex-row"><span class="codex-lbl">USAGE PATTERNS</span><span class="codex-val">{data.content.usage_patterns.join('; ')}</span></div>{/if}
                  {#if data.content.freshness || data.content.refresh_cadence}<div class="codex-row"><span class="codex-lbl">FRESHNESS</span><span class="codex-val">{data.content.freshness || data.content.refresh_cadence}</span></div>{/if}
                  {#if Array.isArray(data.content.alternate_tables) && data.content.alternate_tables.length}<div class="codex-row"><span class="codex-lbl">ALTERNATE TABLES</span><span class="codex-val">{data.content.alternate_tables.join(', ')}</span></div>{/if}
                  {#if Array.isArray(data.content.relationships) && data.content.relationships.length}<div class="codex-row"><span class="codex-lbl">RELATIONSHIPS</span><span class="codex-val">{data.content.relationships.map((r: any) => typeof r === 'string' ? r : `${r.from || r.source || ''} → ${r.to || r.target || ''}`).join(', ')}</span></div>{/if}
                </div>
              {/if}
              {#if data.content.table_columns?.length}
                <div class="tag-label mb-1" style="font-size: 11px;">COLUMNS</div>
                <table style="width: 100%; font-size: 11px; border-collapse: collapse; margin-bottom: 8px;">
                  <thead><tr style="border-bottom: 1px solid var(--pw-ink);"><th style="text-align: left; padding: 3px 6px;">Name</th><th style="text-align: left; padding: 3px 6px;">Type</th><th style="text-align: left; padding: 3px 6px;">Description</th><th style="padding: 3px 6px; width: 40px;"></th></tr></thead>
                  <tbody>
                    {#each data.content.table_columns as col}
                      {@const _tblName = data.content.table_name}
                      {@const _ann = brainAnnotations.find((a: any) => a.table_name === _tblName && a.column_name === col.name)}
                      {@const _enriched = columnMeta[_tblName]?.[col.name]}
                      {@const _mergedCol = _ann ? { ...col, description: _ann.annotation } : col}
                      {@const _autoLoad = (loadColumnMeta(_tblName), true)}
                      <ColumnCard
                        col={_mergedCol}
                        meta={_enriched || null}
                        {slug}
                        table_name={_tblName}
                        on:askQuestion={(e) => handleAskQuestion(e.detail)}
                      />
                    {/each}
                  </tbody>
                </table>
              {/if}
              {#if data.content.use_cases?.length}
                <div class="tag-label mb-1" style="font-size: 11px;">USE CASES</div>
                <div style="margin-bottom: 8px;">{#each data.content.use_cases as uc}<div style="font-size: 10px; color: var(--pw-muted);">· {uc}</div>{/each}</div>
              {/if}
              {#if data.content.data_quality_notes?.length}
                <div class="tag-label mb-1" style="font-size: 11px;">DATA QUALITY</div>
                {#each data.content.data_quality_notes as n}<div style="font-size: 10px; color: #cc7a00;"><Icon name="alert-triangle" size={14} /> {n}</div>{/each}
              {/if}
            </div>
          </div>
        {/if}
      {/await}
    {/each}

    {#if knowledgeFiles.filter(f => f.type === 'business').length > 0}
      {#each knowledgeFiles.filter(f => f.type === 'business') as f}
        {#await fetch(`/api/knowledge-file-content/${f.name}?project=${slug}&subdir=business`, { headers: _h() }).then(r => r.json()) then data}
          {#if data.type === 'json' && data.content}
            <div class="ink-border mb-3" style="background: var(--pw-surface);">
              <div class="dark-title-bar" style="padding: 6px 12px; font-size: 10px;">BUSINESS RULES</div>
              <div style="padding: 12px; font-size: 11px;">
                {#if data.content.metrics?.length}
                  {#each data.content.metrics as m}
                    <div style="margin-bottom: 6px;"><strong>{m.name}</strong>: {m.definition} <span style="color: var(--pw-muted);">({m.calculation})</span></div>
                  {/each}
                {/if}
              </div>
            </div>
          {/if}
        {/await}
      {/each}
    {/if}

    {#if knowledgeFiles.length === 0}
      <div style="font-size: 11px; color: var(--pw-muted);">Upload data to auto-generate knowledge.</div>
    {/if}

  <!-- ═══ RULES ═══ -->
  {:else if activeTab === 'rules'}
    <div class="cli-terminal" style="margin-bottom: 16px; padding: 8px 14px;">
      <div class="cli-line">
        <span class="cli-prompt">$</span>
        <span class="cli-command">dash rules</span>
        <span class="cli-output">--list</span>
        <span class="cli-dim" style="margin-left: auto;">{rules.length} active · {suggestedRules.length} pending</span>
      </div>
    </div>
    <div class="flex items-center justify-between mb-4">
      <div style="font-size: 16px; font-weight: 900; text-transform: uppercase;">Business Rules</div>
      <div class="flex gap-2">
        <button class="btn-primary btn-sm" onclick={() => showAddRule = true}>+ ADD RULE</button>
        <button class="feedback-btn" style="font-size: 10px; padding: 6px 14px; font-weight: 700;" onclick={() => {
          const rule = prompt('Type a rule in plain English (e.g., "MRR excludes churned customers"):');
          if (rule) { fetch(`/api/projects/${slug}/nl-to-rule`, { method: 'POST', headers: { ..._h(), 'Content-Type': 'application/json' }, body: JSON.stringify({ rule }) }).then(() => { loadRules(); loadBrainData(); }); }
        }}>AI CONVERT</button>
      </div>
    </div>
    <div style="font-size: 11px; color: var(--pw-muted); margin-bottom: 16px;">
      Define business rules your agent must follow. Rules like "MRR = active subscriptions only" or "fiscal year starts April" are injected into the agent's instructions.
    </div>

    {#if showAddRule}
      <div class="ink-border stamp-shadow" style="background: var(--pw-surface); padding: 16px; margin-bottom: 16px;">
        <div style="font-size: 11px; font-weight: 900; text-transform: uppercase; margin-bottom: 10px;">NEW RULE</div>

        <!-- Formula / column builder -->
        <div class="formula-builder" style="margin-bottom: 12px; padding: 12px; background: var(--pw-bg-alt); border-radius: 0;">
          <div style="font-size: 11px; text-transform: uppercase; color: var(--pw-muted); margin-bottom: 8px; letter-spacing: 0.04em;">BUILD FROM COLUMNS</div>
          <div style="display: flex; gap: 8px; flex-wrap: wrap; align-items: center;">
            <select bind:value={fbTable} style="border: 1px solid var(--pw-border); background: var(--pw-surface); padding: 5px 8px; font-size: 11px; border-radius: 0;">
              <option value="">Pick table…</option>
              {#each (detail?.tables || []) as t}<option value={t.name}>{t.name}</option>{/each}
            </select>
            {#if fbTable}
              {@const fbCols = (tableInspectCache[fbTable]?.columns || [])}
              <select bind:value={fbColA} style="border: 1px solid var(--pw-border); background: var(--pw-surface); padding: 5px 8px; font-size: 11px; border-radius: 0;">
                <option value="">Column A…</option>
                {#each fbCols as c}<option value={c.name}>{c.name}</option>{/each}
              </select>
              <select bind:value={fbOp} style="border: 1px solid var(--pw-border); background: var(--pw-surface); padding: 5px 8px; font-size: 11px; border-radius: 0;">
                <option value="+">+</option>
                <option value="-">−</option>
                <option value="*">×</option>
                <option value="/">÷</option>
              </select>
              <select bind:value={fbColB} style="border: 1px solid var(--pw-border); background: var(--pw-surface); padding: 5px 8px; font-size: 11px; border-radius: 0;">
                <option value="">Column B…</option>
                {#each fbCols as c}<option value={c.name}>{c.name}</option>{/each}
              </select>
              <button type="button" class="feedback-btn" style="font-size: 10px; padding: 5px 12px;" onclick={fbInsert}>INSERT</button>
              <button type="button" class="send-btn" style="font-size: 10px; padding: 5px 12px;" onclick={fbAiMap}>AI MAP</button>
            {/if}
          </div>
          <div style="font-size: 11px; color: var(--pw-muted); margin-top: 6px;">Tip: AI map auto-generates rule name + type from columns.</div>
        </div>

        <div style="margin-bottom: 8px;">
          <div style="font-size: 11px; font-weight: 700; text-transform: uppercase; margin-bottom: 3px;">NAME</div>
          <input type="text" bind:value={newRuleName} placeholder="e.g., Revenue = MRR * 12" style="width: 100%; border: 2px solid var(--pw-ink); padding: 6px 10px; font-family: var(--pw-font-body); font-size: 12px; background: var(--pw-surface);" />
        </div>
        <div style="margin-bottom: 8px;">
          <div style="font-size: 11px; font-weight: 700; text-transform: uppercase; margin-bottom: 3px;">TYPE</div>
          <select bind:value={newRuleType} style="border: 2px solid var(--pw-ink); padding: 6px 10px; font-family: var(--pw-font-body); font-size: 11px; background: var(--pw-surface);">
            <option value="business_rule">Business Rule</option>
            <option value="metric">Metric Definition</option>
            <option value="gotcha">Common Gotcha</option>
            <option value="calculation">Calculation</option>
          </select>
        </div>
        <div style="margin-bottom: 12px;">
          <div style="font-size: 11px; font-weight: 700; text-transform: uppercase; margin-bottom: 3px;">DEFINITION</div>
          <textarea bind:value={newRuleDefinition} placeholder="Describe the rule the agent should follow..." rows="3" style="width: 100%; border: 2px solid var(--pw-ink); padding: 6px 10px; font-family: var(--pw-font-body); font-size: 11px; background: var(--pw-surface); resize: vertical;"></textarea>
        </div>
        <div class="flex gap-2">
          <button class="btn-primary btn-sm" onclick={addRule} disabled={ruleSaving || !newRuleName || !newRuleDefinition}>
            {ruleSaving ? 'SAVING...' : 'SAVE RULE'}
          </button>
          <button class="feedback-btn" style="font-size: 10px; padding: 6px 14px;" onclick={() => showAddRule = false}>Cancel</button>
        </div>
      </div>
    {/if}

    {#if rules.length > 0}
      <div style="display: flex; flex-direction: column; gap: 8px;">
        {#each rules as rule}
          <div class="ink-border" style="background: var(--pw-surface); padding: 12px 16px;">
            <div class="flex items-center justify-between">
              <div>
                <span style="font-size: 12px; font-weight: 900;">{rule.name}</span>
                <span class="tag-label" style="font-size: 11px; margin-left: 8px;">{rule.type?.replace('_', ' ')}</span>
              </div>
              <button class="feedback-btn" style="font-size: 11px; padding: 3px 8px; color: var(--pw-error);" onclick={() => deleteRule(rule.id)} title="Delete rule">
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
              </button>
            </div>
            <div style="font-size: 11px; color: var(--pw-muted); margin-top: 6px;">{rule.definition}</div>
            {#if rule.created_at}
              <div style="font-size: 11px; color: var(--pw-muted); margin-top: 6px; text-transform: uppercase; letter-spacing: 0.08em;">
                {rule.source === 'user' ? 'USER-DEFINED' : 'AUTO-SUGGESTED'} &middot; {rule.created_at?.slice(0, 10)}
              </div>
            {/if}
          </div>
        {/each}
      </div>
    {:else}
      <div style="text-align: center; padding: 40px 20px; color: var(--pw-muted); font-size: 11px;">
        No rules defined yet. Add rules to make your agent smarter.
      </div>
    {/if}

    <!-- Suggested Rules (from Knowledge Harness) -->
    {#if suggestedRules.length > 0}
      <div style="margin-top: 24px; border-top: 2px solid var(--pw-ink); padding-top: 16px;">
        <div style="font-size: 13px; font-weight: 900; text-transform: uppercase; margin-bottom: 8px;">
          AI-SUGGESTED RULES
          <span class="tag-label" style="font-size: 11px; margin-left: 6px; background: #cc7a00; color: var(--pw-ink);">{suggestedRules.length} PENDING</span>
        </div>
        <div style="font-size: 11px; color: var(--pw-muted); margin-bottom: 12px;">
          These rules were extracted from your conversations. Approve to add them to the agent's instructions.
        </div>
        <div style="display: flex; flex-direction: column; gap: 8px;">
          {#each suggestedRules as sr}
            <div class="ink-border" style="background: var(--pw-surface); padding: 12px 16px; border-left: 3px solid #cc7a00;">
              <div style="font-size: 12px; font-weight: 900;">{sr.name}</div>
              <div style="font-size: 11px; color: var(--pw-muted); margin-top: 4px;">{sr.definition}</div>
              <div class="flex gap-2 mt-2">
                <button class="send-btn" style="font-size: 11px; padding: 4px 12px;" onclick={() => approveRule(sr.id)}>Approve</button>
                <button class="feedback-btn" style="font-size: 11px; padding: 4px 12px;" onclick={() => rejectRule(sr.id)}>Reject</button>
              </div>
            </div>
          {/each}
        </div>
      </div>
    {/if}

  <!-- ═══ TRAINING (Agent Brain) ═══ -->
  {:else if activeTab === 'training'}
    <!-- LIVE TRAINING PROGRESS — shows currently-running runs + auto-polls -->
    {@const liveRuns = (trainingRuns || []).filter((r: any) => r.status === 'running')}
    {#if liveRuns.length > 0}
      <div style="margin-bottom: 16px; padding: 14px 16px; background: rgba(201,99,66,0.08); border-left: 3px solid var(--pw-accent); border-radius: 4px;">
        <div style="display: flex; align-items: center; gap: 10px; margin-bottom: 8px;">
          <div style="width: 10px; height: 10px; border-radius: 50%; background: var(--pw-accent); animation: pulse 1.5s ease-in-out infinite;"></div>
          <div style="font-weight: 700; font-size: 14px; color: var(--pw-accent);">Training in progress · {liveRuns.length} run{liveRuns.length > 1 ? 's' : ''} active</div>
        </div>
        {#each liveRuns as r}
          <div style="font-size: 12px; color: var(--pw-ink); margin-left: 20px; margin-top: 4px; font-family: monospace;">
            ▸ run #{r.id} · {r.current_step || r.steps?.split('|')?.[0] || 'starting…'} · started {formatRelative(r.started_at)}
          </div>
        {/each}
        <div style="font-size: 11px; color: var(--pw-muted); margin-top: 8px; margin-left: 20px;">Page auto-refreshes every 5s.</div>
      </div>
    {/if}

    <!-- CLI Status -->
    <div class="cli-terminal" style="margin-bottom: 16px; padding: 10px 14px;">
      <div class="cli-line">
        <span class="cli-prompt">$</span>
        <span class="cli-command">dash brain</span>
        <span class="cli-output">--verbose</span>
      </div>
      <div class="cli-line"><span style="color: var(--pw-muted);">&gt;</span><span class="cli-check">&#10003;</span><span class="cli-output">error learnings: {training?.learnings || 0}</span></div>
      <div class="cli-line"><span style="color: var(--pw-muted);">&gt;</span><span class="cli-check">&#10003;</span><span class="cli-output">training Q&A: {training?.training_qa?.length || 0}</span></div>
      <div class="cli-line"><span style="color: var(--pw-muted);">&gt;</span><span class="cli-check">&#10003;</span><span class="cli-output">approved responses: {brainFeedback.filter(f => f.rating === 'up').length}</span></div>
      <div class="cli-line"><span style="color: var(--pw-muted);">&gt;</span><span class="cli-check">&#10003;</span><span class="cli-output">rejected patterns: {brainFeedback.filter(f => f.rating === 'down').length}</span></div>
      <div class="cli-line"><span style="color: var(--pw-muted);">&gt;</span><span class="cli-check">&#10003;</span><span class="cli-output">proven queries: {brainPatterns.length}</span></div>
      <div class="cli-line"><span style="color: var(--pw-muted);">&gt;</span><span class="cli-check">&#10003;</span><span class="cli-output">remembered facts: {brainMemories.length}</span></div>
    </div>

    <!-- ═══ Q&A VALIDATION — per-table SQL-validator drop counter ═══ -->
    {@const _qaDropTotal = (qaDrops || []).reduce((acc: number, r: any) => acc + (Number(r?.drop_count) || 0), 0)}
    <details class="ds-card-flat" style="margin-bottom: 16px; padding: 12px 14px;" open={_qaDropTotal > 0}>
      <summary style="cursor: pointer; display: flex; align-items: center; justify-content: space-between; font-size: 12px; font-weight: 900; letter-spacing: 0.06em; text-transform: uppercase; color: var(--pw-ink);">
        <span>Q&amp;A Validation <span style="color: var(--pw-muted); font-weight: 400; letter-spacing: 0; text-transform: none;">({_qaDropTotal} dropped, last 30d)</span></span>
        <button class="set-ghost" style="font-size: 10px;" onclick={(e) => { e.preventDefault(); e.stopPropagation(); loadQaDrops(); }}>↻ Refresh</button>
      </summary>
      <div style="margin-top: 10px;">
        {#if (qaDrops || []).length === 0}
          <div style="padding: 12px; background: rgba(0, 180, 80, 0.08); border-left: 3px solid var(--pw-success, #00b450); border-radius: 4px; font-size: 12px; color: var(--pw-success, #00b450);">
            No Q&amp;A pairs dropped — all generated SQL validated clean.
          </div>
        {:else}
          <table class="ds-table" style="width: 100%; font-size: 12px;">
            <thead>
              <tr style="border-bottom: 1px solid var(--pw-border);">
                <th style="text-align: left; padding: 6px 8px; font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pw-muted);">Table</th>
                <th style="text-align: right; padding: 6px 8px; font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pw-muted);">Drops</th>
                <th style="text-align: left; padding: 6px 8px; font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pw-muted);">Last drop</th>
                <th style="text-align: left; padding: 6px 8px; font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pw-muted);">Top reason</th>
              </tr>
            </thead>
            <tbody>
              {#each qaDrops as row (row?.table_name)}
                {@const _reasons = Array.isArray(row?.reasons) ? row.reasons : []}
                {@const _topReason = _reasons[0] || '—'}
                {@const _expanded = !!qaDropsExpanded[row?.table_name]}
                <tr style="border-bottom: 1px dotted var(--pw-border); cursor: pointer;"
                    onclick={() => { qaDropsExpanded = { ...qaDropsExpanded, [row?.table_name]: !_expanded }; }}>
                  <td style="padding: 6px 8px; font-family: monospace; color: var(--pw-ink);">{row?.table_name || '—'}</td>
                  <td style="padding: 6px 8px; text-align: right; font-weight: 700;">{row?.drop_count ?? 0}</td>
                  <td style="padding: 6px 8px; color: var(--pw-muted);">{row?.last_drop_at ? formatRelTime(row.last_drop_at) : '—'}</td>
                  <td style="padding: 6px 8px; color: var(--pw-muted); font-size: 11px;">{_topReason}</td>
                </tr>
                {#if _expanded && _reasons.length > 0}
                  <tr>
                    <td colspan="4" style="padding: 8px 12px 12px 24px; background: var(--pw-bg-alt); border-bottom: 1px solid var(--pw-border);">
                      <div style="font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pw-muted); margin-bottom: 6px;">All reasons ({_reasons.length})</div>
                      <ul style="margin: 0; padding-left: 18px; font-size: 11px; color: var(--pw-ink); line-height: 1.5;">
                        {#each _reasons as reason}
                          <li>{reason}</li>
                        {/each}
                      </ul>
                    </td>
                  </tr>
                {/if}
              {/each}
            </tbody>
          </table>
        {/if}
      </div>
    </details>

    <div class="flex items-center justify-between mb-4">
      <div style="font-size: 16px; font-weight: 900; text-transform: uppercase;">Agent Brain</div>
      <div class="flex gap-2">
        <button class="send-btn" style="font-size: 10px; padding: 6px 14px;" onclick={() => { window.dispatchEvent(new CustomEvent('dash-train-all')); }}>RETRAIN AGENT</button>
        <button class="feedback-btn" style="font-size: 10px; padding: 6px 14px; font-weight: 700;" onclick={async () => {
          try { const r = await fetch(`/api/projects/${slug}/quality-check`, { method: 'POST', headers: _h() }); if (r.ok) { const d = await r.json(); alert(`Checked ${d.tables_checked} tables. Found ${d.issues.length} issues.`); } } catch {}
        }}>QUALITY CHECK</button>
      </div>
    </div>

    <!-- ═══ INDIVIDUAL TRAINING STEPS — run any one without full TRAIN ALL ═══ -->
    <div class="ink-border" style="padding:14px; margin-bottom:16px; background:var(--pw-surface);">
      <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:10px;">
        <div style="font-size:11px; font-weight:900; letter-spacing:0.08em; color:var(--pw-ink);"><Icon name="zap" size={14} /> RUN SINGLE STEP</div>
        <span style="font-size:10px; color:var(--pw-muted);">re-run any one piece without retraining everything</span>
      </div>
      <div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(260px, 1fr)); gap:8px;">
        {#each STEP_DEFS as st}
          {@const res = stepResults[st.id]}
          {@const isRunning = stepRunning === st.id}
          <div style="padding:10px 12px; background:var(--pw-surface); border:1px solid {res?.ok === true ? 'var(--pw-success)' : res?.ok === false ? 'var(--pw-error)' : 'var(--pw-border)'};">
            <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:4px;">
              <span style="font-size:10px; font-weight:700; color:var(--pw-ink); letter-spacing:0.04em;">{st.label}</span>
              <button onclick={() => runStep(st.id, st.id === 'goals')} disabled={!!stepRunning}
                style="padding:3px 10px; background:{isRunning ? 'var(--pw-dim)' : 'var(--pw-success)'}; color:var(--pw-surface); border:none; cursor:{stepRunning ? 'not-allowed' : 'pointer'}; font-family:inherit; font-size: 11px; font-weight:700;">
                {isRunning ? 'RUNNING…' : '▶ RUN'}
              </button>
            </div>
            <div style="font-size: 11px; color:var(--pw-muted); line-height:1.4;">{st.desc}</div>
            {#if res && !res.running}
              <div style="margin-top:6px; padding-top:6px; border-top:1px dotted var(--pw-border); font-size: 11px; font-family:monospace; color:{res.ok ? 'var(--pw-success)' : 'var(--pw-error)'};">
                {#if res.ok}
                  <Icon name="check" size={14} /> done · {JSON.stringify(res.result || {}).slice(0, 120)}
                {:else}
                  <Icon name="x" size={14} /> {res.reason || 'failed'}
                {/if}
              </div>
            {/if}
          </div>
        {/each}
      </div>
    </div>

    <!-- Stats Grid -->
    <div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; margin-bottom: 20px;">
      {#each [
        { label: 'ERROR LEARNINGS', value: training?.learnings || 0, color: 'var(--pw-error)' },
        { label: 'TRAINING Q&A', value: training?.training_qa?.length || 0, color: 'var(--pw-accent)' },
        { label: 'FEEDBACK', value: brainFeedback.length, color: 'var(--pw-accent-ink)' },
        { label: 'PROVEN SQL', value: brainPatterns.length, color: 'var(--pw-accent)' },
        { label: 'MEMORIES', value: brainMemories.length, color: '#cc7a00' },
        { label: 'ANNOTATIONS', value: brainAnnotations.length, color: 'var(--pw-accent-ink)' },
      ] as stat}
        <div class="ink-border" style="background: var(--pw-surface); padding: 10px; text-align: center;">
          <div style="font-size: 18px; font-weight: 900; color: {stat.color};">{stat.value}</div>
          <div style="font-size: 11px; text-transform: uppercase; color: var(--pw-muted); letter-spacing: 0.06em;">{stat.label}</div>
        </div>
      {/each}
    </div>

    <!-- Memories -->
    <!-- Training History -->
    {#if trainingRuns.length > 0}
      <div style="font-size: 12px; font-weight: 900; text-transform: uppercase; margin-bottom: 8px; margin-top: 16px;">TRAINING HISTORY</div>
      <div class="cli-terminal" style="padding: 10px 14px; margin-bottom: 16px;">
        {#each trainingRuns.slice(0, 5) as run}
          <div class="cli-line">
            <span style="color: {run.status === 'done' ? 'var(--pw-accent)' : run.status === 'failed' ? 'var(--pw-error)' : '#cc7a00'};">
              {run.status === 'done' ? '' : run.status === 'failed' ? '' : '●'}
            </span>
            <span class="cli-output">{run.started_at?.slice(0, 16)} · {run.tables} table{run.tables !== 1 ? 's' : ''} · {run.status}</span>
            {#if run.finished_at && run.started_at}
              <span class="cli-dim" style="margin-left: auto;">{((new Date(run.finished_at).getTime() - new Date(run.started_at).getTime()) / 1000).toFixed(1)}s</span>
            {/if}
          </div>
          {#if run.error}
            <div class="cli-line" style="padding-left: 16px;"><span style="color: var(--pw-error); font-size: 10px;">{run.error.slice(0, 100)}</span></div>
          {/if}
        {/each}
      </div>
    {/if}

    <!-- Drift Alerts -->
    {#if driftAlerts.length > 0}
      <div style="font-size: 12px; font-weight: 900; text-transform: uppercase; margin-bottom: 8px;">DATA DRIFT ALERTS</div>
      <div style="display: flex; flex-direction: column; gap: 6px; margin-bottom: 16px;">
        {#each driftAlerts as da}
          <div class="ink-border" style="background: var(--pw-surface); padding: 10px 14px; border-left: 3px solid #cc7a00;">
            <div style="font-size: 11px; font-weight: 900;">{da.table_name}</div>
            {#each da.alerts as alert}
              <div style="font-size: 10px; color: #cc7a00; margin-top: 2px;"><Icon name="alert-triangle" size={14} /> {alert}</div>
            {/each}
            <div style="font-size: 11px; color: var(--pw-muted); margin-top: 4px;">{da.created_at?.slice(0, 16)}</div>
          </div>
        {/each}
      </div>
    {/if}

    <div style="font-size: 12px; font-weight: 900; text-transform: uppercase; margin-bottom: 8px; margin-top: 16px;">AGENT MEMORIES</div>
    <div class="flex gap-2 items-end mb-3">
      <input type="text" bind:value={newMemoryFact} placeholder="Add a fact the agent should remember..." style="flex: 1; border: 2px solid var(--pw-ink); padding: 5px 10px; font-family: var(--pw-font-body); font-size: 11px; background: var(--pw-surface);" />
      <select bind:value={newMemoryScope} style="border: 2px solid var(--pw-ink); padding: 5px 8px; font-family: var(--pw-font-body); font-size: 10px; background: var(--pw-surface);">
        <option value="project">PROJECT</option>
        <option value="personal">PERSONAL</option>
        <option value="global">GLOBAL</option>
      </select>
      <button class="feedback-btn" style="font-size: 11px; font-weight: 700; padding: 5px 10px;" onclick={async () => {
        if (!newMemoryFact) return;
        await fetch(`/api/projects/${slug}/memories`, { method: 'POST', headers: { ..._h(), 'Content-Type': 'application/json' }, body: JSON.stringify({ fact: newMemoryFact, scope: newMemoryScope }) });
        newMemoryFact = ''; await loadBrainData();
      }}>+ ADD</button>
    </div>
    {#if brainMemories.length > 0}
      <div class="cli-terminal" style="padding: 10px 14px; margin-bottom: 16px;">
        {#each brainMemories as m}
          <div class="cli-line">
            <span style="color: #cc7a00;">&#9679;</span>
            <span class="cli-output">{m.fact}</span>
            <span class="cli-dim" style="margin-left: auto; font-size: 11px;">{m.scope}</span>
            {#if canEdit}<button onclick={async () => { await fetch(`/api/projects/${slug}/memories/${m.id}`, { method: 'DELETE', headers: _h() }); await loadBrainData(); }} style="background: none; border: none; color: var(--pw-muted); cursor: pointer; font-size: 10px; margin-left: 4px;">&#10005;</button>{/if}
          </div>
        {/each}
      </div>
    {:else}
      <div style="font-size: 11px; color: var(--pw-muted); margin-bottom: 16px;">No memories yet. Add facts or chat with the agent — it learns automatically.</div>
    {/if}

    <!-- Proven Query Patterns -->
    {#if brainPatterns.length > 0}
      <div style="font-size: 12px; font-weight: 900; text-transform: uppercase; margin-bottom: 8px;">PROVEN QUERIES ({brainPatterns.length})</div>
      <div style="display: flex; flex-direction: column; gap: 6px; margin-bottom: 16px;">
        {#each brainPatterns.slice(0, 8) as p}
          <div class="ink-border" style="background: var(--pw-surface); padding: 10px 14px;">
            <div class="flex items-center justify-between">
              <div style="font-size: 11px; font-weight: 900; color: var(--pw-accent);">Q: {p.question}</div>
              <span style="font-size: 11px; color: var(--pw-muted);">used {p.uses}x</span>
            </div>
            <pre style="margin-top: 6px; padding: 10px 12px; font-family: var(--pw-font-mono, ui-monospace, SFMono-Regular, Menlo, monospace); font-size: 12px; line-height: 1.5; color: var(--pw-ink); background: var(--pw-bg-alt); border: 1px solid var(--pw-border); border-radius: var(--pw-radius-sm, 6px); white-space: pre-wrap; word-break: break-word; overflow-x: auto;">{p.sql}</pre>
          </div>
        {/each}
      </div>
    {/if}

    <!-- Feedback -->
    {#if brainFeedback.length > 0}
      <div style="font-size: 12px; font-weight: 900; text-transform: uppercase; margin-bottom: 8px;">USER FEEDBACK ({brainFeedback.length})</div>
      <div style="display: flex; flex-direction: column; gap: 6px; margin-bottom: 16px;">
        {#each brainFeedback.slice(0, 8) as f}
          <div class="ink-border" style="background: var(--pw-surface); padding: 10px 14px; border-left: 3px solid {f.rating === 'up' ? 'var(--pw-accent)' : 'var(--pw-error)'};">
            <div class="flex items-center gap-2">
              <span style="font-size: 13px;">{f.rating === 'up' ? '' : ''}</span>
              <div style="font-size: 11px; font-weight: 700;">Q: {f.question}</div>
            </div>
            {#if f.answer}<div style="font-size: 10px; color: var(--pw-muted); margin-top: 2px;">{f.answer?.slice(0, 150)}...</div>{/if}
          </div>
        {/each}
      </div>
    {/if}

    <!-- Training Q&A Pairs -->
    {#if training?.training_qa && training.training_qa.length > 0}
      <div style="font-size: 12px; font-weight: 900; text-transform: uppercase; margin-bottom: 8px;">TRAINING Q&A PAIRS</div>
      <div style="display: flex; flex-direction: column; gap: 6px; margin-bottom: 16px;">
        {#each training.training_qa as qa}
          <div class="ink-border" style="background: var(--pw-surface); padding: 10px 14px;">
            <div style="font-size: 11px; font-weight: 900; color: var(--pw-accent);">Q: {qa.question}</div>
            <div class="cli-terminal" style="margin-top: 4px; padding: 6px 10px; font-size: 10px;">
              <code style="color: var(--pw-border);">{qa.sql}</code>
            </div>
            {#if qa.source_table}
              <div style="font-size: 11px; color: var(--pw-muted); margin-top: 3px; text-transform: uppercase;">TABLE: {qa.source_table}</div>
            {/if}
          </div>
        {/each}
      </div>
    {/if}

    {#if !training?.training_qa?.length && !brainFeedback.filter(f => f.rating === 'up').length && !brainPatterns.length && !brainMemories.length}
      <div style="text-align: center; padding: 30px; color: var(--pw-muted); font-size: 11px;">
        No training data yet. Upload data or click RETRAIN AGENT. Chat with the agent and use thumbs up/down to teach it.
      </div>
    {/if}

    <!-- Self-Evolution Section Divider -->
    <div style="margin-top: 30px; border-top: 3px solid var(--pw-ink); padding-top: 16px; margin-bottom: 16px;">
      <div style="font-size: 13px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.1em; color: var(--pw-accent);">SELF-EVOLUTION</div>
      <div style="font-size: 10px; color: var(--pw-muted); margin-top: 2px;">Auto-learned from your conversations. Updates after each chat.</div>
    </div>

    <!-- Self-Evolution: Proactive Insights -->
    <div style="margin-top: 12px; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px;">PROACTIVE INSIGHTS</div>
    {#if insights.length > 0}
      {#each insights as ins}
        <div class="ink-border" style="padding: 8px 14px; margin-bottom: 6px; background: {ins.severity === 'critical' ? 'var(--pw-error-soft)' : ins.severity === 'warning' ? '#fff4d4' : 'var(--pw-surface)'}; display: flex; align-items: center; gap: 8px;">
          <span style="font-size: 11px; font-weight: 900; padding: 1px 6px; background: {ins.severity === 'critical' ? 'var(--pw-error)' : ins.severity === 'warning' ? '#cc7a00' : 'var(--pw-accent)'}; color: white; text-transform: uppercase;">{ins.severity}</span>
          <span style="flex: 1; font-size: 11px;">{ins.insight}</span>
          <button class="feedback-btn" onclick={async () => { await fetch(`/api/projects/${slug}/insights/${ins.id}/dismiss`, { method: 'POST', headers: _h() }); insights = insights.filter(i => i.id !== ins.id); }} style="font-size: 11px; padding: 2px 8px;">Dismiss</button>
        </div>
      {/each}
    {:else}
      <div style="font-size: 10px; color: var(--pw-muted);">No anomalies detected yet. Chat with the agent to generate insights.</div>
    {/if}

    <!-- Self-Evolution: User Preferences -->
    <div style="margin-top: 20px; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px;">USER PREFERENCES (auto-tracked)</div>
    {#if Object.keys(userPreferences).length > 0}
      <div style="display: flex; gap: 12px; flex-wrap: wrap;">
        {#if userPreferences.chart_type_counts}
          <div class="ink-border" style="padding: 10px 14px; background: var(--pw-surface); flex: 1; min-width: 200px;">
            <div style="font-size: 11px; font-weight: 900; text-transform: uppercase; color: var(--pw-muted); margin-bottom: 6px;">CHART TYPE CLICKS</div>
            {#each Object.entries(userPreferences.chart_type_counts) as [type, count]}
              <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 3px;">
                <span style="font-size: 11px; font-weight: 700; width: 60px; text-transform: uppercase;">{type}</span>
                <div style="flex: 1; height: 8px; background: var(--pw-bg-alt);"><div style="height: 100%; background: var(--pw-accent); width: {Math.min(100, Number(count) * 10)}%;"></div></div>
                <span style="font-size: 10px; font-weight: 900; width: 24px; text-align: right;">{count}</span>
              </div>
            {/each}
          </div>
        {/if}
        {#if userPreferences.tab_click_counts}
          <div class="ink-border" style="padding: 10px 14px; background: var(--pw-surface); flex: 1; min-width: 200px;">
            <div style="font-size: 11px; font-weight: 900; text-transform: uppercase; color: var(--pw-muted); margin-bottom: 6px;">TAB CLICKS</div>
            {#each Object.entries(userPreferences.tab_click_counts) as [tab, count]}
              <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 3px;">
                <span style="font-size: 11px; font-weight: 700; width: 60px; text-transform: uppercase;">{tab}</span>
                <div style="flex: 1; height: 8px; background: var(--pw-bg-alt);"><div style="height: 100%; background: var(--pw-accent-ink); width: {Math.min(100, Number(count) * 10)}%;"></div></div>
                <span style="font-size: 10px; font-weight: 900; width: 24px; text-align: right;">{count}</span>
              </div>
            {/each}
          </div>
        {/if}
      </div>
    {:else}
      <div style="font-size: 10px; color: var(--pw-muted);">No preferences tracked yet. Use the chat — click tabs and chart types to build your profile.</div>
    {/if}

    <!-- Self-Evolution: Meta-Learning -->
    <div style="margin-top: 20px; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px;">SELF-CORRECTION STRATEGIES (auto-learned)</div>
    {#if metaLearnings.length > 0}
      <div style="overflow-x: auto;">
        <table class="data-table" style="font-size: 11px;">
          <thead><tr><th>ERROR TYPE</th><th>FIX STRATEGY</th><th>SUCCESS RATE</th><th>ATTEMPTS</th></tr></thead>
          <tbody>
            {#each metaLearnings as ml}
              <tr>
                <td><code style="font-size: 10px;">{ml.error_type}</code></td>
                <td><code style="font-size: 10px;">{ml.fix_strategy}</code></td>
                <td><span style="font-weight: 900; color: {ml.success_rate >= 70 ? 'var(--pw-accent)' : ml.success_rate >= 40 ? '#cc7a00' : 'var(--pw-error)'};">{ml.success_rate}%</span></td>
                <td>{ml.count}</td>
              </tr>
            {/each}
          </tbody>
        </table>
      </div>
    {:else}
      <div style="font-size: 10px; color: var(--pw-muted);">No self-correction data yet. The agent learns fix strategies as it encounters and resolves errors.</div>
    {/if}

    <!-- Self-Evolution: Knowledge Consolidation -->
    <div style="margin-top: 20px; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px;">KNOWLEDGE CONSOLIDATION</div>
    <div class="ink-border" style="padding: 12px 14px; background: var(--pw-surface); display: flex; align-items: center; gap: 12px;">
      <div style="flex: 1;">
        <div style="font-size: 11px;"><strong>{consolidationStatus.memory_count}</strong> memories</div>
        <div style="font-size: 10px; color: var(--pw-muted);">{consolidationStatus.eligible ? 'Ready to consolidate — compress into higher-level insights' : 'Need 30+ memories to consolidate'}</div>
      </div>
      <button class="send-btn" disabled={!consolidationStatus.eligible || consolidating} style="font-size: 10px; padding: 6px 14px;" onclick={async () => {
        consolidating = true;
        cLog(`${ts()} ── consolidating ${consolidationStatus.memory_count} memories...`);
        try {
          const r = await fetch(`/api/projects/${slug}/consolidate-knowledge`, { method: 'POST', headers: _h() });
          const d = await r.json();
          if (d.status === 'ok') { cLog(`${ts()} │ ${d.archived} memories → ${d.consolidated} insights`); loadConsolidationStatus(); loadBrainData(); }
          else cLog(`${ts()} │ ${d.detail || 'failed'}`);
        } catch {} finally { consolidating = false; }
      }}>{consolidating ? 'CONSOLIDATING...' : 'CONSOLIDATE'}</button>
    </div>

  <!-- ═══ DOCS ═══ -->
  {:else if activeTab === 'docs'}
    <div class="cli-terminal" style="margin-bottom: 16px; padding: 8px 14px;">
      <div class="cli-line">
        <span class="cli-prompt">$</span>
        <span class="cli-command">dash docs</span>
        <span class="cli-output">--list</span>
        <span class="cli-dim" style="margin-left: auto;">{docs.length} files · {(docs.reduce((s: number, d: any) => s + (d.size || 0), 0) / 1024).toFixed(1)} KB</span>
      </div>
    </div>
    <div class="flex items-center justify-between mb-4">
      <div style="font-size: 16px; font-weight: 900; text-transform: uppercase;">Documents</div>
      <button class="send-btn" onclick={() => { showDocUpload = true; docFile = null; docResult = null; }} style="padding: 6px 14px; font-size: 10px; cursor: pointer;">+ ADD DOC</button>
    </div>
    <div style="font-size: 11px; color: var(--pw-muted); margin-bottom: 12px;">Upload SQL, Python, or text files to give the agent business context.</div>
    {#if docs.length > 0}
      {#each docs as d}
        <div class="flex items-center justify-between py-2" style="border-bottom: 1px solid var(--pw-bg-alt); font-size: 11px;">
          <div class="flex items-center gap-2"><span style="font-weight: 900;">{d.name}</span><span class="tag-label" style="font-size: 7px; padding: 1px 4px;">{d.type}</span></div>
          <div class="flex items-center gap-3">
            {#if ['.pptx', '.pdf', '.docx'].includes(d.type)}
              {#if docWorkflowCreated.has(d.name)}
                <span style="font-size: 11px; font-weight: 900; color: var(--pw-accent); text-transform: uppercase; letter-spacing: 0.05em;"><Icon name="check" size={14} /> WORKFLOW</span>
              {:else}
                <button class="feedback-btn" style="font-size: 11px; padding: 2px 8px; cursor: pointer; font-weight: 900; text-transform: uppercase;"
                  disabled={docToWorkflowLoading === d.name}
                  onclick={async () => {
                    docToWorkflowLoading = d.name;
                    try {
                      const r = await fetch(`/api/projects/${slug}/doc-to-workflow`, {
                        method: 'POST', headers: { ..._h(), 'Content-Type': 'application/json' },
                        body: JSON.stringify({ filename: d.name })
                      });
                      if (r.ok) {
                        const data = await r.json();
                        docWorkflowPreview = data.workflow;
                      } else {
                        const err = await r.json().catch(() => ({}));
                        alert(err.detail || 'Failed to extract workflow');
                      }
                    } catch { alert('Failed to extract workflow'); }
                    docToWorkflowLoading = null;
                  }}>{docToWorkflowLoading === d.name ? 'EXTRACTING...' : '→ WORKFLOW'}</button>
              {/if}
            {/if}
            <span style="color: var(--pw-muted); font-size: 10px;">{(d.size / 1024).toFixed(1)} KB</span>
            {#if canEdit}<button class="feedback-btn" style="font-size: 11px; color: var(--pw-error); border-color: var(--pw-error); padding: 2px 8px; cursor: pointer;" onclick={() => deleteDoc(d.name)}>Del</button>{/if}
          </div>
        </div>
      {/each}
    {:else}<div style="font-size: 11px; color: var(--pw-muted);">No documents. Add SQL files or business docs for richer context.</div>{/if}

    {#if investmentMemos.length > 0}
      <div class="docs-section" style="margin-top: 28px;">
        <div style="font-size: 13px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 12px; display: flex; align-items: center; gap: 8px;">
          <span><Icon name="briefcase" size={14} /> Generated IC Memos</span>
          <span style="font-size: 10px; color: var(--pw-muted); font-weight: 600;">({investmentMemos.length})</span>
        </div>
        <div class="memo-list" style="display: flex; flex-direction: column; gap: 6px;">
          {#each investmentMemos as m}
            <div class="memo-row" style="display: grid; grid-template-columns: 90px 70px 90px 1fr auto auto; gap: 12px; align-items: center; padding: 8px 12px; border: 1px solid var(--pw-bg-alt); background: var(--pw-surface); font-size: 11px;">
              <span class="memo-symbol" style="font-family: 'SF Mono', Menlo, monospace; font-weight: 700;">{m.symbol || m.target || '—'}</span>
              <span class="memo-verdict verdict-{(m.verdict || '').toLowerCase()}" style="font-size: 10px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.05em; padding: 3px 7px; border-radius: 0; text-align: center; background: {m.verdict === 'BUY' ? 'rgba(34,197,94,0.14)' : m.verdict === 'HOLD' ? 'rgba(245,158,11,0.14)' : m.verdict === 'SELL' ? 'rgba(239,68,68,0.14)' : 'rgba(120,113,108,0.14)'}; color: {m.verdict === 'BUY' ? '#16a34a' : m.verdict === 'HOLD' ? '#d97706' : m.verdict === 'SELL' ? '#dc2626' : '#57534e'};">{m.verdict || '—'}</span>
              <span class="memo-conviction" style="color: #d97706; letter-spacing: 1.5px;">{''.repeat(Math.max(0, Math.min(5, m.conviction || 0)))}</span>
              <span class="memo-date" style="color: var(--pw-muted); font-size: 11px;">{memoRelTime(m.created_at)}</span>
              <button class="feedback-btn" style="font-size: 11px; padding: 3px 10px; cursor: pointer;" onclick={() => viewInvestmentMemo(m.id)}>VIEW</button>
              <button class="feedback-btn" style="font-size: 11px; padding: 3px 10px; cursor: pointer;" onclick={() => exportInvestmentMemoPdf(m.id)}>PDF</button>
            </div>
          {/each}
        </div>
      </div>
    {/if}

    <!-- Doc-to-Workflow Preview Modal -->
    {#if docWorkflowPreview}
      <div style="position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: 999; display: flex; align-items: center; justify-content: center;"
        onclick={(e) => { if (e.target === e.currentTarget) docWorkflowPreview = null; }}>
        <div class="ink-border stamp-shadow" style="background: var(--pw-surface); width: 560px; max-height: 80vh; overflow-y: auto;">
          <div class="dark-title-bar" style="padding: 8px 14px; font-size: 11px; display: flex; justify-content: space-between; align-items: center;">
            <span>WORKFLOW PREVIEW — {docWorkflowPreview.source_file || ''}</span>
            <button onclick={() => docWorkflowPreview = null} style="background: none; border: none; color: var(--pw-accent-soft); cursor: pointer; font-size: 13px;">&times;</button>
          </div>
          <div style="padding: 16px;">
            <div style="margin-bottom: 12px;">
              <label style="font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; display: block; margin-bottom: 4px;">Workflow Name</label>
              <input type="text" bind:value={docWorkflowPreview.name} style="width: 100%; padding: 6px 10px; font-size: 12px; border: 1px solid var(--pw-bg-alt); font-family: var(--pw-font-body); background: var(--pw-surface);" />
            </div>
            <div style="margin-bottom: 12px;">
              <label style="font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; display: block; margin-bottom: 4px;">Description</label>
              <input type="text" bind:value={docWorkflowPreview.description} style="width: 100%; padding: 6px 10px; font-size: 12px; border: 1px solid var(--pw-bg-alt); font-family: var(--pw-font-body); background: var(--pw-surface);" />
            </div>
            <div style="margin-bottom: 12px;">
              <label style="font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; display: block; margin-bottom: 8px;">Steps ({docWorkflowPreview.steps?.length || 0})</label>
              {#each docWorkflowPreview.steps || [] as step, i}
                <div class="flex items-center gap-2 mb-2" style="border-left: 2px solid var(--pw-accent); padding-left: 8px;">
                  <span style="font-size: 10px; font-weight: 900; color: var(--pw-muted); min-width: 18px;">{i + 1}</span>
                  <input type="text" bind:value={step.question} style="flex: 1; padding: 5px 8px; font-size: 11px; border: 1px solid var(--pw-bg-alt); font-family: var(--pw-font-body); background: var(--pw-surface);" />
                  <button onclick={() => { docWorkflowPreview.steps = docWorkflowPreview.steps.filter((_: any, j: number) => j !== i); docWorkflowPreview = docWorkflowPreview; }}
                    style="background: none; border: none; cursor: pointer; font-size: 11px; color: var(--pw-error); padding: 2px;">&times;</button>
                </div>
              {/each}
            </div>
            <div class="flex justify-end gap-2">
              <button class="feedback-btn" style="padding: 6px 14px; font-size: 10px; cursor: pointer;" onclick={() => docWorkflowPreview = null}>Cancel</button>
              <button class="send-btn" style="padding: 6px 14px; font-size: 10px; cursor: pointer;"
                onclick={async () => {
                  const steps = (docWorkflowPreview.steps || []).map((s: any) => typeof s === 'string' ? s : s.question || s.title || String(s));
                  try {
                    const r = await fetch(`/api/projects/${slug}/workflows-db`, {
                      method: 'POST', headers: { ..._h(), 'Content-Type': 'application/json' },
                      body: JSON.stringify({ name: docWorkflowPreview.name, description: docWorkflowPreview.description, steps, source: 'document' })
                    });
                    if (r.ok) {
                      const sourceFile = docWorkflowPreview.source_file;
                      docWorkflowCreated = new Set([...docWorkflowCreated, sourceFile]);
                      docWorkflowPreview = null;
                      loadWorkflows();
                    } else {
                      const err = await r.json().catch(() => ({}));
                      alert(err.detail || 'Failed to save workflow');
                    }
                  } catch { alert('Failed to save workflow'); }
                }}>SAVE WORKFLOW</button>
            </div>
          </div>
        </div>
      </div>
    {/if}

  <!-- ═══ QUERIES ═══ -->
  {:else if activeTab === 'queries'}
    <div class="cli-terminal" style="margin-bottom: 16px; padding: 8px 14px;">
      <div class="cli-line">
        <span class="cli-prompt">$</span>
        <span class="cli-command">dash queries</span>
        <span class="cli-output">--all</span>
        <span class="cli-dim" style="margin-left: auto;">{brainPatterns.length} patterns · {queryPlans.length} join strategies</span>
      </div>
    </div>

    <!-- Proven Query Patterns from DB -->
    <div style="font-size: 16px; font-weight: 900; text-transform: uppercase; margin-bottom: 16px;">Query Patterns ({brainPatterns.length})</div>
    {#if brainPatterns.length > 0}
      <div style="overflow-x: auto; margin-bottom: 20px;">
        <table class="data-table" style="font-size: 11px; width: 100%;">
          <thead>
            <tr>
              <th style="text-align: left;">QUESTION</th>
              <th>TABLES</th>
              <th>USES</th>
              <th>SOURCE</th>
            </tr>
          </thead>
          <tbody>
            {#each brainPatterns as p}
              <tr>
                <td style="max-width: 400px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">{p.question || p.sql?.slice(0, 60)}</td>
                <td style="text-align: center; font-size: 10px;">{p.tables_used || '—'}</td>
                <td style="text-align: center;">{p.uses || 1}</td>
                <td style="text-align: center;">
                  <span style="font-size: 7px; font-weight: 900; padding: 1px 5px; background: {p.source === 'training' ? '#cc7a00' : p.source === 'sql_file' ? '#6366f1' : 'var(--pw-accent)'}; color: white; text-transform: uppercase;">{p.source || 'user'}</span>
                </td>
              </tr>
            {/each}
          </tbody>
        </table>
      </div>
    {:else}
      <div style="font-size: 11px; color: var(--pw-muted); margin-bottom: 20px;">No query patterns yet. Train the agent or chat to auto-generate SQL patterns.</div>
    {/if}

    <!-- File-based saved queries -->
    {#if knowledgeFiles.filter(f => f.type === 'queries').length > 0}
      <div style="font-size: 12px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px;">SAVED SQL FILES</div>
      {#each knowledgeFiles.filter(f => f.type === 'queries') as f}
        {#await fetch(`/api/knowledge-file-content/${f.name}?project=${slug}&subdir=queries`, { headers: _h() }).then(r => r.json()) then data}
          {#if data.content}
            <div class="ink-border mb-3" style="background: var(--pw-surface);">
              <div class="dark-title-bar" style="padding: 6px 12px; font-size: 10px;">{f.name}</div>
              <pre style="padding: 12px; font-size: 11.5px; font-family: 'SF Mono', Menlo, Consolas, monospace; overflow-x: auto; background: #1a1614; color: #e8e3d6; margin: 0; white-space: pre-wrap; line-height: 1.55;">{data.content}</pre>
            </div>
          {/if}
        {/await}
      {/each}
    {/if}

    <!-- Query Plan Memory -->
    {#if queryPlans.length > 0}
      <div style="margin-top: 16px; font-size: 12px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px;">PROVEN JOIN STRATEGIES</div>
      <div style="overflow-x: auto;">
        <table class="data-table" style="font-size: 10px;">
          <thead><tr><th>TABLES</th><th>JOIN STRATEGY</th><th>FILTERS</th><th>STATUS</th></tr></thead>
          <tbody>
            {#each queryPlans as plan}
              <tr>
                <td><code>{plan.tables?.join(', ')}</code></td>
                <td style="max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">{plan.join_strategy || '—'}</td>
                <td style="max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">{plan.filters || '—'}</td>
                <td><span style="font-size: 11px; font-weight: 900; padding: 1px 6px; background: {plan.success ? 'var(--pw-accent)' : 'var(--pw-error)'}; color: white;">{plan.success ? 'OK' : 'FAIL'}</span></td>
              </tr>
            {/each}
          </tbody>
        </table>
      </div>
    {/if}

  <!-- ═══ LINEAGE ═══ -->
  {:else if activeTab === 'lineage'}
    <LineageTab
      {detail}
      {lineage}
      {relationships}
      {kgTriples}
      {brainMemories}
      {tableInspectCache}
      {tableMetaCache}
      {rules}
    />


  <!-- ═══ AGENTS ═══ -->
  {:else if activeTab === 'agents'}
    <!-- Sub-tab switcher -->
    <div style="display:flex; gap:4px; margin-bottom:12px; border-bottom:1px solid var(--pw-ink-soft);">
      <button
        class="cli-info"
        onclick={() => { agentsSubTab = 'list'; }}
        style="padding:6px 14px; background:{agentsSubTab==='list' ? 'var(--pw-ink)' : 'transparent'}; border:none; border-bottom:2px solid {agentsSubTab==='list' ? 'var(--pw-accent)' : 'transparent'}; color:{agentsSubTab==='list' ? 'var(--pw-accent)' : 'var(--pw-dim)'}; cursor:pointer; font-family:inherit; font-size:11px;">
        AGENT LIST
      </button>
      <button
        class="cli-info"
        onclick={() => { agentsSubTab = 'health'; if (toolHealth.length === 0) loadToolHealth(); }}
        style="padding:6px 14px; background:{agentsSubTab==='health' ? 'var(--pw-ink)' : 'transparent'}; border:none; border-bottom:2px solid {agentsSubTab==='health' ? 'var(--pw-accent)' : 'transparent'}; color:{agentsSubTab==='health' ? 'var(--pw-accent)' : 'var(--pw-dim)'}; cursor:pointer; font-family:inherit; font-size:11px;">
        TOOL HEALTH
      </button>
      <button
        class="cli-info"
        onclick={() => { agentsSubTab = 'transfer'; if (srTransferCandidates.length === 0) loadSrTransferCandidates(); }}
        style="padding:6px 14px; background:{agentsSubTab==='transfer' ? 'var(--pw-ink)' : 'transparent'}; border:none; border-bottom:2px solid {agentsSubTab==='transfer' ? 'var(--pw-accent)' : 'transparent'}; color:{agentsSubTab==='transfer' ? 'var(--pw-accent)' : 'var(--pw-dim)'}; cursor:pointer; font-family:inherit; font-size:11px;">
        TRANSFER
      </button>
    </div>

    {#if agentsSubTab === 'transfer'}
      <div class="cli-terminal" style="padding:10px 14px;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px;">
          <div>
            <span class="cli-prompt">$</span>
            <span class="cli-command">dash refine-tools</span>
            <span class="cli-output">--transfer --siblings</span>
          </div>
          <button onclick={loadSrTransferCandidates} disabled={loadingTransfer}
            style="padding:4px 10px; background:var(--pw-ink); border:1px solid var(--pw-accent); color:var(--pw-accent); cursor:pointer; font-family:inherit; font-size:10px;">
            {loadingTransfer ? 'SCANNING…' : 'RE-SCAN'}
          </button>
        </div>
        <div class="cli-dim" style="font-size:10px; margin-bottom:14px; line-height:1.5;">
          Sibling projects (same user, ≥20% column overlap) with applied patches you don't have yet. Confidence = overlap × shadow × score gain.
        </div>
        {#if srTransferCandidates.length === 0 && !loadingTransfer}
          <div class="cli-dim" style="text-align:center; padding:20px;">No transferable patches available.</div>
        {/if}
        {#each srTransferCandidates as cand}
          <div style="margin-bottom:14px; padding:10px; background:var(--pw-ink); border-left:2px solid #66aaff;">
            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">
              <div>
                <span style="color:#66aaff; font-weight:700; font-size:12px;">{cand.source_name || cand.source_slug}</span>
                <span class="cli-dim" style="margin-left:8px; font-size:10px;">{cand.source_slug}</span>
              </div>
              <div>
                <span style="color:var(--pw-accent); font-weight:700;">{cand.overlap_pct}%</span>
                <span class="cli-dim" style="font-size:10px; margin-left:4px;">overlap</span>
              </div>
            </div>
            <div class="cli-dim" style="font-size: 11px; margin-bottom:8px;">
              shared cols: {cand.shared_columns.slice(0,8).join(', ')}{cand.shared_columns.length > 8 ? '…' : ''}
            </div>
            <table style="width:100%; border-collapse:collapse; font-size:11px;">
              <thead>
                <tr style="border-bottom:1px solid var(--pw-ink-soft); color:var(--pw-dim);">
                  <th style="text-align:left; padding:4px 6px;">TOOL</th>
                  <th style="text-align:right; padding:4px 6px;">CONF</th>
                  <th style="text-align:right; padding:4px 6px;">SHADOW</th>
                  <th style="text-align:right; padding:4px 6px;">SCORE</th>
                  <th style="text-align:left; padding:4px 6px;">REASON</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {#each cand.patches as p}
                  <tr style="border-bottom:1px dotted var(--pw-ink-soft);">
                    <td style="padding:4px 6px; color:var(--pw-accent);">{p.tool_name}</td>
                    <td style="padding:4px 6px; text-align:right; color:{scoreColor(p.confidence)}; font-weight:700;">{p.confidence}%</td>
                    <td style="padding:4px 6px; text-align:right; color:var(--pw-dim);">{p.shadow_pass_rate ? Number(p.shadow_pass_rate).toFixed(0) + '%' : '—'}</td>
                    <td style="padding:4px 6px; text-align:right; color:var(--pw-dim);">
                      {#if p.score_before !== null}{Number(p.score_before).toFixed(0)}{p.score_after !== null ? '→' + Number(p.score_after).toFixed(0) : ''}{:else}—{/if}
                    </td>
                    <td style="padding:4px 6px; color:var(--pw-dim); max-width:280px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">{(p.reason || '').slice(0,80)}</td>
                    <td style="padding:4px 6px; text-align:right;">
                      <button onclick={() => importTransferPatch(p.id, false)} disabled={importing === p.id}
                        style="padding:3px 8px; background:#0d1a2a; border:1px solid #66aaff; color:#66aaff; cursor:pointer; font-family:inherit; font-size: 11px; margin-right:4px;">
                        {importing === p.id ? '…' : 'IMPORT'}
                      </button>
                      <button onclick={() => importTransferPatch(p.id, true)} disabled={importing === p.id}
                        style="padding:3px 8px; background:var(--pw-success); border:1px solid var(--pw-accent); color:var(--pw-accent); cursor:pointer; font-family:inherit; font-size: 11px;">
                        IMPORT+APPLY
                      </button>
                    </td>
                  </tr>
                {/each}
              </tbody>
            </table>
          </div>
        {/each}
      </div>
    {:else if agentsSubTab === 'health'}
      <div class="cli-terminal" style="padding:10px 14px;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px;">
          <div>
            <span class="cli-prompt">$</span>
            <span class="cli-command">dash refine-tools</span>
            <span class="cli-output">--score --window=14d</span>
          </div>
          <button onclick={recomputeToolHealth} disabled={toolHealthLoading}
            style="padding:4px 10px; background:var(--pw-ink); border:1px solid var(--pw-accent); color:var(--pw-accent); cursor:pointer; font-family:inherit; font-size:10px;">
            {toolHealthLoading ? 'COMPUTING…' : 'RECOMPUTE'}
          </button>
        </div>
        {#if toolHealth.length === 0 && !toolHealthLoading}
          <div class="cli-dim" style="padding:20px 0; text-align:center;">No telemetry yet. Tools score after first invocations.</div>
        {:else}
          <table style="width:100%; border-collapse:collapse; font-size:11px;">
            <thead>
              <tr style="border-bottom:1px solid var(--pw-ink-soft); color:var(--pw-dim);">
                <th style="text-align:left; padding:6px 8px;">TOOL</th>
                <th style="text-align:right; padding:6px 8px;">SCORE</th>
                <th style="text-align:right; padding:6px 8px;">CALLS</th>
                <th style="text-align:right; padding:6px 8px;">FAILS</th>
                <th style="text-align:right; padding:6px 8px;">FAIL%</th>
                <th style="text-align:right; padding:6px 8px;">P50</th>
                <th style="text-align:right; padding:6px 8px;">P95</th>
                <th style="text-align:left; padding:6px 8px;">LAST ERROR</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {#each toolHealth as t}
                {@const failPct = t.calls > 0 ? Math.round((t.fails / t.calls) * 100) : 0}
                <tr style="border-bottom:1px solid var(--pw-ink); cursor:pointer;" onclick={() => toggleToolDetail(t.tool_name)}>
                  <td style="padding:6px 8px; color:var(--pw-accent);">{t.tool_name}</td>
                  <td style="padding:6px 8px; text-align:right; color:{scoreColor(Number(t.score))}; font-weight:700;">{Number(t.score).toFixed(1)}</td>
                  <td style="padding:6px 8px; text-align:right; color:var(--pw-dim);">{t.calls}</td>
                  <td style="padding:6px 8px; text-align:right; color:{t.fails > 0 ? '#cc7a00' : 'var(--pw-dim)'};">{t.fails}</td>
                  <td style="padding:6px 8px; text-align:right; color:{failPct > 20 ? 'var(--pw-error)' : 'var(--pw-dim)'};">{failPct}%</td>
                  <td style="padding:6px 8px; text-align:right; color:var(--pw-dim);">{t.latency_p50_ms}ms</td>
                  <td style="padding:6px 8px; text-align:right; color:var(--pw-dim);">{t.latency_p95_ms}ms</td>
                  <td style="padding:6px 8px; color:var(--pw-error); max-width:300px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">{t.last_error || ''}</td>
                  <td style="padding:6px 8px; text-align:right;">
                    {#if Number(t.score) < 60}
                      <button onclick={(e) => { e.stopPropagation(); proposePatch(t.tool_name); }}
                        disabled={proposingPatch === t.tool_name}
                        style="padding:3px 8px; background:var(--pw-ink); border:1px solid var(--pw-error); color:var(--pw-error); cursor:pointer; font-family:inherit; font-size: 11px;">
                        {proposingPatch === t.tool_name ? '…' : 'PROPOSE PATCH'}
                      </button>
                    {/if}
                  </td>
                </tr>
                {#if expandedTool === t.tool_name}
                  <tr><td colspan="9" style="padding:8px 14px; background:var(--pw-ink); border-bottom:1px solid var(--pw-ink);">
                    <div style="display:grid; grid-template-columns:1fr 1fr; gap:14px;">
                      <div>
                        <div class="cli-info" style="margin-bottom:6px;">RECENT FAILURES (last 10)</div>
                        {#if !toolFailures[t.tool_name]}
                          <div class="cli-dim">loading…</div>
                        {:else if toolFailures[t.tool_name].length === 0}
                          <div class="cli-dim">no failure history</div>
                        {:else}
                          {#each toolFailures[t.tool_name] as f}
                            <div style="padding:3px 0; border-bottom:1px dotted var(--pw-ink); font-size:10px;">
                              <span class="cli-dim">{new Date(f.ts).toLocaleString()}</span>
                              <span style="color:#cc7a00; margin-left:8px;">{f.error_class || 'Error'}</span>
                              <span style="color:var(--pw-dim); margin-left:8px;">{(f.error_message || '').slice(0,80)}</span>
                            </div>
                          {/each}
                        {/if}
                      </div>
                      <div>
                        <div class="cli-info" style="margin-bottom:6px;">PATCH HISTORY</div>
                        {#if !toolHistory[t.tool_name]}
                          <div class="cli-dim">loading…</div>
                        {:else if toolHistory[t.tool_name].length === 0}
                          <div class="cli-dim">no patches yet</div>
                        {:else}
                          {#each toolHistory[t.tool_name] as p}
                            <div style="padding:4px 0; border-bottom:1px dotted var(--pw-ink); font-size:10px;">
                              <span style="color:var(--pw-accent); font-weight:700;">v{p.version}</span>
                              <span style="margin-left:6px; padding:1px 5px; background:{p.reverted ? 'var(--pw-ink)' : (p.applied ? 'var(--pw-success)' : 'var(--pw-ink-soft)')}; color:{p.reverted ? 'var(--pw-error)' : (p.applied ? 'var(--pw-accent)' : 'var(--pw-dim)')}; font-size: 11px;">
                                {p.reverted ? 'REVERTED' : (p.applied ? 'ACTIVE' : 'DRAFT')}
                              </span>
                              <span style="margin-left:6px; padding:1px 5px; background:var(--pw-ink); color:var(--pw-dim); font-size: 11px;">{p.source}</span>
                              {#if p.shadow_pass_rate !== null && p.shadow_pass_rate !== undefined}
                                <span class="cli-dim" style="margin-left:6px;">shadow {Number(p.shadow_pass_rate).toFixed(0)}%</span>
                              {/if}
                              {#if p.score_before !== null}
                                <span class="cli-dim" style="margin-left:6px;">{Number(p.score_before).toFixed(0)}{p.score_after !== null ? '→' + Number(p.score_after).toFixed(0) : '→…'}</span>
                              {/if}
                              {#if p.reason}
                                <div style="color:var(--pw-dim); font-size: 11px; margin-top:2px; line-height:1.3;">{(p.reason || '').slice(0,120)}</div>
                              {/if}
                              {#if p.revert_reason}
                                <div style="color:var(--pw-error); font-size: 11px; margin-top:2px;">↺ {p.revert_reason}</div>
                              {/if}
                            </div>
                          {/each}
                        {/if}
                      </div>
                    </div>
                  </td></tr>
                {/if}
              {/each}
            </tbody>
          </table>
        {/if}
      </div>
    {:else}
    {@const _agents = (agentsData?.agents || []) as any[]}
    {@const _coreNames = ['Leader','Analyst','Engineer','Researcher','Customer Strategist']}
    {@const _core = _agents.filter((a:any) => (a.category ? a.category === 'core' : (_coreNames.includes(a.name) || a.type === 'coordinator' || a.type === 'member'))).sort((a:any,b:any) => {const ia = _coreNames.indexOf(a.name); const ib = _coreNames.indexOf(b.name); return (ia < 0 ? 99 : ia) - (ib < 0 ? 99 : ib);})}
    {@const _specs = _agents.filter((a:any) => (a.category ? a.category === 'specialist' : (a.type === 'specialist' && !_coreNames.includes(a.name))))}
    {@const _extended = _agents.filter((a:any) => a.category === 'extended')}
    {@const _investment = _agents.filter((a:any) => a.category === 'investment')}
    {@const _background = _agents.filter((a:any) => a.category === 'background')}
    {@const _upload = _agents.filter((a:any) => a.category === 'upload')}
    {@const _routing = _agents.filter((a:any) => a.category === 'routing')}
    {@const _stateOf = (a:any) => a.state || (a.status === 'active' ? 'active' : 'ready')}
    {@const _activeN = _agents.filter((a:any) => _stateOf(a) === 'active').length}
    {@const _readyN = _agents.filter((a:any) => _stateOf(a) === 'ready').length}
    {@const _needN = _agents.filter((a:any) => _stateOf(a) === 'needs_setup').length}
    {@const _errN = _agents.filter((a:any) => _stateOf(a) === 'error').length}

    <!-- Slim CLI banner -->
    <div style="background: #1a1614; color: #e8e3d6; padding: 10px 16px; font-family: 'SF Mono', Menlo, Consolas, monospace; font-size: 11.5px; line-height: 1.7; border: 1px solid #2c2a26; border-radius: 0; margin-bottom: 14px; display: flex; flex-wrap: wrap; gap: 18px; align-items: center;">
      <span><span style="color: #c96342;">$</span> dash agents · <span style="color: #e8e3d6;">{project?.agent_name || 'Agent'}</span></span>
      <span style="color: #888;">model <span style="color: #f9a374;">{(detail?.model || 'gemini-3.1-flash-lite').split('/').pop()}</span></span>
      <span style="color: #888;">schema <span style="color: #e8e3d6;">{slug}</span></span>
      <span style="color: #888;">|  <span style="color: #10b981;">●{_activeN}</span> active · <span style="color: #3a8dff;">◐{_readyN}</span> ready · <span style="color: #888;">○{_needN}</span> idle · <span style="color: #ff4040;"><Icon name="x" size={14} />{_errN}</span> err · total <span style="color: #e8e3d6;">{_agents.length}</span></span>
      <span style="color: #888; margin-left: auto;">FAST <span style="color: #f9a374;">direct SQL</span> · DEEP <span style="color: #a78bfa;">think+analyze</span></span>
    </div>

    {@const _labelOf = (s:string) => s === 'active' ? 'ACTIVE' : s === 'ready' ? 'READY' : s === 'error' ? 'ERROR' : 'IDLE'}

    <!-- ORG DIAGRAM (collapsible ASCII tree, dark CLI aesthetic) -->
