          ↳ Specialists ({_specs.length}) — tools on Analyst, auto-fire by keyword
        </div>
        {#each _specs as a}
          {@const st = _stateOf(a)}
          {@const col = st === 'active' ? '#10b981' : st === 'ready' ? '#3a8dff' : st === 'error' ? '#ff4040' : '#888'}
          {@const glyph = st === 'active' ? '●' : st === 'ready' ? '◐' : st === 'error' ? '' : '○'}
          <div style="display: grid; grid-template-columns: 16px minmax(150px,1fr) minmax(220px,2.5fr) 70px 80px; padding: 7px 12px; border-bottom: 1px solid var(--pw-bg-alt); align-items: center; font-size: 11px;" title={a.reason || ''}>
            <span style="color: {col}; font-size: 11px;">{glyph}</span>
            <span style="font-weight: 600; padding-left: 14px; color: var(--pw-ink);">{a.name}</span>
            <span style="color: var(--pw-muted); font-size: 10px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">{a.role || ''}{a.trigger ? ` · trig: ${a.trigger}` : ''}</span>
            <span style="text-align: right; color: var(--pw-dim); font-size: 9.5px;">tool</span>
            <span style="text-align: center;"><span style="font-size: 8.5px; font-weight: 700; padding: 1.5px 6px; border-radius: 0; background: {col}1a; color: {col};">{_labelOf(st)}</span></span>
          </div>
        {/each}
      {/if}

      {#if _extended.length > 0}
        <div role="button" tabindex="0" onclick={() => agentsExtendedCollapsed = !agentsExtendedCollapsed} onkeydown={(e:any) => { if (e.key === 'Enter' || e.key === ' ') agentsExtendedCollapsed = !agentsExtendedCollapsed; }} style="padding: 6px 12px; background: var(--pw-bg-alt); font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pw-muted); border-bottom: 1px solid var(--pw-ink-soft); cursor: pointer; user-select: none;">
          {agentsExtendedCollapsed ? '▸' : '▾'} ↳ Extended ({_extended.length}) — full-spectrum agents (Docs, Helpdesk, Feedback, …)
        </div>
        {#if !agentsExtendedCollapsed}
