            {@const glyph = st === 'active' ? '●' : st === 'ready' ? '◐' : st === 'error' ? '' : '○'}
            {@const isIdle = st === 'needs_setup'}
            <div style="display: grid; grid-template-columns: 16px minmax(150px,1fr) minmax(220px,2.5fr) 70px 80px; padding: 7px 12px; border-bottom: 1px solid var(--pw-bg-alt); align-items: center; font-size: 11px;" title={a.reason || ''}>
              <span style="color: {col}; font-size: 11px; {isIdle ? 'animation: idlePulse 2s ease-in-out infinite;' : ''}">{glyph}</span>
              <span style="font-weight: 600; padding-left: 14px; color: var(--pw-ink);">{a.name}</span>
              <span style="color: var(--pw-muted); font-size: 10px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">{a.role || ''}{a.trigger ? ` · trig: ${a.trigger}` : ''}</span>
              <span style="text-align: right; color: {a.tools ? 'var(--pw-accent)' : 'var(--pw-dim)'}; font-size: 9.5px;">{a.tools || '—'}</span>
              <span style="text-align: center;"><span style="font-size: 8.5px; font-weight: 700; padding: 1.5px 6px; border-radius: 0; background: {col}1a; color: {col};">{_labelOf(st)}</span></span>
            </div>
          {/each}
        {/if}
      {/if}

      {#if _investment.length > 0}
        <div role="button" tabindex="0" onclick={() => agentsInvestmentCollapsed = !agentsInvestmentCollapsed} onkeydown={(e:any) => { if (e.key === 'Enter' || e.key === ' ') agentsInvestmentCollapsed = !agentsInvestmentCollapsed; }} style="padding: 6px 12px; background: var(--pw-bg-alt); font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pw-muted); border-bottom: 1px solid var(--pw-ink-soft); cursor: pointer; user-select: none;">
