 top: 14px;
 right: 14px;
 color: var(--pw-muted);
 }
 .set-act-icon svg { width: 18px; height: 18px; }
 .set-act-label {
 font-size: 11px;
 color: var(--pw-muted);
 font-weight: 500;
 }

 /* Tab completion compact pill strip */
 .set-tc-strip {
 display: flex;
 flex-wrap: wrap;
 gap: 6px;
 }
 .set-tc-pill {
 display: inline-flex;
 align-items: center;
 gap: 6px;
 padding: 5px 10px;
 background: var(--pw-bg-alt);
 border: 1px solid var(--pw-border);
