 }

 /* ═══ Table-detail cards (Datasets tab) ═══ */
 .dt-card-list {
 display: flex;
 flex-direction: column;
 gap: 14px;
 margin-top: 12px;
 }
 .dt-filter {
 background: var(--pw-surface);
 border: 1px solid var(--pw-border);
 border-radius: var(--pw-radius-sm);
 padding: 4px 10px;
 font-family: var(--pw-font-body);
 font-size: 11px;
 color: var(--pw-ink);
 cursor: pointer;
 }
 .dt-card {
 border: 1px solid var(--pw-border);
